async def get_rendered_html(url: str, timeout_ms: int = 30000) -> str:
    """
    Railway/GitHub Optimized: Playwright ကို အသုံးပြု၍ JS-heavy site များကို Render လုပ်ပေးသည်။
    """
    if not HAS_PLAYWRIGHT:
        async with aiohttp.ClientSession(headers=_get_headers(), timeout=aiohttp.ClientTimeout(total=timeout_ms//1000)) as session:
            async with session.get(url, ssl=False) as r:
                return await r.text()

    try:
        # ✅ v51: BrowserContextPool ကနေ reuse — new browser မ spawn တော့ဘဲ
        # Pool မ initialize မဖြစ်ရသေးရင် fallback to aiohttp
        if HAS_PLAYWRIGHT and _BROWSER_POOL._ready:
            try:
                return await _BROWSER_POOL.fetch_rendered(url, timeout_ms)
            except Exception as pool_err:
                logging.warning("BrowserPool fallback: %s", pool_err)
        elif HAS_PLAYWRIGHT:
            # Pool မသင့်ကြုံသေး → one-shot browser (degraded mode)
            try:
                from playwright.async_api import async_playwright
                async with async_playwright() as p:
                    browser = await p.chromium.launch(
                        headless=True,
                        args=["--no-sandbox", "--disable-setuid-sandbox",
                              "--disable-dev-shm-usage", "--no-zygote"]
                    )
                    ctx = await browser.new_context(
                        user_agent=random.choice(_UA_LIST),
                        viewport={"width": 1280, "height": 720},
                        ignore_https_errors=True,
                    )
                    page = await ctx.new_page()
                    await page.goto(url, wait_until="networkidle", timeout=timeout_ms)
                    html = await page.content()
                    await browser.close()
                    return html
            except Exception as e:
                logging.warning("One-shot Playwright error: %s", e)

        # Fallback: pure aiohttp (fastest, no JS rendering)
        async with aiohttp.ClientSession(
                headers=_get_headers(),
                timeout=aiohttp.ClientTimeout(total=timeout_ms // 1000)) as session:
            async with session.get(url, ssl=False) as r:
                return await r.text()
    except Exception as e:
        logging.error("get_rendered_html error: %s", e)
        async with aiohttp.ClientSession(
                headers=_get_headers(),
                timeout=aiohttp.ClientTimeout(total=timeout_ms // 1000)) as session:
            async with session.get(url, ssl=False) as r:
                return await r.text()


# ══════════════════════════════════════════════════════════════════════════════
# 🎭  PERSISTENT BROWSER CONTEXT POOL  — v51 (Playwright reuse)
#     Request တိုင်း browser spawn မဟုတ်ဘဲ pool ကနေ reuse လုပ်သည်
#     Memory: 3 contexts × ~80MB = ~240MB (was: per-request ~100MB spike)
#     Performance: ~3x faster (no launch overhead)
# ══════════════════════════════════════════════════════════════════════════════
import asyncio as _asyncio_pool


# ══════════════════════════════════════════════════════════════════════════════
# ⚡  GLOBAL AIOHTTP CONNECTOR POOL  — v52 (Tier 2 Performance)
#     Per-scan session creation is expensive. Share a persistent TCPConnector
#     across all scan operations — keeps connections alive, DNS cached.
#     Lifecycle: created in _startup_pools(), closed in shutdown.
# ══════════════════════════════════════════════════════════════════════════════
_GLOBAL_CONNECTOR: "aiohttp.TCPConnector | None" = None
_GLOBAL_SESSION:   "aiohttp.ClientSession | None" = None

async def _get_global_session() -> "aiohttp.ClientSession":
    """Return the global shared aiohttp session (lazy-init)."""
    global _GLOBAL_CONNECTOR, _GLOBAL_SESSION
    if _GLOBAL_SESSION is None or _GLOBAL_SESSION.closed:
        _GLOBAL_CONNECTOR = aiohttp.TCPConnector(
            limit=100,          # max 100 concurrent connections
            ttl_dns_cache=300,  # 5-min DNS cache
            ssl=False,
            enable_cleanup_closed=True,
        )
        _GLOBAL_SESSION = aiohttp.ClientSession(
            connector=_GLOBAL_CONNECTOR,
            headers=_get_headers(),
            timeout=aiohttp.ClientTimeout(total=30, connect=8),
        )
    return _GLOBAL_SESSION

async def _close_global_session():
    """Close global session — call on shutdown."""
    global _GLOBAL_SESSION, _GLOBAL_CONNECTOR
    if _GLOBAL_SESSION and not _GLOBAL_SESSION.closed:
        await _GLOBAL_SESSION.close()
    if _GLOBAL_CONNECTOR:
        await _GLOBAL_CONNECTOR.close()
    _GLOBAL_SESSION = _GLOBAL_CONNECTOR = None
    logger.info("Global aiohttp session closed")

class BrowserContextPool:
    """
    Async-safe Playwright browser context pool.
    - MAX_CTX contexts ကို pre-warm ပြုလုပ်ထားသည်
    - Semaphore ဖြင့် concurrent access ကို control လုပ်သည်
    - Context error ဖြစ်ရင် auto-replace (self-healing)
    - Lifecycle: init() → get_context() → release() → close_all()
    """

    def __init__(self, max_contexts: int = 3):
        self._max     = max_contexts
        self._sem     = asyncio.Semaphore(max_contexts)
        self._pool    = asyncio.Queue()
        self._browser = None
        self._pw      = None
        self._lock    = asyncio.Lock()
        self._ready   = False

    async def init(self):
        """Launch browser + pre-create all contexts. Call once at startup."""
        if self._ready or not HAS_PLAYWRIGHT:
            return
        async with self._lock:
            if self._ready:
                return
            try:
                from playwright.async_api import async_playwright
                self._pw = await async_playwright().__aenter__()
                self._browser = await self._pw.chromium.launch(
                    headless=True,
                    args=[
                        "--no-sandbox",
                        "--disable-setuid-sandbox",
                        "--disable-dev-shm-usage",
                        "--disable-gpu",
                        "--single-process",
                        "--no-zygote",
                    ]
                )
                for _ in range(self._max):
                    ctx = await self._browser.new_context(
                        user_agent=random.choice(_UA_LIST),
                        viewport={"width": 1280, "height": 720},
                        ignore_https_errors=True,
                    )
                    await self._pool.put(ctx)
                self._ready = True
                logger.info("BrowserContextPool: %d contexts ready", self._max)
            except Exception as e:
                logger.warning("BrowserContextPool init failed: %s", e)

    async def get_context(self):
        """Acquire a context from pool (blocks until one is free)."""
        if not self._ready:
            await self.init()
        await self._sem.acquire()
        try:
            ctx = await asyncio.wait_for(self._pool.get(), timeout=30)
            return ctx
        except asyncio.TimeoutError:
            self._sem.release()
            raise RuntimeError("BrowserContextPool: no context available within 30s")

    async def release(self, ctx, error: bool = False):
        """Return context to pool. If errored, replace with fresh one."""
        try:
            if error or ctx is None:
                # Replace broken context with fresh one
                try:
                    if ctx:
                        await ctx.close()
                except Exception:
                    pass
                if self._browser and self._ready:
                    try:
                        new_ctx = await self._browser.new_context(
                            user_agent=random.choice(_UA_LIST),
                            viewport={"width": 1280, "height": 720},
                            ignore_https_errors=True,
                        )
                        await self._pool.put(new_ctx)
                    except Exception as e:
                        logger.warning("BrowserContextPool: context replacement failed: %s", e)
                        # Put None as placeholder to maintain pool size
                        await self._pool.put(None)
            else:
                # Clear cookies/storage before reuse
                try:
                    await ctx.clear_cookies()
                except Exception:
                    pass
                await self._pool.put(ctx)
        finally:
            self._sem.release()

    async def fetch_rendered(self, url: str, timeout_ms: int = 30000) -> str:
        """Fetch JS-rendered HTML using a pooled context."""
        ctx = await self.get_context()
        error = False
        page = None
        try:
            if ctx is None:
                raise RuntimeError("Null context from pool")
            page = await ctx.new_page()
            await page.goto(url, wait_until="networkidle", timeout=timeout_ms)
            html = await page.content()
            return html
        except Exception as e:
            error = True
            logger.debug("BrowserContextPool.fetch_rendered error: %s", e)
            raise
        finally:
            if page:
                try:
                    await page.close()
                except Exception:
                    pass
            await self.release(ctx, error=error)

    async def close_all(self):
        """Shutdown pool — call on bot stop."""
        self._ready = False
        while not self._pool.empty():
            try:
                ctx = self._pool.get_nowait()
                if ctx:
                    await ctx.close()
            except Exception:
                pass
        if self._browser:
            try:
                await self._browser.close()
            except Exception:
                pass
        if self._pw:
            try:
                await self._pw.__aexit__(None, None, None)
            except Exception:
                pass
        logger.info("BrowserContextPool: shutdown complete")


# ── Global pool instance (initialized in main()) ─────────────────────────
_BROWSER_POOL: BrowserContextPool = BrowserContextPool(max_contexts=3)

async def _animated_spinner_task(
    msg,
    get_text_fn,
    interval: float = 1.2,
    spin_frames: list = None
) -> None:
    """
    Background task: edits a Telegram message every `interval` seconds
    using spinner frames. `get_text_fn()` returns the current body text.
    Caller must cancel this task when done.

    BUG FIX v35:
    - asyncio.CancelledError is now explicitly re-raised (was silently swallowed)
    - RetryAfter (Telegram FloodWait) is now respected with sleep+retry
    - 'Message to edit not found' → stop spinner cleanly (message deleted)
    - get_text_fn() exceptions caught separately from Telegram errors
    """
    from telegram.error import RetryAfter
    frames = spin_frames or SPINNER_BRAILLE
    idx = 0
    while True:
        # ✅ Sleep is cancellable — CancelledError propagates cleanly
        try:
            await asyncio.sleep(interval)
        except asyncio.CancelledError:
            return

        # Safely get text — don't let a bad callback crash the spinner
        try:
            body = get_text_fn() if callable(get_text_fn) else get_text_fn
        except Exception:
            body = "Processing…"

        spin = frames[idx % len(frames)]
        try:
            if hasattr(msg, 'edit_message_text'):
                await msg.edit_message_text(f"{spin} {body}", parse_mode='Markdown')
            else:
                await msg.edit_text(f"{spin} {body}", parse_mode='Markdown')
        except asyncio.CancelledError:
            return   # ✅ Propagate cancellation from edit_text await
        except RetryAfter as e:
            # FloodWait — respect Telegram's rate limit
            try:
                await asyncio.sleep(getattr(e, 'retry_after', 5) + 1)
            except asyncio.CancelledError:
                return
        except Exception as e:
            err = str(e).lower()
            if any(s in err for s in (
                'message is not modified',
                'message to edit not found',
                'there is no text in the message',
            )):
                return   # Message deleted or unchanged — stop silently
            # Other transient errors (NetworkError etc.) — skip this tick
        idx += 1

