# 🔒  SECURITY LAYER 3 — Rate Limiting
# ══════════════════════════════════════════════════

class _TokenBucket:
    """
    Token Bucket rate limiter — O(1) per check, thread-safe.

    v36 improvements:
    - Idle eviction: 1h (was 2h) to save memory on busy bots
    - reset(uid): admin can clear a specific user's bucket
    - stats(): return pool size + oldest entry age for monitoring
    """
    __slots__ = ('_lock', '_buckets', '_rate', '_capacity')

    def __init__(self, rate: float, capacity: float):
        self._lock     = threading.Lock()
        self._buckets: dict = {}   # {uid: (tokens, last_ts)}
        self._rate     = rate      # tokens per second
        self._capacity = capacity  # max tokens

    def consume(self, uid: int, tokens: float = 1.0) -> tuple:
        """
        Atomically consume tokens if available.
        Returns (allowed: bool, wait_seconds: float)
        """
        now = time.monotonic()
        with self._lock:
            stored_tokens, last_ts = self._buckets.get(uid, (self._capacity, now))
            elapsed  = now - last_ts
            refilled = min(self._capacity, stored_tokens + elapsed * self._rate)

            if refilled >= tokens:
                self._buckets[uid] = (refilled - tokens, now)
                return True, 0.0
            else:
                # Evict idle entries (> 1 hour idle) during a consume call
                if elapsed > 3600:
                    del self._buckets[uid]
                wait = (tokens - refilled) / self._rate if self._rate > 0 else 9999.0
                return False, wait

    def reset(self, uid: int) -> None:
        """Clear a user's bucket so their next request is immediately allowed."""
        with self._lock:
            self._buckets.pop(uid, None)

    def stats(self) -> dict:
        """Return pool size for monitoring."""
        with self._lock:
            return {"pool_size": len(self._buckets)}

    def __len__(self):
        with self._lock:
            return len(self._buckets)

# v39 fix: missing _light_rl and _heavy_rl instances
_light_rl   = _TokenBucket(rate=1.0 / RATE_LIMIT_SEC, capacity=1.0)
_heavy_rl   = _TokenBucket(rate=1.0 / max(HEAVY_RATE_LIMIT_SEC, 1), capacity=1.0)
_pentest_rl = _TokenBucket(rate=1.0 / PENTEST_RATE_SEC, capacity=1.0)  # 1 pentest per 2 min

# Daily pentest counter: {uid: (count, date_str)}
_pentest_daily: dict = {}
_pentest_daily_lock = threading.Lock()

# ── Unified Daily Quota System (in-memory, reset daily) ──────────
# {uid: {cmd_type: (count, date_str)}}
_daily_quotas: dict = {}
_daily_quota_lock = threading.Lock()

# Daily limits per command type (overrideable via env)
DAILY_LIMITS = {
    'download':    int(os.getenv('DL_DAILY',       '5')),
    'scan':        int(os.getenv('SCAN_DAILY',     '10')),
    'pentest':     int(os.getenv('PENTEST_DAILY',   '3')),
    'recon':       int(os.getenv('RECON_DAILY',    '15')),
    'devaudit':    int(os.getenv('DEVAUDIT_DAILY',  '5')),
    'fixall':      int(os.getenv('FIXALL_DAILY',    '5')),
    'bruteforce':  int(os.getenv('BRUTE_DAILY',     '3')),
    'default':     int(os.getenv('DEFAULT_DAILY',  '20')),
}

def quota_check(uid: int, cmd_type: str) -> tuple:
    """Check + consume daily quota. Returns (allowed: bool, remaining: int, msg: str)."""
    if uid in ADMIN_IDS: return True, 9999, ''  # admins unlimited
    today = datetime.now().strftime('%Y-%m-%d')
    limit = DAILY_LIMITS.get(cmd_type, DAILY_LIMITS['default'])
    with _daily_quota_lock:
        user_q = _daily_quotas.setdefault(uid, {})
        count, day = user_q.get(cmd_type, (0, today))
        if day != today: count = 0  # new day reset
        if count >= limit:
            return False, 0, (
                f'📛 *Daily limit reached*\n'
                f'`{cmd_type}` limit: `{limit}/day`\n'
                f'Used: `{count}/{limit}` — resets midnight UTC')
        user_q[cmd_type] = (count + 1, today)
    return True, limit - count - 1, ''

def quota_status(uid: int) -> dict:
    """Return {cmd_type: (used, limit, remaining)} for a user."""
    today = datetime.now().strftime('%Y-%m-%d')
    with _daily_quota_lock:
        user_q = _daily_quotas.get(uid, {})
    out = {}
    for k, lim in DAILY_LIMITS.items():
        count, day = user_q.get(k, (0, today))
        if day != today: count = 0
        out[k] = (count, lim, max(0, lim - count))
    return out

def quota_reset_user(uid: int, cmd_type: str = None):
    """Admin: reset quota for a user (all types or specific type)."""
    with _daily_quota_lock:
        if uid in _daily_quotas:
            if cmd_type:
                _daily_quotas[uid].pop(cmd_type, None)
            else:
                _daily_quotas.pop(uid)

def check_pentest_rate(user_id: int) -> tuple:
    """Check both per-minute and daily pentest limits. Returns (allowed, reason)."""
    import math
    if user_id <= 0: return True, ""
    # Per-2-min bucket
    allowed, wait = _pentest_rl.consume(user_id)
    if not allowed:
        return False, f"⏳ Pentest cooldown: `{math.ceil(wait)}s` စောင့်ပါ"
    # Daily limit
    today = datetime.now().strftime('%Y-%m-%d')
    with _pentest_daily_lock:
        count, day = _pentest_daily.get(user_id, (0, today))
        if day != today:
            count = 0
        if count >= DAILY_PENTEST_LIMIT:
            _pentest_rl.reset(user_id)  # refund the token
            return False, f"📛 Daily pentest limit (`{DAILY_PENTEST_LIMIT}`) ပြည့်ပါပြီ — မနက်ဖြန် ထပ်သုံးပါ"
        _pentest_daily[user_id] = (count + 1, today)
    return True, ""

def check_scan_rate(user_id: int) -> tuple:
    """Alias for heavy rate limit — used by scan engines."""
    return check_rate_limit(user_id, heavy=True)


def check_rate_limit(user_id: int, heavy: bool = False) -> tuple:
    """
    Token Bucket rate limiter.
    Returns: (allowed: bool, wait_seconds: int)

    v36:
    - System/internal calls (user_id <= 0) → always allowed
    - wait_seconds: math.ceil() for fairer cooldown display
    - Logging: warning when user hits rate limit repeatedly

    BUG NOTE (v35 fix preserved):
    Old code had: return allowed, int(wait)+1 if not allowed else (True, 0)
    Python parsed this as tuple-in-tuple when allowed=True.
    Fix: explicit if/else blocks — no inline ternary.
    """
    import math
    # System/internal calls bypass rate limiting
    if user_id <= 0:
        return True, 0

    try:
        bucket  = _heavy_rl if heavy else _light_rl   # type: ignore[name-defined]
        allowed, wait = bucket.consume(user_id)
    except Exception as e:
        logger.error("check_rate_limit error for uid=%d: %s", user_id, e)
        return True, 0   # Fail-open: don't block on rate limiter crash

    if not allowed:
        wait_int = math.ceil(wait)
        logger.debug("Rate limited uid=%d heavy=%s wait=%ds", user_id, heavy, wait_int)
        return False, wait_int

    return True, 0

def check_user_quota(user_id: int, action_type: str = "download") -> tuple:
    """
    Check if user exceeded daily quota.
    action_type: 'download' or 'scan'
    Returns: (allowed: bool, remaining: int, message: str)
    """
    today = date.today().isoformat()
    
    # Get user's quota dict: {date: count}
    user_quota = user_daily_quota.get(user_id, {})
    if not isinstance(user_quota, dict):
        user_quota = {}
    
    today_count = user_quota.get(today, 0)
    
    if action_type == "download":
        limit = DAILY_LIMIT_PER_USER_DL
        action_name = "downloads"
    else:  # scan
        limit = DAILY_LIMIT_PER_USER_SCAN
        action_name = "scans"
    
    if today_count >= limit:
        return False, 0, f"❌ *Daily quota exceeded* — `{today_count}/{limit} {action_name}` used today. Try tomorrow!"
    
    remaining = limit - today_count - 1
    return True, remaining, f"✅ `{remaining} {action_name}` remaining today"

def increment_user_quota(user_id: int, action_type: str = "download"):
    """Increment user's daily quota counter"""
    today = date.today().isoformat()
    user_quota = user_daily_quota.get(user_id, {})
    if not isinstance(user_quota, dict):
        user_quota = {}
    user_quota[today] = user_quota.get(today, 0) + 1
    user_daily_quota.set(user_id, user_quota)


