# 🔒  SECURITY LAYER 5 — Admin Auth Hardened
# ══════════════════════════════════════════════════

async def verify_admin(update: Update) -> bool:
    """
    Admin verification — multi-layer check
    """
    uid = update.effective_user.id

    # Layer 1: ID check
    if uid not in ADMIN_IDS:
        return False

    # Layer 2: Private chat only (admin commands in group = dangerous)
    if update.effective_chat.type != "private":
        await update.effective_message.reply_text(
            "⚠️ Admin commands ကို private chat မှာသာ သုံးနိုင်ပါတယ်"
        )
        return False

    # Layer 3: Not a forwarded message (anti-spoofing)
    # forward_origin = newer PTB | forward_date = older PTB version
    if update.message:
        is_forwarded = (
            getattr(update.message, 'forward_origin', None) or
            getattr(update.message, 'forward_date', None)
        )
        if is_forwarded:
            return False

    return True

def admin_only(func):
    @functools.wraps(func)
    async def wrapper(update: Update, context: ContextTypes.DEFAULT_TYPE):
        if not await verify_admin(update):
            # ── Admin command — user မြင်ရင်မကောင်းဘူး — silent ignore ──
            return
        return await func(update, context)
    return wrapper


# ══════════════════════════════════════════════════
# 🚨  ADMIN ERROR NOTIFY — Unhandled error → Admin DM
# ══════════════════════════════════════════════════

async def error_handler(update: object, context: ContextTypes.DEFAULT_TYPE) -> None:
    """Global error handler — Admin ဆီ Telegram message ပို့မည်"""
    import traceback

    err = context.error

    # ── Silently ignore non-critical Telegram API errors ──────────
    if isinstance(err, BadRequest):
        err_msg = str(err).lower()
        if any(s in err_msg for s in (
            "message is not modified",       # same content re-edit
            "message to edit not found",     # message deleted
            "there is no text in the message to edit",
            "query is too old",              # stale callback query
            "message can't be deleted",     # already deleted
        )):
            logger.debug("Ignored non-critical BadRequest: %s", err)
            return

    if isinstance(err, (TimedOut, NetworkError)):
        logger.warning("Network error (ignored in handler): %s", err)
        return

    # ── Real errors → log + notify admin ──────────────────────────
    tb = "".join(traceback.format_exception(
        type(err), err, err.__traceback__
    ))
    short_tb = tb[-1500:] if len(tb) > 1500 else tb

    user_info = ""
    if update and hasattr(update, "effective_user") and update.effective_user:
        u = update.effective_user
        user_info = f"\n👤 User: `{u.id}` ({u.first_name})"

    msg = (
        "🚨 *Bot Error Alert*\n"
        f"━━━━━━━━━━━━━━━━━━━━{user_info}\n\n"
        f"```\n{short_tb}\n```"
    )

    for admin_id in ADMIN_IDS:
        try:
            await context.bot.send_message(
                chat_id=admin_id,
                text=msg,
                parse_mode='Markdown'
            )
        except Exception:
            logger.warning("Admin error notify failed for %d", admin_id)

    logger.error("Unhandled exception: %s", err, exc_info=err)


# ══════════════════════════════════════════════════
# 🗑️  AUTO-DELETE — Expired download files cleaner
# ══════════════════════════════════════════════════

async def auto_delete_loop():
    """Background task — ၂၄ နာရီ (FILE_EXPIRY_HOURS) ကြာတဲ့ ZIP files auto-delete"""
    while True:
        try:
            now     = time.time()
            deleted = 0
            freed   = 0.0
            for folder in [DOWNLOAD_DIR, RESUME_DIR, APP_ANALYZE_DIR]:
                for root, dirs, files in os.walk(folder):
                    for fname in files:
                        fpath = os.path.join(root, fname)
                        try:
                            age_hours = (now - os.path.getmtime(fpath)) / 3600
                            if age_hours >= FILE_EXPIRY_HOURS:
                                size = os.path.getsize(fpath) / 1024 / 1024
                                os.remove(fpath)
                                deleted += 1
                                freed   += size
                        except Exception:
                            pass
            if deleted:
                logger.info(
                    "Auto-delete: %d files | %.1f MB freed (>%dh old)",
                    deleted, freed, FILE_EXPIRY_HOURS
                )
        except Exception as e:
            logger.warning("Auto-delete loop error: %s", e)
        # ၁ နာရီတစ်ကြိမ် check
        await asyncio.sleep(3600)


# ══════════════════════════════════════════════════
# 📋  QUEUE SYSTEM — Download request queue
# ══════════════════════════════════════════════════

async def queue_worker(worker_id: int = 0):
    """
    Background worker — queue ထဲက download request တွေ တစ်ခုစီ run
    V31+: Multiple concurrent workers (NUM_QUEUE_WORKERS) for parallel throughput.
    """
    global _dl_queue
    logger.info("Queue worker #%d started", worker_id)
    while True:
        try:
            task = await _dl_queue.get()
            update, context, url, full_site, use_js, resume_mode, uid, *_extra = task
            _cookies_q       = _extra[0] if len(_extra) > 0 else ""
            _extra_headers_q = _extra[1] if len(_extra) > 1 else ""
            _max_depth_q     = _extra[2] if len(_extra) > 2 else 5
            _queue_pos.pop(uid, None)
            try:
                await _run_download(update, context, url, full_site, use_js, resume_mode,
                                    _cookies_q, _extra_headers_q, _max_depth_q)
            except Exception as e:
                logger.error("Queue worker #%d download error: %s", worker_id, e)
            finally:
                # Decrement per-user slot counter
                current = user_queue_count.get(uid, 1)
                user_queue_count.set(uid, max(0, current - 1))
                _dl_queue.task_done()
        except asyncio.CancelledError:
            logger.info("Queue worker #%d shutting down", worker_id)
            break
        except Exception as e:
            logger.error("Queue worker #%d fatal error: %s", worker_id, e)
            await asyncio.sleep(1)


async def enqueue_download(
    update: Update, context: ContextTypes.DEFAULT_TYPE,
    url: str, full_site: bool, use_js: bool, resume_mode: bool = False,
    cookies: str = "", extra_headers: str = "", max_depth: int = 5,
):
    """Download request ကို queue ထဲ ထည့်သည်
    Improved: per-user queue limit (QUEUE_MAX_PER_USER) to prevent queue monopoly.
    """
    global _dl_queue, _queue_counter
    uid = update.effective_user.id

    # Global queue full check
    if _dl_queue.qsize() >= QUEUE_MAX:
        await update.effective_message.reply_text(
            f"⚠️ Queue ပြည့်နေပါတယ် (`{QUEUE_MAX}` max)\n"
            "ခဏနေပြီးမှ ထပ်ကြိုးစားပါ",
            parse_mode='Markdown'
        )
        return

    # Per-user queue limit check
    user_slots = user_queue_count.get(uid, 0)
    if user_slots >= QUEUE_MAX_PER_USER:
        await update.effective_message.reply_text(
            f"⚠️ သင့် queue slot `{QUEUE_MAX_PER_USER}` ပြည့်နေပါပြီ\n"
            "ပြီးဆုံးသည့်အခါ ထပ်ထည့်နိုင်ပါမည်",
            parse_mode='Markdown'
        )
        return

    _queue_counter += 1
    pos = _dl_queue.qsize() + 1
    user_queue_count.set(uid, user_slots + 1)
    increment_user_quota(uid, "download")  # ✅ Increment daily quota

    await _dl_queue.put((update, context, url, full_site, use_js, resume_mode, uid, cookies, extra_headers, max_depth))
    _queue_pos.set(uid, pos)

    if pos > 1:
        await update.effective_message.reply_text(
            f"📋 *Queue ထဲ ထည့်ပြီးပါပြီ*\n"
            f"📍 Position: `{pos}` | သင့် slots: `{user_slots+1}/{QUEUE_MAX_PER_USER}`\n"
            f"⏳ Download ရောက်လာသည့်အခါ အလိုအလျောက် စမည်",
            parse_mode='Markdown'
        )


# ══════════════════════════════════════════════════
# 📦  DATABASE  (with async lock for race condition)
# ══════════════════════════════════════════════════

# ══════════════════════════════════════════════════════════════
# 🗄️  SQLite DATABASE LAYER  (replaces JSON flat-file)
#     • Built-in sqlite3 — no extra install required
#     • WAL mode: concurrent reads + writes without blocking
#     • Async via run_in_executor — never blocks event loop
#     • Auto-migrates from legacy bot_db.json on first run
#     • db_lock still used for write serialization safety
# ══════════════════════════════════════════════════════════════

def _sqlite_init():
    """Create tables if not exist. Called once at startup."""
    con = sqlite3.connect(SQLITE_FILE, timeout=30)
    con.execute("PRAGMA journal_mode=WAL")   # WAL = concurrent read+write
    con.execute("PRAGMA synchronous=NORMAL") # faster writes, still safe
    con.execute("PRAGMA cache_size=-8000")   # 8MB cache
    con.execute("""
        CREATE TABLE IF NOT EXISTS users (
            uid          TEXT PRIMARY KEY,
            name         TEXT DEFAULT '',
            banned       INTEGER DEFAULT 0,
            daily_limit  INTEGER,
            count_today  INTEGER DEFAULT 0,
            last_date    TEXT DEFAULT '',
            total_downloads INTEGER DEFAULT 0,
            total_scans  INTEGER DEFAULT 0,
            scans_today  INTEGER DEFAULT 0,
            downloads    TEXT DEFAULT '[]',
            scan_history TEXT DEFAULT '[]'
        )
    """)
    con.execute("""
        CREATE TABLE IF NOT EXISTS settings (
            key   TEXT PRIMARY KEY,
            value TEXT
        )
    """)
    # Default settings
    defaults = [
        ("global_daily_limit", str(DAILY_LIMIT)),
        ("max_pages",          str(MAX_PAGES)),
        ("max_assets",         str(MAX_ASSETS)),
        ("bot_enabled",        "1"),
    ]
    for k, v in defaults:
        con.execute("INSERT OR IGNORE INTO settings(key,value) VALUES(?,?)", (k, v))
    con.commit()
    con.close()
    logging.info("SQLite DB initialized: %s", SQLITE_FILE)


def _migrate_json_to_sqlite():
    """One-time migration: bot_db.json → SQLite (runs only if JSON exists and has data)."""
    if not os.path.exists(DB_FILE):
        return
    try:
        with open(DB_FILE, 'r', encoding='utf-8') as f:
            old = json.load(f)
    except Exception as e:
        logging.warning("JSON migration read error: %s", e)
        return

    if not old.get("users"):
        return  # nothing to migrate

    con = sqlite3.connect(SQLITE_FILE, timeout=30)
    migrated = 0
    for uid, u in old["users"].items():
        try:
            con.execute("""
                INSERT OR REPLACE INTO users
                (uid, name, banned, daily_limit, count_today, last_date,
                 total_downloads, total_scans, scans_today, downloads, scan_history)
                VALUES (?,?,?,?,?,?,?,?,?,?,?)
            """, (
                uid,
                u.get("name", ""),
                1 if u.get("banned") else 0,
                u.get("daily_limit"),
                u.get("count_today", 0),
                u.get("last_date", ""),
                u.get("total_downloads", 0),
                u.get("total_scans", 0),
                u.get("scans_today", 0),
                json.dumps(u.get("downloads", [])[-100:]),
                json.dumps(u.get("scan_history", [])[-20:]),
            ))
            migrated += 1
        except Exception as e:
            logging.warning("Migration error for uid %s: %s", uid, e)

    # Migrate settings
    if "settings" in old:
        for k, v in old["settings"].items():
            con.execute("INSERT OR REPLACE INTO settings(key,value) VALUES(?,?)",
                        (k, str(int(v) if isinstance(v, bool) else v)))

    con.commit()
    con.close()
    logging.info("Migrated %d users from JSON to SQLite", migrated)
    # Rename old file so migration doesn't repeat
    os.rename(DB_FILE, DB_FILE + ".migrated")


def _get_con() -> sqlite3.Connection:
    """Get a short-lived SQLite connection (WAL mode, thread-safe)."""
    con = sqlite3.connect(SQLITE_FILE, timeout=30, check_same_thread=False)
    con.execute("PRAGMA journal_mode=WAL")
    con.row_factory = sqlite3.Row
    return con


def _load_db_sync() -> dict:
    """Compatibility shim — loads full DB as dict (for code that still uses db dict pattern)."""
    con = _get_con()
    try:
        users = {}
        for row in con.execute("SELECT * FROM users"):
            uid = row["uid"]
            users[uid] = {
                "name":            row["name"],
                "banned":          bool(row["banned"]),
                "daily_limit":     row["daily_limit"],
                "count_today":     row["count_today"],
                "last_date":       row["last_date"],
                "total_downloads": row["total_downloads"],
                "total_scans":     row["total_scans"],
                "scans_today":     row["scans_today"],
                "downloads":       json.loads(row["downloads"] or "[]"),
                "scan_history":    json.loads(row["scan_history"] or "[]"),
            }
        settings = {}
        for row in con.execute("SELECT key, value FROM settings"):
            v = row["value"]
            try:
                settings[row["key"]] = int(v) if v.lstrip("-").isdigit() else (True if v == "1" else (False if v == "0" else v))
            except Exception:
                settings[row["key"]] = v
        return {"users": users, "settings": settings}
    finally:
        con.close()


def _save_db_sync(db: dict):
    """Compatibility shim — writes full db dict back to SQLite."""
    con = _get_con()
    try:
        settings = db.get("settings", {})
        for k, v in settings.items():
            con.execute("INSERT OR REPLACE INTO settings(key,value) VALUES(?,?)",
                        (k, str(int(v) if isinstance(v, bool) else v)))

        for uid, u in db.get("users", {}).items():
            con.execute("""
                INSERT OR REPLACE INTO users
                (uid, name, banned, daily_limit, count_today, last_date,
                 total_downloads, total_scans, scans_today, downloads, scan_history)
                VALUES (?,?,?,?,?,?,?,?,?,?,?)
            """, (
                uid,
                u.get("name", ""),
                1 if u.get("banned") else 0,
                u.get("daily_limit"),
                u.get("count_today", 0),
                u.get("last_date", ""),
                u.get("total_downloads", 0),
                u.get("total_scans", 0),
                u.get("scans_today", 0),
                json.dumps(u.get("downloads", [])[-100:]),
                json.dumps(u.get("scan_history", [])[-20:]),
            ))
        con.commit()
    finally:
        con.close()


async def db_read() -> dict:
    """Async DB read — runs in executor so event loop is never blocked."""
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(None, _load_db_sync)


async def db_write(db: dict):
    """Async DB write — runs in executor."""
    loop = asyncio.get_running_loop()
    async with db_lock:
        await loop.run_in_executor(None, _save_db_sync, db)


async def db_update(func):
    """Atomic read-modify-write. Usage: await db_update(lambda db: ...)"""
    loop = asyncio.get_running_loop()
    async with db_lock:
        db = await loop.run_in_executor(None, _load_db_sync)
        func(db)
        await loop.run_in_executor(None, _save_db_sync, db)
        return db


# ══════════════════════════════════════════════════
# ⚡  DIRECT SQLITE OPS  — Targeted row-level queries
#     Bypass full DB load/save for simple operations
#     Up to 10x faster for single-user updates
# ══════════════════════════════════════════════════

def _sqlite_get_user(uid: int) -> Optional[dict]:
    """Fetch one user row directly — no full DB load."""
    con = _get_con()
    try:
        row = con.execute("SELECT * FROM users WHERE uid=?", (str(uid),)).fetchone()
        if not row:
            return None
        return {
            "name":            row["name"],
            "banned":          bool(row["banned"]),
            "daily_limit":     row["daily_limit"],
            "count_today":     row["count_today"],
            "last_date":       row["last_date"],
            "total_downloads": row["total_downloads"],
            "total_scans":     row["total_scans"],
            "scans_today":     row["scans_today"],
            "downloads":       json.loads(row["downloads"] or "[]"),
            "scan_history":    json.loads(row["scan_history"] or "[]"),
        }
    finally:
        con.close()


def _sqlite_upsert_user(uid: int, user: dict):
    """Write one user row directly — no full DB save."""
    con = _get_con()
    try:
        con.execute("""
            INSERT OR REPLACE INTO users
            (uid, name, banned, daily_limit, count_today, last_date,
             total_downloads, total_scans, scans_today, downloads, scan_history)
            VALUES (?,?,?,?,?,?,?,?,?,?,?)
        """, (
            str(uid),
            user.get("name", ""),
            1 if user.get("banned") else 0,
            user.get("daily_limit"),
            user.get("count_today", 0),
            user.get("last_date", ""),
            user.get("total_downloads", 0),
            user.get("total_scans", 0),
            user.get("scans_today", 0),
            json.dumps(user.get("downloads", [])[-100:]),
            json.dumps(user.get("scan_history", [])[-20:]),
        ))
        con.commit()
    finally:
        con.close()


def _sqlite_is_banned(uid: int) -> bool:
    """Fast ban check — single column query."""
    con = _get_con()
    try:
        row = con.execute(
            "SELECT banned FROM users WHERE uid=?", (str(uid),)
        ).fetchone()
        return bool(row["banned"]) if row else False
    finally:
        con.close()


def _sqlite_get_setting(key: str, default=None):
    """Fetch one setting — no full DB load."""
    con = _get_con()
    try:
        row = con.execute(
            "SELECT value FROM settings WHERE key=?", (key,)
        ).fetchone()
        if not row:
            return default
        v = row["value"]
        try:
            return int(v) if v.lstrip("-").isdigit() else v
        except Exception:
            return v
    finally:
        con.close()


async def sqlite_get_user(uid: int) -> Optional[dict]:
    """Async single-user fetch — runs in executor."""
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(None, _sqlite_get_user, uid)


async def sqlite_upsert_user(uid: int, user: dict):
    """Async single-user write — runs in executor with db_lock."""
    loop = asyncio.get_running_loop()
    async with db_lock:
        await loop.run_in_executor(None, _sqlite_upsert_user, uid, user)


async def sqlite_is_banned(uid: int) -> bool:
    """Async fast ban check."""
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(None, _sqlite_is_banned, uid)

# ══════════════════════════════════════════════════════════════════════════════
# ⚡  AIOSQLITE NATIVE ASYNC LAYER  — v51
#     run_in_executor(sqlite3) ကို replace လုပ်သည်
#     Connection pool: asyncio.Queue ဖြင့် manage (thread-safe per event loop)
#     TTL-based connection recycling — stale connections auto-close
# ══════════════════════════════════════════════════════════════════════════════
try:
    import aiosqlite as _aiosqlite
    HAS_AIOSQLITE = True
except ImportError:
    HAS_AIOSQLITE = False
    logger.warning("aiosqlite not installed — falling back to run_in_executor. "
                   "Run: pip install aiosqlite --break-system-packages")

_AIOSQL_POOL_SIZE = 4
_aiosql_pool: asyncio.Queue = asyncio.Queue(maxsize=_AIOSQL_POOL_SIZE)
_aiosql_pool_ready = False
_aiosql_pool_lock  = None   # set in main()

async def _aiosql_init_pool():
    """Create aiosqlite connection pool. Called once in main()."""
    global _aiosql_pool_ready
    if not HAS_AIOSQLITE or _aiosql_pool_ready:
        return
    for _ in range(_AIOSQL_POOL_SIZE):
        conn = await _aiosqlite.connect(SQLITE_FILE)
        conn.row_factory = _aiosqlite.Row
        await conn.execute("PRAGMA journal_mode=WAL")
        await conn.execute("PRAGMA synchronous=NORMAL")
        await conn.execute("PRAGMA cache_size=10000")
        await _aiosql_pool.put(conn)
    _aiosql_pool_ready = True
    logger.info("aiosqlite pool ready (%d connections)", _AIOSQL_POOL_SIZE)

async def _aiosql_get() -> "_aiosqlite.Connection":
    """Borrow a connection from pool (waits up to 5s)."""
    try:
        return await asyncio.wait_for(_aiosql_pool.get(), timeout=5.0)
    except asyncio.TimeoutError:
        # Pool exhausted → create temporary connection
        conn = await _aiosqlite.connect(SQLITE_FILE)
        conn.row_factory = _aiosqlite.Row
        return conn

async def _aiosql_put(conn):
    """Return connection to pool (or close if pool full)."""
    try:
        _aiosql_pool.put_nowait(conn)
    except asyncio.QueueFull:
        await conn.close()

async def aiosql_get_user(uid: int) -> dict | None:
    """
    Native async single-user fetch — zero thread overhead.
    Replaces: loop.run_in_executor(None, _sqlite_get_user, uid)
    """
    if not HAS_AIOSQLITE or not _aiosql_pool_ready:
        # Fallback to executor-based sync version
        return await asyncio.get_running_loop().run_in_executor(
            None, _sqlite_get_user, uid)
    conn = await _aiosql_get()
    try:
        async with conn.execute(
                "SELECT * FROM users WHERE uid=?", (str(uid),)) as cur:
            row = await cur.fetchone()
        if not row:
            return None
        return {
            "name":            row["name"],
            "banned":          bool(row["banned"]),
            "daily_limit":     row["daily_limit"],
            "count_today":     row["count_today"],
            "last_date":       row["last_date"],
            "total_downloads": row["total_downloads"],
            "total_scans":     row["total_scans"],
            "scans_today":     row["scans_today"],
            "downloads":       json.loads(row["downloads"] or "[]"),
            "scan_history":    json.loads(row["scan_history"] or "[]"),
        }
    finally:
        await _aiosql_put(conn)

async def aiosql_upsert_user(uid: int, user: dict):
    """
    Native async single-user write.
    Replaces: async with db_lock: loop.run_in_executor(None, _sqlite_upsert_user, ...)
    """
    if not HAS_AIOSQLITE or not _aiosql_pool_ready:
        async with db_lock:
            await asyncio.get_running_loop().run_in_executor(
                None, _sqlite_upsert_user, uid, user)
        return
    conn = await _aiosql_get()
    try:
        await conn.execute("""
            INSERT OR REPLACE INTO users
            (uid, name, banned, daily_limit, count_today, last_date,
             total_downloads, total_scans, scans_today, downloads, scan_history)
            VALUES (?,?,?,?,?,?,?,?,?,?,?)
        """, (
            str(uid),
            user.get("name", ""),
            1 if user.get("banned") else 0,
            user.get("daily_limit"),
            user.get("count_today", 0),
            user.get("last_date", ""),
            user.get("total_downloads", 0),
            user.get("total_scans", 0),
            user.get("scans_today", 0),
            json.dumps(user.get("downloads", [])[-100:]),
            json.dumps(user.get("scan_history", [])[-20:]),
        ))
        await conn.commit()
    finally:
        await _aiosql_put(conn)

async def aiosql_is_banned(uid: int) -> bool:
    """Native async fast ban check."""
    if not HAS_AIOSQLITE or not _aiosql_pool_ready:
        return await asyncio.get_running_loop().run_in_executor(
            None, _sqlite_is_banned, uid)
    conn = await _aiosql_get()
    try:
        async with conn.execute(
                "SELECT banned FROM users WHERE uid=?", (str(uid),)) as cur:
            row = await cur.fetchone()
        return bool(row["banned"]) if row else False
    finally:
        await _aiosql_put(conn)

async def _aiosql_close_pool():
    """Close all connections. Called on shutdown."""
    while not _aiosql_pool.empty():
        try:
            conn = _aiosql_pool.get_nowait()
            await conn.close()
        except Exception:
            pass
    logger.info("aiosqlite pool closed")



def get_user(db: dict, user_id: int, name: str = "") -> dict:
    uid = str(user_id)
    if uid not in db["users"]:
        db["users"][uid] = {
            "name": name, "banned": False,
            "daily_limit": None, "count_today": 0,
            "last_date": "", "total_downloads": 0,
            "downloads": [],
            "total_scans": 0, "scans_today": 0,
            "scan_history": [],   # last 20 scans [{type,target,ts}]
        }
    if name:
        db["users"][uid]["name"] = name
    return db["users"][uid]


def track_scan(db: dict, uid: int, scan_type: str, target: str):
    """Record a scan in user's history."""
    u = db["users"].get(str(uid))
    if not u: return
    u.setdefault("total_scans", 0)
    u.setdefault("scans_today", 0)
    u.setdefault("scan_history", [])
    u["total_scans"]  += 1
    u["scans_today"]  += 1
    entry = {"type": scan_type, "target": target[:80],
             "ts": datetime.now().strftime("%m-%d %H:%M")}
    u["scan_history"].insert(0, entry)
    if len(u["scan_history"]) > 20:
        u["scan_history"] = u["scan_history"][:20]


def reset_daily(user: dict):
    today = str(date.today())
    if user["last_date"] != today:
        user["count_today"] = 0
        user["last_date"] = today

def get_limit(db: dict, user: dict) -> int:
    return user["daily_limit"] if user["daily_limit"] is not None \
           else db["settings"]["global_daily_limit"]

def can_download(db: dict, user: dict) -> bool:
    reset_daily(user)
    lim = get_limit(db, user)
    return lim == 0 or user["count_today"] < lim

def log_download(user: dict, url: str, size_mb: float, status: str):
    user["downloads"].append({
        "url": sanitize_log_url(url),       # ← sanitized before storing
        "time": datetime.now().strftime("%Y-%m-%d %H:%M"),
        "size_mb": round(size_mb, 2),
        "status": status
    })
    if len(user["downloads"]) > 100:
        user["downloads"] = user["downloads"][-100:]
    user["count_today"] += 1
    user["total_downloads"] += 1


# ══════════════════════════════════════════════════
# 💾  RESUME STATE  (with HMAC integrity)
# ══════════════════════════════════════════════════

def _state_sig(state: dict) -> str:
    data = json.dumps({k: v for k, v in state.items() if k != "_sig"}, sort_keys=True)
    return hmac.HMAC(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()

def _resume_path(url: str) -> str:
    return os.path.join(RESUME_DIR, hashlib.md5(url.encode()).hexdigest()[:12] + ".json")

def load_resume(url: str) -> dict:
    path = _resume_path(url)
    empty = {"visited": [], "downloaded": [], "assets": [], "stats": {}}
    if not os.path.exists(path):
        return empty
    try:
        with open(path) as f:
            state = json.load(f)
        sig = state.pop("_sig", "")
        if not hmac.compare_digest(_state_sig(state), sig):
            logger.warning("Resume state integrity check FAILED — ignoring")
            os.remove(path)
            return empty
        return state
    except Exception:
        return empty

def save_resume(url: str, state: dict):
    to_save = dict(state)
    to_save["_sig"] = _state_sig(state)
    tmp = _resume_path(url) + ".tmp"
    with open(tmp, 'w') as f:
        json.dump(to_save, f)
    os.replace(tmp, _resume_path(url))

def clear_resume(url: str):
    p = _resume_path(url)
    if os.path.exists(p):
        os.remove(p)


# ══════════════════════════════════════════════════
# 📊  PROGRESS BAR (Upgraded for Telegram)
# ══════════════════════════════════════════════════

def pbar(done: int, total: int, width: int = 18,
         elapsed: float = 0.0, unit: str = "") -> str:
    if total <= 0:
        spin = ["⠋","⠙","⠹","⠸","⠼","⠴","⠦","⠧","⠇","⠏"]
        idx  = int(time.time() * 4) % len(spin)
        return f"│{'░' * width}│  {spin[idx]}"

    pct       = min(max(done / total, 0.0), 1.0)
    fill_exact = pct * width
    full_blocks = int(fill_exact)
    remainder   = fill_exact - full_blocks
    partials  = [" ", "▏", "▎", "▍", "▌", "▋", "▊", "▉"]
    bar = "█" * full_blocks
    if full_blocks < width:
        bar += partials[int(remainder * len(partials))]
        bar += " " * (width - full_blocks - 1)
    else:
        bar = "█" * width
    pct_str = f"{int(pct * 100):>3}%"
    if pct < 0.3: status_icon = "🌑"
    elif pct < 0.7: status_icon = "🌓"
    elif pct < 1.0: status_icon = "🌔"
    else: status_icon = "🌕"
    base = f"{status_icon} │{bar}│ {pct_str}"
    if elapsed > 1.0 and done > 0 and done < total:
        rate = done / elapsed
        eta  = (total - done) / rate
        if eta < 60: base += f" ⏳ {int(eta)}s"
        else: base += f" ⏳ {int(eta/60)}m{int(eta%60)}s"
    elif unit and elapsed > 0 and done > 0:
        rate = done / elapsed
        if rate > 1024: base += f" 🚀 {rate/1024:.1f}k{unit}/s"
        else: base += f" 🚀 {rate:.1f}{unit}/s"
    return base

# ══════════════════════════════════════════════════
# 🌐  JS RENDERER  (Puppeteer via subprocess)
# ══════════════════════════════════════════════════

def fetch_with_puppeteer(url: str) -> str | None:
    """
    SECURITY: URL ကို sanitize + validate ပြီးမှသာ subprocess pass
    shell=False (default) ဖြစ်တဲ့အတွက် shell injection မဖြစ်နိုင်
    """
    if not PUPPETEER_OK:
        return None

    # ── Subprocess injection fix ──────────────────
    safe, reason = is_safe_url(url)
    if not safe:
        logger.warning(f"Puppeteer blocked unsafe URL: {reason}")
        return None

    # Strict URL chars whitelist (extra layer)
    if not re.match(r'^https?://[a-zA-Z0-9\-._~:/?#\[\]@!$&()*+,;=%]+$', url):
        logger.warning("Puppeteer blocked URL with invalid characters")
        return None

    try:
        result = subprocess.run(
            ["node", JS_RENDER, url],  # list → no shell injection possible
            capture_output=True,
            timeout=45,
            text=True,
            shell=False                # explicit: False
        )
        if result.returncode == 0 and result.stdout.strip():
            return result.stdout
        logger.warning(f"Puppeteer stderr: {result.stderr[:100]}")
        return None
    except subprocess.TimeoutExpired:
        log_warn(url, "puppeteer timeout")
        return None
    except Exception as e:
        logger.warning(f"Puppeteer exception: {type(e).__name__}")
        return None

def _fetch_page_sync(url: str, use_js: bool = False) -> tuple:
    """Sync version — called via asyncio.to_thread()
    V32 Upgrade:
    • Pooled Session (no per-call Session() leak)
    • Exponential backoff on 429 / 5xx (1s→2s→4s→8s)
    • WAF/CF detection → auto-UA rotation + delay
    • SSL fallback with retry
    • Cloudflare challenge detection
    • Referer injection for better asset fetch
    • Empty-body detection (CF JS challenge returns short HTML)
    • Sec-CH-UA + Priority headers for bot-detection bypass
    • Circuit Breaker: skip dead hosts after 5 consecutive failures
    """
    if use_js:
        html = fetch_with_puppeteer(url)
        if html:
            return html, True
        log_info(f"JS fallback to requests: {sanitize_log_url(url)}")

    parsed = urlparse(url)
    origin = f"{parsed.scheme}://{parsed.netloc}"
    host   = parsed.hostname or ""

    # ── Circuit Breaker: fail-fast on known-dead hosts ──
    if _CIRCUIT_BREAKER.is_open(host):
        logger.debug("Circuit OPEN — skipping %s", sanitize_log_url(url))
        return None, False

    def _do_fetch(verify: bool, referer: str = None) -> requests.Response:
        sess = _get_pooled_session(verify_ssl=verify)
        hdrs = _get_headers(referer=referer)
        # For same-origin fetches add Origin header
        if referer:
            hdrs['Origin'] = origin
            hdrs['Sec-Fetch-Site'] = 'same-origin'
        return sess.get(
            url,
            headers=hdrs,
            timeout=(8, TIMEOUT),   # (connect_timeout, read_timeout)
            allow_redirects=True,
        )

    MAX_FETCH_RETRIES = 4
    for attempt in range(MAX_FETCH_RETRIES):
        try:
            resp = _do_fetch(verify=True, referer=origin if attempt > 0 else None)

            # Cloudflare challenge (503/403 + cf-ray header)
            if resp.status_code in (403, 503) and ('cf-ray' in resp.headers or 'cloudflare' in resp.headers.get('server','').lower()):
                if attempt < MAX_FETCH_RETRIES - 1:
                    wait = min(2 ** attempt + random.uniform(0.5, 1.5), 15)
                    logger.debug("CF challenge on %s — wait %.1fs (attempt %d)", sanitize_log_url(url), wait, attempt)
                    # Rotate CF bypass strategy each retry
                    bypass_hdrs = _get_cf_bypass_headers(attempt)
                    hdrs = {**bypass_hdrs, 'Referer': url}
                    referer = url
                    time.sleep(wait)
                    continue
                return None, False

            # Cloudflare JS challenge: short body with cf-mitigated
            if resp.status_code == 200 and len(resp.content) < 2048:
                body_lower = resp.text.lower()
                if 'cf-spinner' in body_lower or 'challenge-platform' in body_lower or \
                   'just a moment' in body_lower or 'cf_chl_opt' in body_lower:
                    logger.debug("CF JS challenge detected on %s (attempt %d)", sanitize_log_url(url), attempt)
                    if attempt < MAX_FETCH_RETRIES - 1:
                        time.sleep(min(3 ** attempt, 15))
                        continue
                    return None, False

            # Rate limit back-off (429)
            if resp.status_code == 429:
                retry_after = int(resp.headers.get('Retry-After', 2 ** (attempt + 1)))
                time.sleep(min(retry_after, 30))
                continue

            # 5xx server errors — retry
            if resp.status_code in (500, 502, 503, 504, 520, 521, 522, 524):
                if attempt < MAX_FETCH_RETRIES - 1:
                    time.sleep(2 ** attempt)
                    continue
                return None, False

            ct = resp.headers.get('Content-Type', '')
            if resp.status_code == 200 and not any(
                t in ct for t in ('text/html', 'application/xhtml', 'text/plain',
                                  'application/xml', 'text/xml')
            ):
                return None, False

            if resp.status_code < 400:
                html = resp.text
                # Final CF JS challenge check even on 200
                if len(html) < 3000 and ('cf_chl_opt' in html or 'jschl_vc' in html or
                                          'cf-spinner' in html.lower()):
                    if attempt < MAX_FETCH_RETRIES - 1:
                        time.sleep(3)
                        continue
                    _CIRCUIT_BREAKER.record_failure(host)
                    return None, False
                _CIRCUIT_BREAKER.record_success(host)
                return html, False
            _CIRCUIT_BREAKER.record_failure(host)
            return None, False

        except requests.exceptions.SSLError:
            try:
                resp = _do_fetch(verify=False, referer=origin)
                ct = resp.headers.get('Content-Type', '')
                if not any(t in ct for t in ('text/html', 'application/xhtml', 'text/plain')):
                    return None, False
                _CIRCUIT_BREAKER.record_success(host)
                return resp.text, False
            except Exception as e:
                log_warn(url, f"fetch error (ssl-fallback): {type(e).__name__}")
                _CIRCUIT_BREAKER.record_failure(host)
                return None, False

        except requests.exceptions.Timeout:
            if attempt < MAX_FETCH_RETRIES - 1:
                time.sleep(1.5 * (attempt + 1))
                continue
            log_warn(url, "fetch timeout (all retries exhausted)")
            _CIRCUIT_BREAKER.record_failure(host)
            return None, False

        except requests.exceptions.ConnectionError as e:
            if attempt < MAX_FETCH_RETRIES - 1:
                time.sleep(2 ** attempt)
                continue
            log_warn(url, f"connection error: {type(e).__name__}")
            _CIRCUIT_BREAKER.record_failure(host)
            return None, False

        except Exception as e:
            log_warn(url, f"fetch error: {type(e).__name__}")
            return None, False

    _CIRCUIT_BREAKER.record_failure(host)
    return None, False

def fetch_page(url: str, use_js: bool = False) -> tuple:
    """Returns: (html | None, js_used: bool)
    Bug fix: requests.get() ကို sync ဖြင့် run — event loop ကို မ block ဖို့
    async context ထဲမှာ asyncio.to_thread(fetch_page, url) ဖြင့် ခေါ်ပါ
    CF bypass: empty result ဖြစ်ရင် bypass strategies ဖြင့် retry
    """
    html, js_used = _fetch_page_sync(url, use_js)
    if not html:
        # Retry with CF/WAF bypass header rotation
        for attempt in range(len(_CF_BYPASS_SESSIONS)):
            try:
                import time as _t
                _t.sleep(0.8 + attempt * 0.5)
                sess = _make_cf_session(attempt)
                r = sess.get(url, timeout=20, verify=False, allow_redirects=True)
                if r.status_code == 200 and len(r.text) > 100:
                    return r.text, False
            except Exception:
                continue
    return html, js_used


# ══════════════════════════════════════════════════
# 🔍  ASSET EXTRACTORS
# ══════════════════════════════════════════════════

def extract_assets(html: str, page_url: str, soup=None) -> set:
    """
    Extract all asset URLs from a page — v36 Improved.

    v36 ပြင်ချက်များ:
    - Protocol-relative URLs (//cdn.example.com/...) — page scheme ဖြင့် resolve
    - CSS url() improved: data: URI ကို လုံးဝ exclude
    - @font-face multi-url() per block — old regex missed 2nd+ url()
    - <link rel="dns-prefetch/preconnect"> ကို asset list မထည့် (false positives)
    - SRI integrity hash ကို URL တွင် မထည့်
    - Vite/Rollup /assets/ path support
    - Webpack publicPath-aware origin detection
    - javascript:/mailto:/tel: ကို _add() ထဲမှာပင် ပိတ်ဆို့
    - soup=None တွင် lxml fallback ပါ BeautifulSoup တိကျစွာ parse
    """
    from bs4 import BeautifulSoup

    # ── Parser selection (imported from bot globals) ─────────────────
    try:
        _parser = _BS_PARSER  # type: ignore[name-defined]
    except NameError:
        try:
            import lxml  # noqa: F401
            _parser = 'lxml'
        except ImportError:
            _parser = 'html.parser'

    if soup is None:
        try:
            soup = BeautifulSoup(html, _parser)
        except Exception as e:
            logger.debug("extract_assets: parse error: %s", e)
            return set()

    assets: set = set()
    parsed_base  = urlparse(page_url)
    origin       = f"{parsed_base.scheme}://{parsed_base.netloc}"

    # ── Detect <base> tag for relative URL resolution ────────────────
    base_tag = soup.find('base', href=True)
    base_url_resolved = base_tag['href'] if base_tag else page_url

    # ── Detect Webpack publicPath for better chunk URL resolution ────
    webpack_origin = origin
    for m in _RE_WEBPACK_PUBLIC.finditer(html):
        pp = (m.group(1) or m.group(2) or "").strip()
        if pp.startswith('http'):
            webpack_origin = pp.rstrip('/')
            break
        elif pp.startswith('/'):
            webpack_origin = origin

    def _add(url: str) -> None:
        """
        Normalize, validate and add a URL to assets.
        Handles: absolute, relative, protocol-relative.
        Excludes: data:, #anchors, javascript:, mailto:, tel:, SRI hashes.
        """
        if not url:
            return
        url = url.strip().strip('"\'')
        if not url:
            return
        # Fast-path exclusion
        lower = url.lower()
        if lower.startswith(('data:', '#', 'javascript:', 'mailto:', 'tel:', 'blob:')):
            return
        # SRI hash guard — avoid adding sha256-xxxx as URL
        if _RE_SRI_HASH.match(url):
            return

        # Protocol-relative → prepend page scheme
        if url.startswith('//'):
            url = parsed_base.scheme + ':' + url

        # Resolve relative URLs against <base> or page_url
        if not url.startswith('http'):
            url = urljoin(base_url_resolved, url)

        try:
            p = urlparse(url)
            if p.scheme in ('http', 'https') and p.netloc:
                assets.add(url)
        except Exception:
            pass
        """
        Normalize, validate and add a URL to assets.
        Handles: absolute, relative, protocol-relative.
        Excludes: data:, #anchors, javascript:, mailto:, tel:, SRI hashes.
        """
        if not url:
            return
        url = url.strip().strip('"\'')
        if not url:
            return
        # Fast-path exclusion
        lower = url.lower()
        if lower.startswith(('data:', '#', 'javascript:', 'mailto:', 'tel:', 'blob:')):
            return
        # SRI hash guard — avoid adding sha256-xxxx as URL
        if _RE_SRI_HASH.match(url):
            return

        # Protocol-relative → prepend page scheme
        if url.startswith('//'):
            url = parsed_base.scheme + ':' + url

        # Resolve relative URLs
        if not url.startswith('http'):
            url = urljoin(page_url, url)

        try:
            p = urlparse(url)
            if p.scheme in ('http', 'https') and p.netloc:
                assets.add(url)
        except Exception:
            pass

    def _parse_srcset(srcset_val: str) -> None:
        """
        Parse srcset attribute value.
        Format: "url1 1x, url2 2x" or "url1 480w, url2 800w"
        """
        if not srcset_val:
            return
        for candidate in srcset_val.split(','):
            parts = candidate.strip().split()
            if parts:
                _add(parts[0])

    def _extract_css_urls(css_text: str) -> None:
        """
        Extract all url() references from CSS text.
        Uses improved regex that avoids data: URIs and handles all quote styles.
        Also extracts @import and multi-url @font-face.
        """
        # url() — triple-group regex: double-quote, single-quote, unquoted
        for m in _RE_CSS_URL_SAFE.finditer(css_text):
            val = m.group(1) or m.group(2) or m.group(3) or ''
            val = val.strip()
            if val and not val.startswith('data:') and not val.startswith('#'):
                _add(val)
        # @import
        try:
            for m in _RE_CSS_IMPORT.finditer(css_text):  # type: ignore[name-defined]
                u = m.group(1).strip().strip('"\'')
                if u and not u.startswith('data:'):
                    _add(u)
        except NameError:
            pass
        # @font-face — multiple url() per block (woff/woff2/ttf/otf/eot/svg)
        for m in _RE_CSS_FONT_MULTI.finditer(css_text):
            _add(m.group(1).strip())

    # ══ 1. <link> ═══════════════════════════════════════════════
    # dns-prefetch / preconnect → connections, not assets → skip
    _LINK_ASSET_RELS = frozenset({
        'stylesheet', 'icon', 'shortcut icon', 'apple-touch-icon',
        'preload', 'prefetch', 'manifest', 'modulepreload',
    })
    for tag in soup.find_all('link'):
        href = (tag.get('href') or '').strip()
        if not href:
            continue
        rel_parts = [r.lower() for r in tag.get('rel', [])]
        rel_str   = ' '.join(rel_parts)
        # Only add if rel matches asset types (skip preconnect/dns-prefetch)
        if any(r in rel_str for r in _LINK_ASSET_RELS):
            _add(href)

    # ══ 2. <script src> + inline JS mining ══════════════════════
    for tag in soup.find_all('script'):
        src = (tag.get('src') or '').strip()
        if src:
            _add(src)
        inline = tag.string or ''
        if not inline.strip():
            continue
        try:
            # Full https?:// URLs in JS
            for m in _RE_JS_FULL_URL.finditer(inline):  # type: ignore[name-defined]
                _add(m.group(1))
            # Relative /path/ URLs in JS
            for m in _RE_JS_REL_URL.finditer(inline):  # type: ignore[name-defined]
                _add(m.group(1))
            # Next.js /_next/static/ chunks
            for m in _RE_NEXT_CHUNK.finditer(inline):  # type: ignore[name-defined]
                _add(origin + m.group(0))
            # Vite/Rollup /assets/ paths
            for m in _RE_VITE_ASSET.finditer(inline):
                _add(m.group(1))
            # Service Worker registration
            for m in _RE_SW_REGISTER.finditer(inline):  # type: ignore[name-defined]
                _add(m.group(1))
            # window.__NEXT_DATA__ / __INITIAL_STATE__ JSON blobs
            for m in _RE_WIN_STATE.finditer(inline):  # type: ignore[name-defined]
                blob = m.group(1)
                for jm in _RE_JSONLD_IMG.finditer(blob):  # type: ignore[name-defined]
                    _add(jm.group(1))
            # Protocol-relative in JS ("//cdn.example.com/lib.js")
            for m in _RE_PROTO_REL_URL.finditer(inline):  # type: ignore[name-defined]
                _add(m.group(1))
        except Exception as e:
            logger.debug("extract_assets: inline JS mining error: %s", e)

    # ══ 3. <img> — lazy-load attrs + srcset ═════════════════════
    try:
        _lazy_attrs = _LAZY_LOAD_ATTRS  # type: ignore[name-defined]
    except NameError:
        _lazy_attrs = ('src', 'data-src', 'data-lazy', 'data-original',
                       'data-lazy-src', 'data-srcset', 'data-image',
                       'data-img', 'data-bg', 'data-background')
    for tag in soup.find_all('img'):
        for attr in _lazy_attrs:
            v = (tag.get(attr) or '').strip()
            if v:
                _add(v)
        _parse_srcset(tag.get('srcset', ''))

    # ══ 4. <picture> + nested <source> ═══════════════════════════
    for tag in soup.find_all('picture'):
        for source in tag.find_all('source'):
            _parse_srcset(source.get('srcset', '') or source.get('data-srcset', ''))
            v = (source.get('src') or '').strip()
            if v:
                _add(v)

    # ══ 5. Standalone <source> (video/audio/picture) ════════════
    for tag in soup.find_all('source'):
        for attr in ('src', 'data-src'):
            v = (tag.get(attr) or '').strip()
            if v:
                _add(v)
        _parse_srcset(tag.get('srcset', ''))

    # ══ 6. <video> + <audio> ═════════════════════════════════════
    for tag in soup.find_all(['video', 'audio']):
        for attr in ('src', 'data-src', 'poster'):
            v = (tag.get(attr) or '').strip()
            if v:
                _add(v)

    # ══ 7. <iframe> embeds (media platforms only) ════════════════
    _IFRAME_ALLOW = ('youtube', 'vimeo', 'player', 'embed', 'video', 'cdn',
                     'dailymotion', 'twitch', 'streamable')
    for tag in soup.find_all('iframe', src=True):
        s = (tag.get('src') or '').strip()
        if s and any(x in s.lower() for x in _IFRAME_ALLOW):
            _add(s)

    # ══ 8. Deep Regex Discovery (v46) ════════════════════════════
    # Find all potential API endpoints and hidden files in the entire HTML
    for m in _RE_API_ENDPOINT.finditer(html):
        _add(m.group(0))
    for m in _RE_HIDDEN_FILES.finditer(html):
        _add(m.group(0))
    for m in _RE_CLOUD_BUCKET.finditer(html):
        bucket_url = m.group(0)
        if not bucket_url.startswith('http'):
            bucket_url = 'https://' + bucket_url
        _add(bucket_url)
    for m in _RE_URL_IN_HTML.finditer(html):
        _add(m.group(1))

    # ══ 8. <a href> downloadable files ══════════════════════════
    _FILE_EXTS = frozenset({
        '.pdf', '.zip', '.rar', '.7z', '.tar', '.gz', '.bz2',
        '.doc', '.docx', '.xls', '.xlsx', '.ppt', '.pptx', '.odt',
        '.mp3', '.mp4', '.avi', '.mkv', '.mov', '.webm', '.flac', '.wav',
        '.apk', '.exe', '.dmg', '.iso', '.deb', '.rpm',
    })
    for tag in soup.find_all('a', href=True):
        h = (tag.get('href') or '').strip()
        if not h or h.startswith(('#', 'mailto:', 'tel:', 'javascript:')):
            continue
        full = urljoin(page_url, h)
        path_no_qs = full.lower().split('?')[0].split('#')[0]
        if any(path_no_qs.endswith(ext) for ext in _FILE_EXTS):
            assets.add(full)

    # ══ 9. <object> + <embed> ════════════════════════════════════
    for tag in soup.find_all(['object', 'embed']):
        v = (tag.get('data') or tag.get('src') or '').strip()
        if v:
            _add(v)

    # ══ 10. SVG <image> and xlink:href ══════════════════════════
    for tag in soup.find_all('image'):
        for attr in ('href', 'xlink:href'):
            v = (tag.get(attr) or '').strip()
            if v and not v.startswith('#'):
                _add(v)

    # ══ 11. Inline style="…" url() references ═══════════════════
    for tag in soup.find_all(style=True):
        style_val = tag.get('style', '')
        if style_val:
            _extract_css_urls(style_val)

    # ══ 12. <style> block CSS (url + @import + @font-face) ══════
    for st in soup.find_all('style'):
        css = st.string or ''
        if css.strip():
            _extract_css_urls(css)

    # ══ 13. <meta> OG / Twitter / Schema images ═════════════════
    _META_IMAGE_KEYS = ('image', 'thumbnail', 'banner', 'icon', 'logo',
                        'og:image', 'twitter:image')
    for tag in soup.find_all('meta'):
        prop = (tag.get('property', '') + tag.get('name', '')).lower()
        if any(k in prop for k in _META_IMAGE_KEYS):
            c = (tag.get('content') or '').strip()
            if c.startswith(('http', '//')):
                _add(c)
        # meta refresh redirect URL
        if tag.get('http-equiv', '').lower() == 'refresh':
            content = tag.get('content', '')
            url_m = re.search(r'url\s*=\s*["\x27"]?([^"\x27;\s]+)', content, re.IGNORECASE)
            if url_m:
                _add(url_m.group(1))

    # ══ 14. JSON-LD structured data images ══════════════════════
    for tag in soup.find_all('script', type='application/ld+json'):
        txt = tag.string or ''
        try:
            for m in _RE_JSONLD_IMG.finditer(txt):  # type: ignore[name-defined]
                _add(m.group(1))
        except NameError:
            pass

    # ══ 15. Raw HTML regex sweep (server-injected paths) ════════
    #   protocol-relative sweep
    for m in _RE_PROTO_REL_URL.finditer(html):  # type: ignore[name-defined]
        _add(m.group(1))
    try:
        for m in _RE_URL_IN_HTML.finditer(html):  # type: ignore[name-defined]
            _add(m.group(1))
    except NameError:
        pass

    # ══ 16. Manifest & BrowserConfig ════════════════════════════
    # If we see a link to manifest.json or browserconfig.xml, we'll 
    # eventually need to parse them. For now, ensure they are in assets.
    for tag in soup.find_all('link', rel=lambda x: x and ('manifest' in x.lower() or 'config' in x.lower())):
        _add(tag.get('href', ''))

    return assets

def extract_css_assets(css: str, css_url: str) -> set:
    """
    Extract all asset URLs from CSS text — v35 upgrade.
    Handles: url() with/without quotes, @import, @font-face src chains.
    Bug fix: old regex matched data: URIs and failed on unquoted url().
    Uses improved _RE_CSS_URL and _RE_CSS_IMPORT patterns.
    """
    assets = set()
    # url(...) — covers background, border-image, mask, src, etc.
    for m in _RE_CSS_URL.finditer(css):
        u = m.group(1).strip().strip('"\'')
        if u and not u.startswith('data:') and not u.startswith('#'):
            assets.add(urljoin(css_url, u))
    # @import
    for m in _RE_CSS_IMPORT.finditer(css):
        u = m.group(1).strip().strip('"\'')
        if u and not u.startswith('data:'):
            assets.add(urljoin(css_url, u))
    # @font-face src (may have multiple url() in one block)
    for m in _RE_CSS_FONT.finditer(css):
        u = m.group(1).strip().strip('"\'')
        if u and not u.startswith('data:'):
            assets.add(urljoin(css_url, u))
    return assets


def extract_media_from_js(js_content: str, base_url: str) -> set:
    """
    Mine JS/JSON files for media URLs, webpack chunks, and asset paths.
    v35 upgrade: uses module-level pre-compiled patterns (was re.compile()
    inside the function — recompiled on every call, wasting CPU).
    Also added: service worker paths, window.__INITIAL_STATE__ images.
    """
    assets = set()
    origin = f"{urlparse(base_url).scheme}://{urlparse(base_url).netloc}"

    # Full https?:// URLs
    for m in _RE_JS_FULL_URL.finditer(js_content):
        assets.add(m.group(1))

    # Relative /path/to/asset URLs
    for m in _RE_JS_REL_URL.finditer(js_content):
        assets.add(urljoin(base_url, m.group(1)))

    # Webpack content-hash named chunks (e.g. "abc12345.main.js")
    for m in _RE_WEBPACK_CHUNK.finditer(js_content):
        assets.add(f"{origin}/static/js/{m.group(1)}")

    # Next.js /_next/static/ chunks
    for m in _RE_NEXT_CHUNK.finditer(js_content):
        assets.add(urljoin(base_url, m.group(0)))

    # Service worker registration paths
    for m in _RE_SW_REGISTER.finditer(js_content):
        assets.add(urljoin(base_url, m.group(1)))

    # Embedded JSON state blobs (window.__NEXT_DATA__ etc.)
    for m in _RE_WIN_STATE.finditer(js_content):
        for jm in _RE_JSONLD_IMG.finditer(m.group(1)):
            assets.add(jm.group(1))

    return assets


# ══════════════════════════════════════════════════
# 🗺️  SITEMAP PARSER
# ══════════════════════════════════════════════════

def fetch_sitemap(base_url: str) -> set:
    """
    Fetch sitemap.xml (and sitemap index) — returns all page URLs.
    Supports: /sitemap.xml, /sitemap_index.xml, /robots.txt discovery
    """
    urls   = set()

    def _fetch_one_sitemap(url: str, depth: int = 0):
        if depth > 5:   # v45: increased depth limit
            return
        try:
            r = requests.get(url, headers=_get_headers(), timeout=15, verify=False)
            if r.status_code != 200:
                return
            
            content = r.content
            # v45: GZIP support
            if url.endswith('.gz') or content.startswith(b'\x1f\x8b'):
                import gzip
                try:
                    content = gzip.decompress(content)
                except Exception:
                    pass
            text = content.decode('utf-8', 'replace')
            
            # Sitemap index → recurse
            if '<sitemapindex' in text:
                for m in _RE_SITEMAP_LOC.finditer(text):
                    sub = m.group(1).strip()
                    if sub not in urls:
                        _fetch_one_sitemap(sub, depth + 1)
            else:
                for m in _RE_SITEMAP_LOC.finditer(text):
                    urls.add(m.group(1).strip())
        except Exception as _e:
            logging.debug("Scan error: %s", _e)

    # Try common sitemap locations
    parsed = urlparse(base_url)
    root   = f"{parsed.scheme}://{parsed.netloc}"

    # 1. Check HTML for <link rel="sitemap">
    try:
        r = _make_cf_session(0).get(base_url, timeout=10, verify=False)
        if r.status_code == 200:
            from bs4 import BeautifulSoup
            soup = BeautifulSoup(r.text, 'html.parser')
            for link in soup.find_all('link', rel=lambda x: x and 'sitemap' in x.lower()):
                href = link.get('href')
                if href:
                    _fetch_one_sitemap(urljoin(base_url, href))
    except Exception:
        pass

    # 2. Check robots.txt for sitemap pointer
    try:
        r = _make_cf_session(0).get(f"{root}/robots.txt",
                         timeout=8, verify=False)
        if r.status_code == 200:
            for m in _RE_ROBOTS_SM.finditer(r.text):
                _fetch_one_sitemap(m.group(1).strip())
    except Exception as _e:
        logging.debug("Scan error: %s", _e)

    # 3. Brute-force common paths
    common_paths = [
        '/sitemap.xml', '/sitemap_index.xml', '/sitemap-index.xml',
        '/sitemap/sitemap.xml', '/wp-sitemap.xml',
        '/news-sitemap.xml', '/post-sitemap.xml',
        '/page-sitemap.xml', '/product-sitemap.xml',
        '/sitemap.xml.gz', '/sitemap_index.xml.gz',
        '/sitemap/', '/sitemaps/', '/sitemap_index.xml.php'
    ]
    for path in common_paths:
        _fetch_one_sitemap(root + path)

    # Filter to same domain only
    netloc = parsed.netloc
    return {u for u in urls if urlparse(u).netloc == netloc}


