    re.compile(r"""(?:url|endpoint|baseURL|apiUrl|API_URL|baseUrl|apiBase|BASE_URL|API_BASE)\s*[:=]\s*['"`]([^'"`\s]{5,200})['"`]"""),
    re.compile(r"""['"`](/api/[^\\s\x27"`\?#]{3,100})['"`]"""),
    re.compile(r"""['"`](/rest/[^\\s\x27"`\?#]{3,100})['"`]"""),
    re.compile(r"""['"`](/v\d+/[^\\s\x27"`\?#]{3,100})['"`]"""),
