def _parse_semver_simple(ver_str: str) -> tuple:
    """'1.2.3-beta' → (1,2,3). Returns (0,0,0) on failure."""
    try:
        clean = re.sub(r'[^0-9.]', '', ver_str.split('-')[0])
        parts = clean.split('.')[:3]
        return tuple(int(x) for x in (parts + ['0', '0'])[:3])
    except Exception:
        return (0, 0, 0)


def _extract_api_urls_from_js(js_text: str, base_root: str) -> list:
    """JS bundle/source ထဲက API URL တွေ mine လုပ်"""
    found = set()
    for pat in _JS_API_PATTERNS:
        for m in pat.findall(js_text):
            url = m.strip()
            if not url or len(url) < 4:
                continue
            if url.startswith('/'):
                url = base_root + url
            if url.startswith('http') and '/api/' not in url and '/rest/' not in url and '/v' not in url:
                continue
            if url.startswith('http') or url.startswith('/'):
                found.add(url)
    return list(found)


_RE_API_PATH_BROAD = re.compile(
    r'^(/(?:api|v\d+|rest|rpc|graphql|query|gql|service|svc|ws|sse|stream|internal|private|admin|backend|gateway|proxy)[/\w\-\.]{0,120})$',
    re.I
)
_RE_INIT_STATE = re.compile(
    r'window\.__(?:INITIAL_STATE|NUXT|STATE|APP_STATE|PRELOADED_STATE)__\s*=\s*(\{.{10,}?\});',
    re.DOTALL
)
_RE_NEXT_DATA  = re.compile(r"<script[^>]+__NEXT_DATA__[^>]*>(.+?)</script>", re.DOTALL)


def _looks_like_api_url(url: str) -> bool:
    kw = ('/api/', '/v1/', '/v2/', '/v3/', '/rest/', '/rpc/', '/graphql',
          '/query', '/gql', '/sse/', '/stream/', '/internal/', '/private/',
          '/admin/api', '/backend/', '/service/', '/gateway/')
    return any(k in url.lower() for k in kw)


def _walk_json_for_api_urls(obj, base_root: str, depth: int = 0) -> list:
    if depth > 5:
        return []
    found = []
    if isinstance(obj, dict):
        for k, v in obj.items():
            if isinstance(v, str) and len(v) > 2:
                path = v.split('?')[0]
                if _RE_API_PATH_BROAD.match(path):
                    found.append(base_root + path)
                elif v.startswith('http') and _looks_like_api_url(v):
                    found.append(v.split('?')[0])
            elif isinstance(v, (dict, list)):
                found.extend(_walk_json_for_api_urls(v, base_root, depth + 1))
    elif isinstance(obj, list):
        for item in obj[:20]:
            found.extend(_walk_json_for_api_urls(item, base_root, depth + 1))
    return found


def _extract_api_urls_from_html(html: str, base_root: str) -> list:
    """HTML source ထဲက API references mine လုပ် — v2 (deep)"""
    found = set()
    soup  = BeautifulSoup(html, 'html.parser')

    # ① All attributes — broadened filter (/v2/, /rpc/, /gql/ etc.)
    for tag in soup.find_all(True):
        for attr, val in tag.attrs.items():
            if not isinstance(val, str):
                continue
            path = val.strip().split('?')[0]
            if _RE_API_PATH_BROAD.match(path):
                found.add(base_root + path)
            elif val.startswith('http') and _looks_like_api_url(val):
                found.add(val.split('?')[0])

    # ② Form action endpoints (POST write targets)
    for form in soup.find_all('form'):
        action = form.get('action', '')
        if action and action != '#' and len(action) > 1:
            url = (base_root + action) if action.startswith('/') else action
            if url.startswith('http'):
                found.add(url.split('?')[0])

    # ③ <meta> API hints
    for meta in soup.find_all('meta'):
        content = meta.get('content', '') or ''
        name    = (meta.get('name', '') + meta.get('property', '')).lower()
        if content and any(k in name for k in ('api', 'endpoint', 'base', 'service')):
            if content.startswith(('/', 'http')):
                url = (base_root + content) if content.startswith('/') else content
                found.add(url.split('?')[0])

    # ④ <link rel=manifest/preload/prefetch>
    for link in soup.find_all('link'):
        href = link.get('href', '')
        rel  = ' '.join(link.get('rel', [])).lower()
        if href and any(k in rel for k in ('manifest', 'preload', 'prefetch')):
            url = (base_root + href) if href.startswith('/') else href
            if url.startswith('http'):
                found.add(url.split('?')[0])

    # ⑤ Inline scripts
    for script in soup.find_all('script'):
        if script.get('src'):
            continue
        content = script.string or ''
        if not content:
            continue
        for url in _extract_api_urls_from_js(content, base_root):
            found.add(url.split('?')[0])
        # window.__INITIAL_STATE__ / __NUXT__ JSON blob
        for m in _RE_INIT_STATE.finditer(content):
            try:
                blob = json.loads(m.group(1))
                for url in _walk_json_for_api_urls(blob, base_root):
                    found.add(url)
            except Exception:
                pass

    # ⑥ __NEXT_DATA__ inline JSON (Next.js pages)
    nd = _RE_NEXT_DATA.search(html)
    if nd:
        try:
            nd_data = json.loads(nd.group(1))
            # runtimeConfig, publicRuntimeConfig contain API base URLs
            for key in ('runtimeConfig', 'publicRuntimeConfig', 'serverRuntimeConfig'):
                rc = nd_data.get(key, {})
                for url in _walk_json_for_api_urls(rc, base_root):
                    found.add(url)
            # page props may contain prefetched API data URLs
            props = nd_data.get('props', {})
            for url in _walk_json_for_api_urls(props, base_root):
                found.add(url)
        except Exception:
            pass

    # ⑦ noscript/iframe fallback
    for tag in soup.find_all(['noscript', 'iframe', 'object']):
        src = tag.get('src') or tag.get('data') or ''
        if src and _looks_like_api_url(src):
            url = (base_root + src) if src.startswith('/') else src
            found.add(url.split('?')[0])

    return list(found)


