def _mine_js_bundles(html: str, root: str, proxies) -> list:
    """External JS files တွေ download ပြီး API URLs ထုတ် — v2 (deep: manifest + routes + env)"""
    global _BUNDLE_INTEL
    _BUNDLE_INTEL = {'env_vars': {}, 'js_routes': [], 'chunk_urls': []}

    soup    = BeautifulSoup(html, 'html.parser')
    js_urls = []
    seen_js = set()
    found   = set()
    routes  = []
    env_vars: dict = {}

    # ── Collect JS URLs from HTML ────────────────────────────────────────────
    for tag in soup.find_all('script', src=True):
        src = tag['src']
        if not src: continue
        if src.startswith('//'): src = 'https:' + src
        elif src.startswith('/'): src = root + src
        if src.startswith('http') and src not in seen_js:
            if src.endswith('.js') or any(kw in src.lower() for kw in (
                'chunk', 'bundle', 'main', 'app', 'vendor', 'index', 'runtime',
                'polyfill', 'pages', 'component', 'init', 'config', 'api',
                'service', 'util', 'helper', 'module', 'store', 'router',
                'layout', 'view', 'action', 'reducer', 'webpack', 'next',
            )):
                js_urls.append(src)
                seen_js.add(src)

    # ── Phase A: Manifests & well-known (cheap, high yield) ─────────────────
    for mp in _MANIFEST_PATHS:
        murl = root + mp
        if murl in seen_js: continue
        try:
            r = requests.get(murl, headers=HEADERS, timeout=5, verify=False)
            if r.status_code != 200 or len(r.text) < 10:
                continue
            seen_js.add(murl)
            ct = r.headers.get('Content-Type', '')
            if 'json' in ct or murl.endswith('.json'):
                try:
                    mdata = r.json()
                    # Walk manifest for chunk URLs and page routes
                    def _walk_manifest(obj, dep=0):
                        if dep > 4: return
                        if isinstance(obj, dict):
                            for k, v in obj.items():
                                if isinstance(v, str):
                                    if v.endswith('.js') and ('/' in v or v.startswith('_')):
                                        chunk = (root + '/' + v.lstrip('/')) if not v.startswith('http') else v
                                        if chunk not in seen_js:
                                            js_urls.append(chunk)
                                            seen_js.add(chunk)
                                            _BUNDLE_INTEL['chunk_urls'].append(chunk)
                                    if k.startswith('/') and len(k) > 1:
                                        routes.append(k)
                                elif isinstance(v, (dict, list)):
                                    _walk_manifest(v, dep+1)
                        elif isinstance(obj, list):
                            for item in obj: _walk_manifest(item, dep+1)
                    _walk_manifest(mdata)
                    # OIDC / OAuth endpoint extraction
                    if isinstance(mdata, dict):
                        for key in ('authorization_endpoint', 'token_endpoint',
                                    'userinfo_endpoint', 'revocation_endpoint',
                                    'introspection_endpoint', 'jwks_uri'):
                            if key in mdata and isinstance(mdata[key], str):
                                found.add(mdata[key])
                except Exception:
                    pass
            elif murl.endswith('.js'):
                for url in _extract_api_urls_from_js(r.text, root):
                    found.add(url)
        except Exception as _e:
            logging.debug("Manifest %s: %s", mp, _e)

    # ── Phase B: Common bundle paths not in HTML ─────────────────────────────
    _COMMON_BUNDLE_PATHS = [
        '/static/js/main.js', '/assets/js/app.js', '/js/app.js',
        '/dist/bundle.js', '/build/static/js/main.chunk.js',
        '/_next/static/chunks/main.js', '/nuxt/dist/client/app.js',
        '/assets/index.js', '/public/app.js', '/js/index.js',
        '/static/bundle.js', '/dist/app.js', '/js/bundle.js', '/dist/js/app.js',
    ]
    for bp in _COMMON_BUNDLE_PATHS:
        full = root + bp
        if full not in seen_js:
            js_urls.append(full)
            seen_js.add(full)

    # ── Phase C: Deep-mine each JS bundle ────────────────────────────────────
    def _fetch_and_mine(js_url):
        result = {'urls': [], 'routes': [], 'env': {}, 'secrets': []}
        try:
            r = requests.get(js_url, headers=HEADERS, timeout=15, verify=False)
            if r.status_code != 200 or len(r.text) < 100:
                return result
            content = r.text

            # API URLs
            result['urls'] = _extract_api_urls_from_js(content, root)

            # Route definitions
            for pat in _ROUTE_RE_LIST:
                for m in pat.findall(content):
                    route = m[-1] if isinstance(m, tuple) else m
                    if isinstance(route, str) and route.startswith('/') and len(route) > 1:
                        result['routes'].append(route)

            # Env vars / config values containing URL/API hints
            for m in _RE_ENV_CAPTURE.finditer(content):
                var_name, var_val = m.group(1), m.group(2)
                if any(k in var_name for k in ('URL', 'API', 'BASE', 'HOST', 'ENDPOINT', 'SERVICE',
                                                 'KEY', 'SECRET', 'TOKEN', 'PASSWORD', 'PASS')):
                    result['env'][var_name] = var_val

            # Secret patterns quick-scan
            for pat, label in _ANALYZE_SECRET_PATTERNS[:30]:  # fast subset
                try:
                    for m in set(re.findall(pat, content)):
                        val = m[-1] if isinstance(m, tuple) else m
                        if len(val) >= 8:
                            masked = val[:6] + "···" + val[-4:] if len(val) > 10 else val
                            result['secrets'].append(f"{label}: `{masked[:60]}`")
                except Exception:
                    pass

            # Webpack runtime chunk map → discover dynamic import chunks
            if 'webpackChunk' in content or '__webpack_require__' in content:
                chunk_map = dict(_RE_WEBPACK_MAP.findall(content[:60000]))
                if chunk_map:
                    base_js = js_url.rsplit('/', 1)[0] + '/'
                    for cid, chash in list(chunk_map.items())[:60]:
                        chunk_url = f"{base_js}{cid}.{chash}.js"
                        result['urls'].append(chunk_url)

            # Next.js page chunk map
            if '_next' in js_url:
                for m in _RE_NEXT_PAGES.findall(content[:100000]):
                    page_path = m[0]
                    if page_path.startswith('/'):
                        result['routes'].append(page_path)

        except Exception as _e:
            logging.debug("JS mine %s: %s", js_url, _e)
        return result

    js_all_secrets = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=24) as ex:
        futs = {ex.submit(_fetch_and_mine, u): u for u in js_urls[:120]}
        try:
            for fut in concurrent.futures.as_completed(futs, timeout=55):
                try:
                    res = fut.result(timeout=10)
                    for url in res['urls']:
                        found.add(url.split('?')[0])
                    routes.extend(res['routes'])
                    env_vars.update(res['env'])
                    js_all_secrets.extend(res.get('secrets', []))
                except Exception:
                    pass
        except concurrent.futures.TimeoutError:
            for f in futs: f.cancel()

    # Save intel for report
    _BUNDLE_INTEL['env_vars']  = env_vars
    _BUNDLE_INTEL['js_routes'] = list(set(routes))
    _BUNDLE_INTEL['js_secrets'] = list(dict.fromkeys(js_all_secrets))[:50]  # deduplicated

    # Convert discovered routes to probe URLs
    for route in set(routes):
        if route.startswith('/') and len(route) > 1:
            found.add(root + route)

    return list(found)


_RE_SITEMAP_LOC   = re.compile(r'<loc>\s*(https?://[^<\s]+)\s*</loc>', re.I)
_RE_SITEMAP_INDEX = re.compile(r'<sitemap>', re.I)

_WELL_KNOWN_PATHS = [
    '/.well-known/openid-configuration',
    '/.well-known/oauth-authorization-server',
    '/.well-known/jwks.json',
    '/.well-known/assetlinks.json',
    '/.well-known/apple-app-site-association',
    '/.well-known/security.txt',
    '/security.txt',
    '/humans.txt',
]

def _parse_sitemap_urls(url: str, depth: int = 0) -> list:
    """Recursively parse sitemap XML → list of <loc> URLs"""
    if depth > 2:
        return []
    urls = []
    try:
        r = requests.get(url, headers=HEADERS, timeout=8, verify=False)
        if r.status_code != 200:
            return []
        text = r.text
        if _RE_SITEMAP_INDEX.search(text[:500]):
            for child_url in _RE_SITEMAP_LOC.findall(text)[:8]:
                urls.extend(_parse_sitemap_urls(child_url, depth + 1))
        else:
            urls = _RE_SITEMAP_LOC.findall(text)[:300]
    except Exception as _e:
        logging.debug("sitemap error: %s", _e)
    return urls


def _check_robots_and_sitemap(root: str, proxies) -> list:
    """robots.txt + sitemap + .well-known — v2 (full parse)"""
    found = set()

    # ── ① robots.txt — ALL Disallow/Allow paths ─────────────────────────────
    try:
        r = requests.get(root + '/robots.txt', headers=HEADERS, timeout=8, verify=False)
        if r.status_code == 200:
            sm_urls = []
            for line in r.text.splitlines():
                line = line.strip()
                lo   = line.lower()
                if lo.startswith('disallow:') or lo.startswith('allow:'):
                    path = line.split(':', 1)[1].strip().split('*')[0].rstrip('$')
                    if path and len(path) > 1 and path != '/':
                        found.add(root + path)   # ALL paths, not just /api/
                elif lo.startswith('sitemap:'):
                    sm_url = line.split(':', 1)[1].strip()
                    if sm_url.startswith('http'):
                        sm_urls.append(sm_url)
            for sm_url in sm_urls[:5]:
                for u in _parse_sitemap_urls(sm_url):
                    found.add(u)
    except Exception as _e:
        logging.debug("robots.txt error: %s", _e)

    # ── ② sitemap.xml standard locations ────────────────────────────────────
    for sm_path in ('/sitemap.xml', '/sitemap_index.xml', '/wp-sitemap.xml',
                    '/sitemap-index.xml', '/sitemap/sitemap.xml'):
        try:
            r = requests.get(root + sm_path, headers=HEADERS, timeout=6, verify=False)
            if r.status_code == 200 and '<url' in r.text.lower():
                for u in _parse_sitemap_urls(root + sm_path):
                    found.add(u)
                break
        except Exception:
            pass

    # ── ③ .well-known endpoints ──────────────────────────────────────────────
    for wk in _WELL_KNOWN_PATHS:
        try:
            r = requests.get(root + wk, headers=HEADERS, timeout=5, verify=False)
            if r.status_code == 200:
                found.add(root + wk)
                # OIDC / OAuth config → extract real auth endpoints
                if 'openid' in wk or 'oauth' in wk:
                    try:
                        oidc = r.json()
                        for key in ('authorization_endpoint', 'token_endpoint',
                                    'userinfo_endpoint', 'revocation_endpoint',
                                    'introspection_endpoint', 'jwks_uri',
                                    'device_authorization_endpoint'):
                            if key in oidc and isinstance(oidc[key], str):
                                found.add(oidc[key])
                    except Exception:
                        pass
        except Exception:
            pass

    return list(found)


def discover_api_endpoints(base_url: str, progress_cb=None) -> dict:
    """
    Comprehensive API discovery with CMS-aware path prioritization.
    1. SiteProfile → reorder paths by detected CMS
    2. HTML source mining
    3. JS bundle mining
    4. robots.txt discovery
    5. CORS header detection
    """
    parsed  = urlparse(base_url)
    root    = f"{parsed.scheme}://{parsed.netloc}"

    # ── Reuse or build SiteProfile ────────────────
    domain  = parsed.netloc
    profile = _PROFILE_CACHE.get(domain) or detect_site_profile(base_url)

    # ── Profile-aware path ordering ──────────────
    # Put CMS-specific paths first so results appear faster
    if profile.is_wordpress:
        priority = _API_PATHS_NEWS + list(_API_PATHS_GENERAL)
        rest     = [p for p in ALL_API_PATHS if p not in priority]
        ordered_paths = priority + rest
        api_workers   = 8 if not (profile.is_cloudflare or profile.has_waf) else 4
        probe_delay   = 0.15 if profile.is_cloudflare else 0.0
        if progress_cb:
            progress_cb("📝 *WordPress detected* — WP/WooCommerce paths first")
    elif profile.is_shopify:
        priority = [
            '/products.json', '/collections.json', '/pages.json',
            '/collections/all/products.json',
            '/admin/api/2023-10/products.json',
            '/cart.js', '/recommendations/products.json',
        ] + list(_API_PATHS_GENERAL)
        rest     = [p for p in ALL_API_PATHS if p not in priority]
        ordered_paths = priority + rest
        api_workers   = 6
        probe_delay   = 0.2
        if progress_cb:
            progress_cb("🛍️ *Shopify detected* — Shopify API paths first")
    elif profile.is_spa:
        priority = [
            '/api/graphql', '/graphql', '/api/v1', '/api/v2',
            '/api/auth', '/api/me', '/api/config',
        ] + list(_API_PATHS_GENERAL)
        rest     = [p for p in ALL_API_PATHS if p not in priority]
        ordered_paths = priority + rest
        api_workers   = 12
        probe_delay   = 0.0
        if progress_cb:
            progress_cb("⚛️ *SPA detected* — GraphQL/REST paths first")
    elif profile.is_cloudflare or profile.has_waf:
        ordered_paths = list(ALL_API_PATHS)
        api_workers   = 5
        probe_delay   = 0.3
        if progress_cb:
            progress_cb("☁️ *Cloudflare/WAF detected* — slow scan mode")
    else:
        ordered_paths = list(ALL_API_PATHS)
        api_workers   = 15
        probe_delay   = 0.0

    # ── Phase 0: Fetch homepage for mining ───────
    homepage_html = None
    try:
        r0 = requests.get(base_url, headers=HEADERS, timeout=12, verify=False)
        if r0.status_code == 200:
            homepage_html = r0.text
    except Exception as _e:
        logging.debug("Scan error: %s", _e)

    # ── Phase 1: HTML + JS mining (parallel) ─────
    html_mined = []
    js_mined   = []
    robots_found = []

    if homepage_html:
        if progress_cb: progress_cb("🔍 HTML source mining...")
        html_mined = _extract_api_urls_from_html(homepage_html, root)

        if progress_cb: progress_cb("📦 JS bundle mining...")
        js_mined   = _mine_js_bundles(homepage_html, root, None)

    if progress_cb: progress_cb("🤖 robots.txt scanning...")
    robots_found = _check_robots_and_sitemap(root, None)

    # ── Phase 2: Path brute-force ─────────────────
    found  = []
    seen   = set()

    # ── GraphQL introspection query ─────────────────────────────────────────
    _GQL_INTROSPECT = {"query": "{__schema{queryType{name}mutationType{name}types{name kind fields(includeDeprecated:false){name type{name kind ofType{name kind}}}}}}"}
    _GQL_INTEL    = {}
    _OPENAPI_EXTRAS = []

    def _parse_gql_schema(sr):
        result = {"queries": [], "mutations": [], "types": []}
        try:
            schema = sr.get("data", {}).get("__schema", {})
            qt = (schema.get("queryType") or {}).get("name", "Query")
            mt = (schema.get("mutationType") or {}).get("name", "Mutation")
            for t in schema.get("types", []):
                nm, kd = t.get("name",""), t.get("kind","")
                if nm.startswith("__"): continue
                if nm == qt:
                    result["queries"] = [f.get("name") for f in (t.get("fields") or []) if f.get("name")]
                elif nm == mt:
                    result["mutations"] = [f.get("name") for f in (t.get("fields") or []) if f.get("name")]
                elif kd == "OBJECT" and not nm.startswith("_"):
                    result["types"].append(nm)
        except Exception: pass
        return result

    def _parse_openapi(spec, spec_base):
        eps = []
        try:
            if "servers" in spec:
                base = spec["servers"][0].get("url", root)
                if base.startswith("/"): base = root + base
            elif "host" in spec:
                scheme = spec.get("schemes", ["https"])[0]
                base = f"{scheme}://{spec['host']}{spec.get('basePath','')}"
            else:
                base = root
            for path, pi in list(spec.get("paths", {}).items())[:150]:
                for method in ("get","post","put","patch","delete"):
                    op = pi.get(method)
                    if not op: continue
                    sec = op.get("security", None)
                    risk = 0; auth_hint = None
                    if sec == []: risk += 25; auth_hint = "NONE (no auth)"
                    elif sec: auth_hint = list(sec[0].keys())[0] if sec[0] else "REQUIRED"
                    if method in ("post","put","patch","delete"): risk += 15
                    params = [p.get("name") for p in op.get("parameters",[]) if p.get("name")]
                    eps.append({
                        "url": base.rstrip("/") + path, "type": "JSON_API", "status": 200,
                        "method": method.upper(), "note": op.get("summary","")[:60],
                        "risk": risk, "size_b": 0, "cors": None,
                        "fields": params, "auth_hint": auth_hint, "source": "openapi_spec",
                    })
        except Exception as _e: logging.debug("OpenAPI: %s", _e)
        return eps

    def _probe(path: str) -> dict | None:
        url = root + path if path.startswith("/") else path
        try:
            r = requests.get(url, headers={**HEADERS, "Accept": "application/json, text/plain, */*"},
                             timeout=7, verify=False, allow_redirects=True)
            ct           = r.headers.get("Content-Type", "")
            cors         = r.headers.get("Access-Control-Allow-Origin", "")
            cors_methods = r.headers.get("Access-Control-Allow-Methods", "")
            server       = r.headers.get("Server", "")
            powered      = r.headers.get("X-Powered-By", "")
            www_auth     = r.headers.get("WWW-Authenticate", "")
            size         = len(r.content)
            risk = 0
            path_lower = path.lower()
            for kw in ("admin","config","secret","credential","password","token","key","backup",
                       "dump","sql","env","private","internal","debug","actuator","graphql",
                       "swagger","openapi","export","download","management","monitoring","health"):
                if kw in path_lower: risk += 20; break

            endpoint = {
                "url": url, "status": r.status_code,
                "cors": cors if cors else None,
                "cors_methods": cors_methods if cors_methods else None,
                "server": server if server else None,
                "powered_by": powered if powered else None,
                "size_b": size, "preview": "", "type": "OTHER",
                "method": "GET", "risk": risk,
                "fields": [],
                "auth_hint": www_auth.split(" ")[0].upper() if www_auth else None,
                "pagination": False, "version": None,
            }

            if r.status_code in (401, 403):
                endpoint["type"]  = "PROTECTED"; endpoint["risk"] += 15
                try:
                    opts  = requests.options(url, headers=_get_headers(), timeout=4, verify=False)
                    allow = opts.headers.get("Allow","") or opts.headers.get("Access-Control-Allow-Methods","")
                    if allow:
                        endpoint["note"] = f"Allow: {allow[:60]}"
                        if any(m in allow.upper() for m in ("PUT","PATCH","DELETE")):
                            endpoint["risk"] += 25; endpoint["note"] += " ⚠️WRITE"
                except Exception: pass
                return endpoint

            if r.status_code == 405:
                endpoint["type"] = "PROTECTED"; endpoint["note"] = "GET not allowed"
                try:
                    pr = requests.post(url, json={},
                                       headers={**_get_headers(), "Content-Type": "application/json"},
                                       timeout=5, verify=False)
                    if pr.status_code not in (404, 410):
                        endpoint["note"] = f"POST:{pr.status_code}"
                        if pr.status_code == 200:
                            endpoint["method"] = "POST"; body_p = pr.text[:150].strip()
                            if body_p.startswith(("{","[")):
                                endpoint["type"] = "JSON_API"; endpoint["preview"] = body_p
                except Exception: pass
                return endpoint

            if r.status_code in (301, 302, 307, 308):
                loc = r.headers.get("Location", "")
                if loc and "swagger" in loc.lower():
                    endpoint["type"] = "API_DOCS"; endpoint["note"] = f"→ {loc[:60]}"
                    return endpoint

            if r.status_code == 200 and size > 5:
                body = r.text[:3000].strip()

                # Pagination headers
                if any(h in r.headers for h in ("X-Total-Count","X-Total","X-Count")):
                    endpoint["pagination"] = True
                    endpoint["note"] = f"Total: {r.headers.get('X-Total-Count') or r.headers.get('X-Total')}"
                if 'rel="next"' in r.headers.get("Link","") or 'rel=next' in r.headers.get("Link",""):
                    endpoint["pagination"] = True

                # Version
                vm = re.search(r'"(?:version|api_version|apiVersion|build)"\s*:\s*"([0-9][^"]{0,20})"', body)
                if vm: endpoint["version"] = vm.group(1)

                if path.endswith(".map"):
                    endpoint["type"] = "SOURCE_MAP"; endpoint["preview"] = body[:80]
                    endpoint["risk"] += 30; return endpoint

                if "json" in ct or body.startswith(("{","[")):
                    endpoint["type"] = "JSON_API"; endpoint["preview"] = body[:200]
                    # Field extraction
                    try:
                        parsed = json.loads(r.text[:60000])
                        if isinstance(parsed, dict):
                            endpoint["fields"] = list(parsed.keys())[:20]
                            d = parsed.get("data")
                            if isinstance(d, dict):
                                endpoint["fields"] += [f"data.{k}" for k in list(d.keys())[:8]]
                            elif isinstance(d, list) and d and isinstance(d[0], dict):
                                endpoint["fields"] += [f"data[].{k}" for k in list(d[0].keys())[:8]]
                        elif isinstance(parsed, list) and parsed and isinstance(parsed[0], dict):
                            endpoint["fields"] = [f"[].{k}" for k in list(parsed[0].keys())[:15]]
                    except Exception: pass

                    # GraphQL introspection
                    if "/graphql" in url.lower() or ('"data"' in body and '"errors"' in body):
                        endpoint["type"] = "GRAPHQL"; endpoint["risk"] += 20
                        try:
                            intr = requests.post(url, json=_GQL_INTROSPECT,
                                                 headers={**_get_headers(), "Content-Type": "application/json"},
                                                 timeout=10, verify=False)
                            if intr.status_code == 200:
                                gql_info = _parse_gql_schema(intr.json())
                                endpoint["graphql_schema"] = gql_info
                                _GQL_INTEL[url] = gql_info
                                for qname in gql_info.get("queries",[])[:20]:
                                    _OPENAPI_EXTRAS.append({"url":url,"type":"GRAPHQL_QUERY","status":200,
                                        "preview":qname,"risk":10,"note":f"query: {qname}","size_b":0,
                                        "cors":cors or None,"fields":[],"method":"POST"})
                                for mname in gql_info.get("mutations",[])[:10]:
                                    _OPENAPI_EXTRAS.append({"url":url,"type":"GRAPHQL_MUTATION","status":200,
                                        "preview":mname,"risk":35,"note":f"mutation: {mname} ⚠️WRITE",
                                        "size_b":0,"cors":cors or None,"fields":[],"method":"POST"})
                        except Exception as _e: logging.debug("GQL introspect: %s", _e)

                    # OpenAPI / Swagger spec parse
                    elif '"openapi"' in body or '"swagger"' in body:
                        endpoint["type"] = "API_DOCS"; endpoint["preview"] = "OpenAPI/Swagger JSON"
                        endpoint["risk"] += 10
                        try:
                            spec = json.loads(r.text)
                            spec_eps = _parse_openapi(spec, url)
                            _OPENAPI_EXTRAS.extend(spec_eps)
                            endpoint["note"] = f"{len(spec_eps)} paths in spec"
                        except Exception as _e: logging.debug("OpenAPI: %s", _e)
                    else:
                        try:
                            hr = requests.head(url, headers=_get_headers(), timeout=4, verify=False)
                            allow_h = hr.headers.get("Allow","") or hr.headers.get("Access-Control-Allow-Methods","")
                            if allow_h:
                                endpoint["allow_methods"] = allow_h[:80]
                                if any(m in allow_h.upper() for m in ("PUT","PATCH","DELETE")):
                                    endpoint["risk"] += 25; endpoint["allow_methods"] += " ⚠️WRITE"
                        except Exception: pass

                elif "xml" in ct or "rss" in ct or "atom" in ct:
                    endpoint["type"] = "XML/RSS"; endpoint["preview"] = body[:100]
                elif "html" in ct and any(k in url for k in ("/swagger","/redoc","/docs","/api-ui","/api-doc")):
                    endpoint["type"] = "API_DOCS"; endpoint["preview"] = "Swagger/OpenAPI docs"
                    endpoint["risk"] += 10
                    sm = re.search(r"url\s*:\s*[\x22']([^\x22']+\.json)[\x22']", body)
                    if sm:
                        spec_url_found = sm.group(1)
                        if spec_url_found.startswith("/"): spec_url_found = root + spec_url_found
                        endpoint["note"] = f"spec: {spec_url_found}"
                elif url.endswith((".env",".config",".yml",".yaml",".json",".conf",".xml",".bak",".backup",".sql"))                         and size < 200_000:
                    endpoint["type"] = "CONFIG_LEAK"; endpoint["preview"] = body[:200]
                    endpoint["risk"] += 40
                elif size > 20:
                    endpoint["type"] = "OTHER"; endpoint["preview"] = body[:80]
                else:
                    return None
                return endpoint
        except Exception as _e:
            logging.debug("Scan error: %s", _e)
        return None

    # ── Probe paths (profile-ordered) ────────────
    all_probe_paths = list(ordered_paths)
    # Add mined paths (path-only) at the end
    for mined_url in (html_mined + js_mined + robots_found):
        try:
            p = urlparse(mined_url).path
            if p and p not in all_probe_paths and len(p) < 150:
                all_probe_paths.append(p)
        except Exception as _e:
            logging.debug("Scan error: %s", _e)

    # ── Source-map path detection ─────────────────
    # Add .map variants for common JS bundle paths
    _extra_map_paths = []
    for p in all_probe_paths[:]:
        if p.endswith('.js') and len(_extra_map_paths) < 30:
            _extra_map_paths.append(p + '.map')

    # Add .map source file probes
    all_probe_paths.extend(_extra_map_paths)

    total = len(all_probe_paths)
    if progress_cb:
        progress_cb(
            f"🔌 Path scanning: `{total}` paths "
            f"[{profile.profile_name}] ×`{api_workers}` workers..."
        )

    with concurrent.futures.ThreadPoolExecutor(max_workers=api_workers) as ex:
        fmap = {ex.submit(_probe, path): path for path in all_probe_paths}
        done = 0
        try:
            for fut in concurrent.futures.as_completed(fmap, timeout=180):
                done += 1
                try:
                    result = fut.result(timeout=8)
                    if result and result["url"] not in seen:
                        seen.add(result["url"])
                        found.append(result)
                except Exception:
                    pass
                if progress_cb and done % 15 == 0:
                    progress_cb(
                        f"🔌 Scanning: `{done}/{total}`\n"
                        f"✅ JSON: `{sum(1 for e in found if e['type']=='JSON_API')}` | "
                        f"🔒 Protected: `{sum(1 for e in found if e['type']=='PROTECTED')}` | "
                        f"📰 RSS: `{sum(1 for e in found if e['type']=='XML/RSS')}` | "
                        f"📄 Config: `{sum(1 for e in found if e['type']=='CONFIG_LEAK')}` | "
                        f"🗺️ SrcMap: `{sum(1 for e in found if e['type']=='SOURCE_MAP')}`"
                    )
                if probe_delay > 0:
                    time.sleep(probe_delay)
        except concurrent.futures.TimeoutError:
            # Timeout — cancel remaining, return partial results
            for f in fmap:
                f.cancel()
            if progress_cb:
                progress_cb(
                    f"⚠️ Scan timeout — partial results\n"
                    f"✅ Completed: `{done}/{total}` | Found: `{len(found)}`"
                )

    # ── Merge OpenAPI / GraphQL extracted extras ────────────────────────────
    for extra in _OPENAPI_EXTRAS:
        if extra.get("url") and extra.get("url") not in seen:
            seen.add(extra["url"])
            found.append(extra)

    _type_order = {"JSON_API": 0, "GRAPHQL": 1, "GRAPHQL_QUERY": 2, "GRAPHQL_MUTATION": 2,
                   "XML/RSS": 3, "API_DOCS": 4, "CONFIG_LEAK": 5, "SOURCE_MAP": 6,
                   "PROTECTED": 7, "OTHER": 8}
    found.sort(key=lambda x: (_type_order.get(x.get("type",""), 9), -x.get("risk", 0)))

    return {
        "found":       found,
        "js_mined":    list(set(js_mined)),
        "html_mined":  list(set(html_mined)),
        "robots":      robots_found,
        "stats": {
            "total_probed":   total,
            "json_apis":      sum(1 for e in found if e["type"] == "JSON_API"),
            "graphql":        sum(1 for e in found if e["type"] == "GRAPHQL"),
            "xml_rss":        sum(1 for e in found if e["type"] == "XML/RSS"),
            "api_docs":       sum(1 for e in found if e["type"] == "API_DOCS"),
            "config_leaks":   sum(1 for e in found if e["type"] == "CONFIG_LEAK"),
            "source_maps":    sum(1 for e in found if e["type"] == "SOURCE_MAP"),
            "protected":      sum(1 for e in found if e["type"] == "PROTECTED"),
            "other":          sum(1 for e in found if e["type"] == "OTHER"),
            "js_urls_found":  len(js_mined),
            "html_urls_found":len(html_mined),
        }
    }


def _normalize_url(url: str) -> str:
    """Normalize URL: strip trailing slash, lowercase scheme+host, remove fragment."""
    p = urlparse(url)
    path = p.path.rstrip('/') or '/'
    return p._replace(scheme=p.scheme.lower(), netloc=p.netloc.lower(),
                       path=path, fragment='').geturl()


def get_internal_links(html: str, base_url: str, soup=None) -> set:
    """
    v46: Universal Deep Link Discovery
    - Tag-based extraction from <a>, <area>, <base>, <link>, <form>
    - Regex-based path discovery for hidden routes in JS/HTML
    - Handles protocol-relative and deep relative paths
    """
    if soup is None:
        soup = BeautifulSoup(html, _BS_PARSER)
    netloc  = urlparse(base_url).netloc.lower()
    links   = set()
    
    # 1. Standard Tag Discovery
    for tag in soup.find_all(['a', 'area', 'link', 'form'], href=True):
        h = tag.get('href') or tag.get('action', '')
        if h.startswith(('#','mailto:','tel:','javascript:')): continue
        full = urljoin(base_url, h)
        p    = urlparse(full)
        if p.netloc.lower() == netloc:
            links.add(_normalize_url(full))
            
    # 2. Advanced Regex Discovery for hidden routes (v46)
    # Scan for anything that looks like a path: /api/v1/..., /dashboard, etc.
    path_regex = re.compile(r'["\x27`](/[a-zA-Z0-9_\-\./]+)["\x27`]')
    for m in path_regex.finditer(html):
        path = m.group(1)
        if len(path) > 1 and not path.startswith('//'):
            full = urljoin(base_url, path)
            links.add(_normalize_url(full))
            
    return links


