def _get_headers(referer: str = None, bypass_403: bool = False) -> dict:
    """Rotate User-Agent each call with realistic browser headers and optional 403 bypass.
    v42: Added advanced 403 bypass headers and better Sec-CH-UA logic.
    """
    ua = random.choice(_UA_LIST)
    is_mobile = any(x in ua for x in ('Mobile', 'Android', 'iPhone', 'iPad'))
    is_chrome  = 'Chrome/' in ua and 'Chromium' not in ua
    is_firefox = 'Firefox/' in ua and 'Chrome' not in ua
    is_edge    = 'Edg/' in ua
    is_safari  = 'Safari/' in ua and 'Chrome' not in ua and 'Android' not in ua

    hdrs = {
        'User-Agent'               : ua,
        'Accept'                   : 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7',
        'Accept-Language'          : random.choice([
            'en-US,en;q=0.9', 'en-GB,en;q=0.9', 'en-US,en;q=0.8', 'en-US,en;q=0.5'
        ]),
        'Accept-Encoding'          : 'gzip, deflate, br',
        'Connection'               : 'keep-alive',
        'Upgrade-Insecure-Requests': '1',
        'Cache-Control'            : 'max-age=0',
        'DNT'                      : '1',
        'Sec-Fetch-Dest'           : 'document',
        'Sec-Fetch-Mode'           : 'navigate',
        'Sec-Fetch-Site'           : 'none',
        'Sec-Fetch-User'           : '?1',
    }

    if referer:
        hdrs['Referer'] = referer

    if bypass_403:
        # Advanced 403/WAF bypass headers
        bypass_ips = ['127.0.0.1', '::1', 'localhost', '192.168.1.1', '10.0.0.1']
        ip = random.choice(bypass_ips)
        hdrs.update({
            'X-Forwarded-For': ip,
            'X-Originating-IP': ip,
            'X-Remote-IP': ip,
            'X-Remote-Addr': ip,
            'X-Client-IP': ip,
            'X-Real-IP': ip,
            'X-Forwarded-Host': 'localhost',
            'X-Custom-IP-Authorization': ip,
            'Forwarded': f'for={ip};proto=http',
        })

    if is_chrome or is_edge:
        # ✅ Extract ACTUAL version from UA — not hardcoded
        browser_key = 'Edg/' if is_edge else 'Chrome/'
        ver_m   = re.search(r'Chrome/(\d+)', ua)
        ver_int = int(ver_m.group(1)) if ver_m else 120
        ver     = str(ver_int)
        full_m  = re.search(r'Chrome/([\d.]+)', ua)
        full_ver = full_m.group(1) if full_m else f'{ver}.0.0.0'

        if is_edge:
            edge_m = re.search(r'Edg/([\d.]+)', ua)
            edge_ver = edge_m.group(1) if edge_m else full_ver
            ch_ua = (f'"Chromium";v="{ver}", "Microsoft Edge";v="{ver}", '
                     f'"Not.A/Brand";v="99"')
        else:
            ch_ua = (f'"Chromium";v="{ver}", "Google Chrome";v="{ver}", '
                     f'"Not.A/Brand";v="99"')
            full_ver_label = f'"Google Chrome";v="{full_ver}"'

        if 'Windows' in ua:
            platform = '"Windows"'
        elif 'Macintosh' in ua:
            platform = '"macOS"'
        elif 'Android' in ua:
            platform = '"Android"'
        elif 'Linux' in ua:
            platform = '"Linux"'
        else:
            platform = '"Unknown"'

        hdrs.update({
            'Sec-Fetch-Dest'             : 'document',
            'Sec-Fetch-Mode'             : 'navigate',
            'Sec-Fetch-Site'             : 'none',
            'Sec-Fetch-User'             : '?1',
            'Sec-CH-UA'                  : ch_ua,
            'Sec-CH-UA-Mobile'           : '?1' if is_mobile else '?0',
            'Sec-CH-UA-Platform'         : platform,
            'Sec-CH-UA-Full-Version-List': f'"Google Chrome";v="{full_ver}"',
            'Priority'                   : 'u=0, i',
        })

    elif is_firefox:
        # ✅ Firefox does NOT send Sec-CH-UA in real browsers
        hdrs.update({
            'Sec-Fetch-Dest': 'document',
            'Sec-Fetch-Mode': 'navigate',
            'Sec-Fetch-Site': 'none',
            'Sec-Fetch-User': '?1',
        })

    elif is_safari:
        # ✅ Safari does not send Sec-CH-UA either
        hdrs['Accept'] = 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'

    if referer:
        hdrs['Referer'] = referer

    # ── Cloudflare bypass extras (rotate to appear as real browser) ──
    # CF checks: TLS fingerprint, cookie presence, header order, timing
    # These headers help pass CF's JS challenge heuristics passively
    cf_extras = random.choice([
        {
            'Accept-Language': 'en-US,en;q=0.9',
            'Cache-Control':   'no-cache',
            'Pragma':          'no-cache',
        },
        {
            'Accept-Language': 'en-GB,en;q=0.9,en-US;q=0.8',
            'Cache-Control':   'max-age=0',
        },
        {
            'Accept-Language': 'en-US,en;q=0.8,zh-CN;q=0.5',
            'Cache-Control':   'no-store, must-revalidate',
        },
    ])
    hdrs.update(cf_extras)
    # Randomize header value details to avoid fingerprinting
    if random.random() < 0.3:
        hdrs['Accept'] = 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8'
    return hdrs




