def _get_cf_bypass_headers(attempt: int = 0) -> dict:
    """Get CF bypass headers - rotates strategy per attempt."""
    strategy = _CF_BYPASS_SESSIONS[attempt % len(_CF_BYPASS_SESSIONS)]
    return strategy()

def _make_cf_session(attempt: int = 0) -> requests.Session:
    """Create a requests.Session pre-configured for CF bypass."""
    sess = requests.Session()
    hdrs = _get_cf_bypass_headers(attempt)
    sess.headers.update(hdrs)
    # Mount retry adapter
    adapter = HTTPAdapter(max_retries=Retry(total=2, backoff_factor=0.5,
                          status_forcelist=[429, 500, 502, 503, 524]))
    sess.mount('https://', adapter)
    sess.mount('http://', adapter)
    return sess

# ══════════════════════════════════════════════════
# 🔍  SITE PROFILE DETECTOR  — Adaptive download
# ══════════════════════════════════════════════════

_PROFILE_CACHE: dict = {}   # {domain: SiteProfile} — session-level cache (max 100)
_PROFILE_CACHE_MAX = 100

def _profile_cache_set(domain: str, profile) -> None:
    """Insert profile with LRU-style eviction at max capacity."""
    if len(_PROFILE_CACHE) >= _PROFILE_CACHE_MAX:
        # Evict first-inserted (oldest) entry
        oldest = next(iter(_PROFILE_CACHE))
        _PROFILE_CACHE.pop(oldest, None)
    _PROFILE_CACHE[domain] = profile

class SiteProfile:
    """
    Detected characteristics of a target website.
    Used to adapt download behavior for best results.
    """
    __slots__ = (
        'is_cloudflare', 'is_spa', 'is_wordpress', 'is_shopify',
        'is_static', 'has_waf', 'crawl_delay', 'accepts_gzip',
        'server', 'tech_hints',
        # Adaptive settings derived from profile
        'asset_workers', 'page_delay', 'req_delay', 'chunk_size',
        'suggest_js', 'profile_name',
    )

    def __init__(self):
        self.is_cloudflare  = False
        self.is_spa         = False
        self.is_wordpress   = False
        self.is_shopify     = False
        self.is_static      = False
        self.has_waf        = False
        self.crawl_delay    = 0.0
        self.accepts_gzip   = True
        self.server         = ''
        self.tech_hints     = []
        # Defaults (override in _apply_profile_settings)
        self.asset_workers  = 25           # 10 → 25
        self.page_delay     = 0.0
        self.req_delay      = 0.0
        self.chunk_size     = 65536
        self.suggest_js     = False
        self.profile_name   = 'Normal'

    def _apply_profile_settings(self):
        """Set adaptive download parameters based on detected profile."""
        if self.is_cloudflare or self.has_waf:
            self.asset_workers = 6             # 4 → 6
            self.req_delay     = 0.2
            self.page_delay    = 0.3
            self.profile_name  = 'Cloudflare/WAF'
        elif self.is_shopify:
            self.asset_workers = 10            # 6 → 10
            self.req_delay     = 0.15
            self.profile_name  = 'Shopify'
        elif self.is_wordpress:
            self.asset_workers = 15            # 8 → 15
            self.req_delay     = 0.05
            self.profile_name  = 'WordPress'
        elif self.is_spa:
            self.asset_workers = 20            # 12 → 20
            self.req_delay     = 0.0
            self.suggest_js    = True
            self.profile_name  = 'SPA (React/Vue/Next)'
        elif self.is_static:
            self.asset_workers = 30            # 15 → 30
            self.req_delay     = 0.0
            self.profile_name  = 'Static Site'
        else:
            self.asset_workers = 25            # 10 → 25
            self.req_delay     = 0.02
            self.profile_name  = 'Normal'

        # Crawl-delay from robots.txt always respected
        if self.crawl_delay > 0:
            self.page_delay = max(self.page_delay, self.crawl_delay)

    def summary(self) -> str:
        tags = []
        if self.is_cloudflare: tags.append("☁️ CF")
        if self.has_waf:       tags.append("🛡️ WAF")
        if self.is_spa:        tags.append("⚛️ SPA")
        if self.is_wordpress:  tags.append("📝 WP")
        if self.is_shopify:    tags.append("🛍️ Shopify")
        if self.is_static:     tags.append("📄 Static")
        tag_str = " ".join(tags) if tags else "🌐 Normal"
        return (
            f"{tag_str} | Workers: `{self.asset_workers}` | "
            f"Delay: `{self.req_delay:.2f}s`"
        )


def detect_site_profile(url: str) -> SiteProfile:
    """
    Probe a URL once and return a SiteProfile with adaptive settings.
    Results are cached per domain for the session.
    """
    domain = urlparse(url).netloc
    if domain in _PROFILE_CACHE:
        return _PROFILE_CACHE[domain]

    profile = SiteProfile()

    try:
        resp = requests.get(
            url, headers=_get_headers(),
            timeout=12, verify=False,
            allow_redirects=True,
            stream=True
        )
        # Read minimal content for fingerprinting
        buf = io.BytesIO()
        for chunk in resp.iter_content(8192):
            buf.write(chunk)
            if buf.tell() >= 32768:  # 32KB enough for detection
                break
        resp.close()
        body = buf.getvalue().decode('utf-8', 'replace').lower()
        hdrs = {k.lower(): v.lower() for k, v in resp.headers.items()}

        # ── Server / CDN detection ─────────────────
        server = hdrs.get('server', '')
        profile.server = server

        # Cloudflare
        if ('cloudflare' in server or 'cf-ray' in hdrs or
                'cf-cache-status' in hdrs or '__cfduid' in hdrs.get('set-cookie','')):
            profile.is_cloudflare = True

        # Generic WAF signals
        waf_headers = ('x-sucuri-id', 'x-firewall-protection', 'x-waf',
                       'x-defended-by', 'x-shield', 'x-powered-by-akamai')
        if any(h in hdrs for h in waf_headers):
            profile.has_waf = True
        if 'x-sucuri' in str(hdrs):
            profile.has_waf = True

        # ── CMS / Framework detection ──────────────
        # WordPress
        if ('wp-content/' in body or 'wp-includes/' in body or
                'wordpress' in body or '/wp-json/' in body):
            profile.is_wordpress = True

        # Shopify
        if ('cdn.shopify.com' in body or 'shopify.theme' in body or
                'myshopify.com' in hdrs.get('x-shopify-stage','') or
                'shopify' in hdrs.get('x-powered-by','')):
            profile.is_shopify = True

        # SPA frameworks (React / Vue / Next / Nuxt / Angular)
        spa_signals = (
            '__next_data__', '/_next/static/', '__nuxt__', '/_nuxt/',
            '__vue__', 'data-v-', 'ng-version=', '__reactfiber',
            'react-dom.production', 'react.development',
            'window.__initial_state__', 'window.__redux_state__',
        )
        if sum(1 for s in spa_signals if s in body) >= 1:
            profile.is_spa = True

        # Static site (no dynamic signals)
        dynamic_signals = ('php', 'asp', 'jsp', 'django', 'rails', 'laravel',
                           'wp-content', 'powered by')
        if not any(s in body for s in dynamic_signals) and not profile.is_spa:
            profile.is_static = True

        # ── robots.txt crawl-delay ─────────────────
        try:
            parsed   = urlparse(url)
            root     = f"{parsed.scheme}://{parsed.netloc}"
            rb       = requests.get(f"{root}/robots.txt", timeout=5,
                                    headers=_get_headers(), verify=False)
            if rb.status_code == 200:
                for line in rb.text.lower().splitlines():
                    if line.startswith('crawl-delay:'):
                        try:
                            profile.crawl_delay = float(line.split(':', 1)[1].strip())
                        except Exception:
                            pass
                        break
        except Exception as _e:
            logging.debug("Scan error: %s", _e)

    except Exception as e:
        logger.debug("Site profile detection failed: %s", e)

    profile._apply_profile_settings()
    _profile_cache_set(domain, profile)
    logger.info("Site profile [%s]: %s", domain, profile.summary())
    return profile


def _get_page_fingerprint(url: str, timeout: int = 6) -> tuple:
    """
    Get (status_code, body_hash, content_length) for baseline comparison.
    Used to detect catch-all pages.
    """
    try:
        resp = requests.get(url, headers=_get_headers(), timeout=timeout,
                            stream=True, allow_redirects=True, verify=False)
        status = resp.status_code
        chunk  = b''
        for part in resp.iter_content(1024):
            chunk += part
            if len(chunk) >= 1024: break
        resp.close()
        body_hash = hashlib.md5(chunk[:512]).hexdigest()
        ct_length = int(resp.headers.get('Content-Length', len(chunk)))
        return status, body_hash, ct_length, resp.headers.get('Content-Type','')
    except Exception:
        return 0, '', 0, ''


def _detect_catchall(base_url: str) -> tuple:
    """
    Request a random non-existent path — if it returns 200,
    the server has a catch-all (Cloudflare, custom 404 as 200).
    Returns (is_catchall: bool, baseline_hash: str, baseline_len: int)
    """
    rand_path = '/' + ''.join(random.choices(string.ascii_lowercase, k=16)) + '.html'
    status, body_hash, ct_len, ct = _get_page_fingerprint(base_url.rstrip('/') + rand_path)
    if status == 200:
        return True, body_hash, ct_len   # catch-all confirmed
    return False, '', 0


def _is_fake_200_content(body: bytes, ct: str) -> bool:
    if 'html' not in ct.lower():
        return False
    snippet = body[:800].lower()
    return any(s in snippet for s in _FAKE_SIGS)


def _probe_one(
    base_url: str, path: str, label: str, severity: str,
    catchall: bool, baseline_hash: str, baseline_len: int,
    delay: float = 0.0
) -> Optional[dict]:
    """
    Probe one vulnerability path.
    Returns finding dict or None (clean / false positive filtered).

    v36 improvements:
    - Content-Type awareness: HTML response for /api/ path → fake 200 skip
    - Empty body 200 → None (false positive)
    - Catch-all: dynamic length tolerance (5% of baseline, min 100 bytes)
    - 301/302 to login = protected finding (no severity downgrade)
    - Timeout split: (connect=5s, read=8s)
    - Binary content validation for config/git/env endpoints
    """
    import math

    if delay > 0:
        time.sleep(delay)

    full_url = base_url.rstrip('/') + path

    # Config/secret file extensions — expect non-HTML content
    _BINARY_SENSITIVE = frozenset({
        '/.git/config', '/.git/HEAD', '/.env', '/.env.local',
        '/.env.production', '/wp-config.php', '/config.yaml',
        '/config.json', '/appsettings.json',
    })
    _expect_non_html = any(path.startswith(p) or path == p
                           for p in _BINARY_SENSITIVE)

    try:
        resp = requests.get(  # type: ignore[name-defined]
            full_url,
            headers=_get_headers(),  # type: ignore[name-defined]
            timeout=(5, 8),          # (connect, read) — split for accuracy
            stream=True,
            allow_redirects=True,
            verify=False,
        )
        status = resp.status_code
        ct     = resp.headers.get('Content-Type', '').lower()

        if status == 200:
            # Read first 2KB for analysis
            chunk = b''
            for part in resp.iter_content(2048):
                chunk += part
                if len(chunk) >= 2048:
                    break
            resp.close()

            # ── Empty body 200 = false positive ──────────────────
            if not chunk.strip():
                return None

            # ── Content-Type mismatch filter ─────────────────────
            # /api/, /.env, /.git/config, etc. returning HTML = custom 404
            if _expect_non_html and ('text/html' in ct or b'<!DOCTYPE' in chunk[:100]):
                return None
            # API paths returning full HTML = catch-all / 404 masquerading as 200
            if (path.startswith('/api/') and 'text/html' in ct
                    and len(chunk) > 500):
                return None

            # ── Catch-all filter ──────────────────────────────────
            if catchall:
                page_hash = hashlib.md5(chunk[:512]).hexdigest()
                if page_hash == baseline_hash:
                    return None
                if baseline_len > 0:
                    # Dynamic tolerance: 5% of baseline size, min 100 bytes
                    tolerance = max(100, math.ceil(baseline_len * 0.05))
                    page_len  = int(resp.headers.get('Content-Length', len(chunk)))
                    if abs(page_len - baseline_len) < tolerance:
                        return None

            # ── Fake 200 (custom 404) HTML content ───────────────
            try:
                if _is_fake_200_content(chunk, ct):  # type: ignore[name-defined]
                    return None
            except NameError:
                # Fallback: simple heuristic if _is_fake_200_content not available
                lower_chunk = chunk.lower()
                _FAKE_200_MARKERS = (
                    b'page not found', b'404 not found', b'error 404',
                    b'not found</title>', b'the page you were looking for',
                    b'no page found', b'sorry, this page',
                )
                if any(m in lower_chunk for m in _FAKE_200_MARKERS):
                    return None

            size = int(resp.headers.get('Content-Length', len(chunk)))
            return {
                "path": path, "full_url": full_url,
                "label": label, "severity": severity,
                "status": 200, "protected": False, "size": size,
                "content_type": ct.split(';')[0].strip(),
            }

        elif status == 403:
            resp.close()
            # Only report 403 for CRITICAL or HIGH paths
            # (avoids flooding report with every 403)
            if severity not in ("CRITICAL", "HIGH"):
                return None
            cf = ('cloudflare' in resp.headers.get('Server', '').lower()
                  or 'cf-ray' in resp.headers)
            note = " (CF-blocked)" if cf else ""
            return {
                "path": path, "full_url": full_url,
                "label": label + note, "severity": severity,
                "status": 403, "protected": True, "size": 0,
                "content_type": "",
            }

        elif status in (301, 302, 307, 308):
            loc = resp.headers.get('Location', '')
            resp.close()
            # Redirect to login/auth = resource exists but protected
            if any(k in loc.lower() for k in ('login', 'auth', 'signin', 'session')):
                return {
                    "path": path, "full_url": full_url,
                    "label": label + " (→ login redirect)",
                    "severity": severity,   # keep original severity
                    "status": status, "protected": True, "size": 0,
                    "content_type": "",
                }

        else:
            try:
                resp.close()
            except Exception:
                pass

    except Exception as e:
        # Timeouts are normal during scans — debug only, not warning
        err_name = type(e).__name__
        if 'Timeout' not in err_name:
            logger.debug("_probe_one error [%s] %s: %s", status if 'status' in dir() else '?', path, e)

    return None

def _verify_subdomain_real(sub_url: str) -> bool:
    """
    A subdomain is 'real' only if:
    1. DNS resolves OK
    2. HTTP responds (any code)
    3. It has DIFFERENT content than a random path on SAME subdomain
       (i.e. not a Cloudflare/nginx catch-all that mirrors base domain)
    """
    try:
        hostname = urlparse(sub_url).hostname
        socket.gethostbyname(hostname)   # DNS must resolve
    except socket.gaierror:
        return False  # NXDOMAIN = not real

    # Check if it returns anything
    try:
        r = _make_cf_session(0).get(sub_url, timeout=5,
                         allow_redirects=True, verify=False, stream=True)
        r.close()
        code = r.status_code
        if code >= 500:
            return False
    except Exception:
        return False

    # Verify it's NOT a catch-all mirror of the base domain
    is_catchall, _, _ = _detect_catchall(sub_url)
    # Even catch-all subdomains can be real services — just note it
    # We still include them but mark behavior
    return True


def _scan_target_sync(
    target_url: str,
    delay_per_req: float = 0.3,
    vuln_paths: list = None,
    max_workers: int = 5,
) -> tuple:
    """Scan one URL with catch-all detection and delays."""
    if vuln_paths is None:
        vuln_paths = _VULN_PATHS
    exposed   = []
    protected = []

    # Detect catch-all first
    catchall, baseline_hash, baseline_len = _detect_catchall(target_url)

    with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as ex:
        fmap = {
            ex.submit(
                _probe_one, target_url, path, label, sev,
                catchall, baseline_hash, baseline_len,
                delay_per_req * (i % max_workers)
            ): (path, label, sev)
            for i, (path, label, sev) in enumerate(vuln_paths)
        }
        try:
            for fut in concurrent.futures.as_completed(fmap, timeout=120):
                try:
                    f = fut.result(timeout=15)
                    if f:
                        (protected if f["protected"] else exposed).append(f)
                except Exception:
                    pass
        except concurrent.futures.TimeoutError:
            for f in fmap: f.cancel()

    exposed.sort(key=lambda x: _SEV_ORDER.get(x["severity"],9))
    protected.sort(key=lambda x: _SEV_ORDER.get(x["severity"],9))
    return exposed, protected, catchall


def _discover_subdomains_sync(base_url: str, progress_q: list) -> list:
    """
    Discover live subdomains — with real verification (not catch-all mirrors).
    """
    parsed = urlparse(base_url)
    scheme = parsed.scheme
    parts  = parsed.hostname.split('.')
    root   = '.'.join(parts[-2:]) if len(parts) > 2 else parsed.hostname

    progress_q.append(
        f"📡 Subdomain discovery...\n"
        f"Testing `{len(_COMMON_SUBDOMAINS)}` common names on `{root}`"
    )

    live = []

    def check_sub(sub):
        url = f"{scheme}://{sub}.{root}"
        if _verify_subdomain_real(url):
            return url
        return None

    with concurrent.futures.ThreadPoolExecutor(max_workers=10) as ex:
        futures = {ex.submit(check_sub, sub): sub for sub in _COMMON_SUBDOMAINS}
        try:
            for fut in concurrent.futures.as_completed(futures, timeout=60):
                try:
                    result = fut.result(timeout=8)
                    if result:
                        live.append(result)
                except Exception:
                    pass
        except concurrent.futures.TimeoutError:
            for f in futures: f.cancel()

    return live


def _vuln_scan_sync(url: str, progress_q: list) -> dict:
    """
    Main security scan orchestrator.

    v36 improvements:
    - Dedup vuln paths (no duplicate HTTP calls for same path)
    - Case-insensitive security header checking
    - X-Powered-By: version present check before reporting
    - Error rate tracking with warning if > 20% fail
    - Profile-aware adaptive settings preserved
    """
    results = {
        "url": url,
        "findings": [],
        "missing_headers": [],
        "clickjacking": False,
        "https": url.startswith("https://"),
        "server": "Unknown",
        "subdomains_found": [],
        "total_scanned": 0,
        "errors": 0,
        "cloudflare": False,
        "profile": None,
        "error_rate": 0.0,
    }

    # ── SiteProfile ────────────────────────────────────────────────
    domain = urlparse(url).netloc
    try:
        profile = _PROFILE_CACHE.get(domain) or detect_site_profile(url)  # type: ignore[name-defined]
    except Exception:
        profile = None

    results["profile"] = getattr(profile, 'profile_name', 'Unknown')
    is_cloudflare = getattr(profile, 'is_cloudflare', False)
    has_waf       = getattr(profile, 'has_waf', False)
    results["cloudflare"] = is_cloudflare

    # ── Adaptive scan settings ─────────────────────────────────────
    if is_cloudflare or has_waf:
        req_delay, sub_workers, vuln_workers = 0.8, 4, 4
    elif getattr(profile, 'is_shopify', False) or getattr(profile, 'is_wordpress', False):
        req_delay, sub_workers, vuln_workers = 0.4, 7, 6
    else:
        req_delay, sub_workers, vuln_workers = 0.2, 10, 8

    # ── Build profile-specific extra vuln paths ────────────────────
    extra_paths = []
    if getattr(profile, 'is_wordpress', False):
        extra_paths += [
            ("/wp-config.php.bak",       "🔑 wp-config.bak",    "CRITICAL"),
            ("/wp-content/debug.log",     "📋 WP debug.log",     "HIGH"),
            ("/.git/config",              "📁 .git/config",      "CRITICAL"),
            ("/wp-json/wp/v2/users",      "👤 WP users API",     "MEDIUM"),
            ("/wp-content/uploads/",      "📁 WP uploads dir",   "LOW"),
            ("/xmlrpc.php",               "⚠️ xmlrpc.php",      "MEDIUM"),
            ("/.htaccess",                "📄 .htaccess",        "LOW"),
        ]
    if getattr(profile, 'is_shopify', False):
        extra_paths += [
            ("/admin",                    "🔐 Shopify Admin",    "HIGH"),
            ("/products.json",            "📦 Products JSON",    "INFO"),
            ("/collections.json",         "📦 Collections JSON", "INFO"),
            ("/pages.json",               "📄 Pages JSON",       "INFO"),
        ]
    if getattr(profile, 'is_spa', False):
        extra_paths += [
            ("/api/graphql",              "🔌 GraphQL",          "MEDIUM"),
            ("/.env",                     "🔑 .env file",        "CRITICAL"),
            ("/api/v1/users",             "👤 Users API",        "MEDIUM"),
            ("/static/js/main.chunk.js",  "📦 React main bundle","INFO"),
        ]

    # ── Deduplicate paths (path key only, keep first occurrence) ────
    try:
        base_paths = list(_VULN_PATHS)   # type: ignore[name-defined]
    except NameError:
        base_paths = []
    seen_paths = {}
    for entry in base_paths + extra_paths:
        p = entry[0]
        if p not in seen_paths:
            seen_paths[p] = entry
    all_vuln_paths = list(seen_paths.values())

    # ── Baseline headers ───────────────────────────────────────────
    progress_q.append(
        f"🔍 Security headers...\n"
        f"📋 Profile: *{results['profile']}* | "
        f"Workers: `{vuln_workers}` | Delay: `{req_delay}s`"
    )
    try:
        r0   = requests.get(url, timeout=10, headers=_get_headers(),  # type: ignore[name-defined]
                            allow_redirects=True, verify=False)
        hdrs = {k.lower(): v for k, v in r0.headers.items()}   # case-insensitive
        srv  = r0.headers.get('Server', 'Unknown')
        results["server"] = srv[:60]

        try:
            sec_headers = _SEC_HEADERS  # type: ignore[name-defined]
        except NameError:
            sec_headers = {}

        for hdr, (name, sev) in sec_headers.items():
            if hdr.lower() not in hdrs:
                results["missing_headers"].append((name, hdr, sev))

        # Server version disclosure — only if version digits present
        if srv and srv != 'Unknown' and any(c.isdigit() for c in srv):
            results["missing_headers"].append(
                ("Server version leak", f"Server: {srv[:50]}", "LOW"))

        # X-Powered-By — only report if contains version info
        xpb = r0.headers.get('X-Powered-By', '')
        if xpb and any(c.isdigit() for c in xpb):
            results["missing_headers"].append(
                ("Tech version disclosure", f"X-Powered-By: {xpb[:40]}", "LOW"))

        has_xfo = 'x-frame-options' in hdrs
        has_csp = 'content-security-policy' in hdrs
        has_fa  = has_csp and 'frame-ancestors' in hdrs.get(
            'content-security-policy', '')
        results["clickjacking"] = not has_xfo and not has_fa

    except Exception as e:
        logger.warning("Header check error for %s: %s", url, e)
        results["errors"] += 1

    if is_cloudflare:
        progress_q.append(
            "☁️ *Cloudflare detected*\n"
            "Slower scan mode activated..."
        )

    # ── Subdomain discovery ────────────────────────────────────────
    try:
        live_subs = _discover_subdomains_sync(url, progress_q)  # type: ignore[name-defined]
    except Exception as e:
        logger.warning("Subdomain discovery error: %s", e)
        live_subs = []
    results["subdomains_found"] = live_subs

    if live_subs:
        progress_q.append(
            f"✅ *{len(live_subs)} subdomains found:*\n"
            + "\n".join(f"  • `{urlparse(s).netloc}`" for s in live_subs[:8])
        )
    else:
        progress_q.append("📭 No live subdomains found")

    # ── Scan each target ────────────────────────────────────────────
    all_targets = [url] + live_subs
    total_probes = 0
    total_errors = 0

    for i, target in enumerate(all_targets):
        netloc = urlparse(target).netloc
        progress_q.append(
            f"🔍 Scanning `{netloc}`...\n"
            f"Target `{i+1}/{len(all_targets)}` | "
            f"`{len(all_vuln_paths)}` paths"
            + (" ☁️ slow mode" if is_cloudflare else "")
        )
        try:
            exposed, protected, catchall = _scan_target_sync(  # type: ignore[name-defined]
                target, req_delay, all_vuln_paths, vuln_workers
            )
        except Exception as e:
            logger.warning("_scan_target_sync error for %s: %s", target, e)
            exposed, protected, catchall = [], [], False
            total_errors += 1

        total_probes += len(all_vuln_paths)
        if exposed or protected:
            results["findings"].append({
                "target":    target,
                "netloc":    netloc,
                "exposed":   exposed,
                "protected": protected,
                "catchall":  catchall,
            })

    results["total_scanned"] = total_probes
    # Track error rate for report warnings
    if total_probes > 0:
        results["error_rate"] = round(
            (results["errors"] + total_errors) / total_probes, 3
        )

    return results

def _format_vuln_report(r: dict) -> str:
    """
    Format vulnerability scan results as a Telegram Markdown message.

    v36 improvements:
    - Findings grouped by severity (CRITICAL → HIGH → MEDIUM → LOW → INFO)
    - Executive summary table showing counts per severity
    - Remediation hints for actionable findings
    - Content-Type shown per finding (authenticity)
    - Error rate warning if scan quality is degraded
    - Report sections: Summary → HTTPS → Severity Groups → Headers → Notes
    """
    domain = urlparse(r["url"]).netloc
    lines  = []

    # ── Flatten all exposed findings ─────────────────────────────
    all_exposed: list = []
    for f in r.get("findings", []):
        for fi in f.get("exposed", []):
            fi["_netloc"] = f["netloc"]
            all_exposed.append(fi)

    # ── Overall risk ──────────────────────────────────────────────
    all_sevs = [fi["severity"] for fi in all_exposed]

    try:
        sev_order = _SEV_ORDER   # type: ignore[name-defined]
        sev_emoji = _SEV_EMOJI   # type: ignore[name-defined]
    except NameError:
        sev_order = {"CRITICAL": 0, "HIGH": 1, "MEDIUM": 2, "LOW": 3, "INFO": 4}
        sev_emoji = {"CRITICAL": "🔴", "HIGH": "🟠", "MEDIUM": "🟡",
                     "LOW": "🔵", "INFO": "⚪"}

    if "CRITICAL" in all_sevs:
        overall = "🔴 CRITICAL RISK"
    elif "HIGH" in all_sevs:
        overall = "🟠 HIGH RISK"
    elif "MEDIUM" in all_sevs or r.get("clickjacking"):
        overall = "🟡 MEDIUM RISK"
    elif r.get("missing_headers"):
        overall = "🔵 LOW RISK"
    else:
        overall = "✅ CLEAN"

    cf_badge = " ☁️ Cloudflare" if r.get("cloudflare") else ""

    # ── Header ────────────────────────────────────────────────────
    lines += [
        "🛡️ *Vulnerability Scan Report*",
        f"🌐 `{domain}`{cf_badge}",
        f"📊 Risk: *{overall}*",
        f"🔍 Paths: `{r.get('total_scanned', 0)}` | Issues: `{len(all_exposed)}`",
        f"📡 Subdomains: `{len(r.get('subdomains_found', []))}`",
        f"🖥️ Server: `{r.get('server', 'Unknown')}`",
        "",
    ]

    # ── Executive Summary (severity count table) ──────────────────
    from collections import Counter
    sev_counts = Counter(fi["severity"] for fi in all_exposed)
    if sev_counts:
        lines.append("*📊 Finding Summary:*")
        for sev in ["CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"]:
            count = sev_counts.get(sev, 0)
            if count > 0:
                em = sev_emoji.get(sev, "⚪")
                lines.append(f"  {em} `{sev}`: `{count}` finding(s)")
        lines.append("")

    # ── HTTPS ─────────────────────────────────────────────────────
    lines.append("*🔐 HTTPS:*")
    lines.append("  ✅ HTTPS enabled" if r.get("https") else
                 "  🔴 HTTP only — no encryption!")
    lines.append("")

    # ── Subdomains ────────────────────────────────────────────────
    if r.get("subdomains_found"):
        lines.append("*📡 Live Subdomains:*")
        for s in r["subdomains_found"]:
            lines.append(f"  • `{urlparse(s).netloc}`")
        lines.append("")

    # ── Remediation hints per severity ───────────────────────────
    _REMEDIATION_HINTS = {
        "CRITICAL": "🔧 _Immediately restrict access & rotate credentials_",
        "HIGH":     "🔧 _Restrict access via server config or .htaccess_",
        "MEDIUM":   "🔧 _Review exposure and apply access controls_",
        "LOW":      "🔧 _Consider restricting public access_",
        "INFO":     "",
    }

    # ── Findings grouped by severity ─────────────────────────────
    if all_exposed:
        lines.append("*🚨 Findings by Severity:*")
        lines.append("")
        for sev_level in ["CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"]:
            level_findings = [fi for fi in all_exposed if fi["severity"] == sev_level]
            if not level_findings:
                continue
            em = sev_emoji.get(sev_level, "⚪")
            lines.append(f"{em} *{sev_level}* ({len(level_findings)})")
            lines.append("─" * 20)
            for fi in level_findings:
                netloc_note = (f" _(on `{fi['_netloc']}`)"
                               if fi.get("_netloc") and fi["_netloc"] != domain
                               else "")
                ct_note = (f" `[{fi.get('content_type', '')}]`"
                           if fi.get('content_type') else "")
                lines.append(f"  • {fi['label']}{netloc_note}")
                lines.append(f"    🔗 `{fi['full_url']}`")
                lines.append(f"    HTTP `{fi['status']}`{ct_note}")
            # Remediation hint per severity group
            hint = _REMEDIATION_HINTS.get(sev_level, "")
            if hint:
                lines.append(f"  {hint}")
            lines.append("")
    else:
        lines += ["*✅ No exposed files found*", ""]

    # ── Protected (403) findings — compact section ─────────────────
    all_protected = []
    for f in r.get("findings", []):
        for fi in f.get("protected", []):
            fi["_netloc"] = f["netloc"]
            all_protected.append(fi)
    if all_protected:
        lines.append("*⚠️ Blocked Paths (403 / Redirected):*")
        lines.append("_These paths exist but are access-controlled_")
        for fi in all_protected[:8]:
            em = sev_emoji.get(fi.get("severity", "INFO"), "⚪")
            lines.append(f"  {em} {fi['label']}")
            lines.append(f"    🔗 `{fi['full_url']}`")
        if len(all_protected) > 8:
            lines.append(f"  _…and {len(all_protected) - 8} more_")
        lines.append("")

    # ── Clickjacking ──────────────────────────────────────────────
    lines.append("*🖼️ Clickjacking:*")
    if r.get("clickjacking"):
        lines.append("  🟠 Vulnerable — no X-Frame-Options / frame-ancestors CSP")
        lines.append("  🔧 Fix: Add `X-Frame-Options: SAMEORIGIN`")
    else:
        lines.append("  ✅ Protected")
    lines.append("")

    # ── Missing Security Headers ──────────────────────────────────
    if r.get("missing_headers"):
        lines.append("*📋 Security Header Issues:*")
        # Group by severity
        try:
            sev_ord = _SEV_ORDER  # type: ignore[name-defined]
        except NameError:
            sev_ord = {"CRITICAL": 0, "HIGH": 1, "MEDIUM": 2, "LOW": 3, "INFO": 4}
        sorted_hdrs = sorted(
            r["missing_headers"][:12],
            key=lambda x: sev_ord.get(x[2], 9)
        )
        for name, hdr, sev in sorted_hdrs:
            em = sev_emoji.get(sev, "⚪")
            if "leak" in name.lower() or "disclosure" in name.lower():
                lines.append(f"  {em} {name}: `{hdr}`")
            else:
                lines.append(f"  {em} Missing *{name}*")
                lines.append(f"    `{hdr}`")
        lines.append("")

    # ── Cloudflare note ───────────────────────────────────────────
    if r.get("cloudflare"):
        lines += [
            "☁️ *Cloudflare note:*",
            "  Some paths may be hidden behind CF WAF.",
            "  403 results may indicate file exists but CF blocks access.",
            "",
        ]

    # ── Scan quality warning ──────────────────────────────────────
    error_rate = r.get("error_rate", 0.0)
    if error_rate > 0.15:
        lines += [
            f"⚠️ *Scan quality notice:* `{error_rate:.0%}` of probes errored.",
            "  Results may be incomplete. Try again or check network.",
            "",
        ]

    lines += [
        "━━━━━━━━━━━━━━━━━━",
        "⚠️ _Passive scan only — no exploitation_",
    ]
    return "\n".join(lines)


# ══════════════════════════════════════════════════
# 🛡️  SECURITY GUARD — စစ်ဆေးချက် ၃ ခုလုံး တစ်ခါတည်း
#     rate_limit + is_safe_url + url normalise
# ══════════════════════════════════════════════════
async def _security_guard(update, context, heavy: bool = True):
    """
    Command မှန်သမျှ အစပိုင်းမှာ ခေါ်ပါ။
    Returns (ok: bool, url: str|None)
    ok=False ဆိုရင် caller က ချက်ချင်း return လုပ်ပါ။
    """
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=heavy)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return False, None
    if not context.args:
        return False, None
    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    safe, reason = is_safe_url(url)
    if not safe:
        await update.effective_message.reply_text(
            f"❌ *Blocked:* {reason}", parse_mode='Markdown')
        return False, None
    return True, url

async def _scan_guard(update, context, cmd_type: str, cmd_label: str) -> bool:
    """
    Standard guard for all heavy scan commands.
    Checks: force_join → rate_limit → quota → active_scan → global_semaphore
    Returns True if ALL checks pass (caller can proceed).
    Usage:
        if not await _scan_guard(update, context, 'scan', 'Vuln Scan'): return
    """
    if not await check_force_join(update, context): return False
    uid = update.effective_user.id

    # Rate limit
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ *Rate limit:* `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return False

    # Daily quota
    ok, remaining, msg_txt = quota_check(uid, cmd_type)
    if not ok:
        await update.effective_message.reply_text(msg_txt, parse_mode='Markdown')
        return False

    # Active scan check (per-user)
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running\n"
            f"ပြီးဆုံးဖို့ စောင့်ပါ သို့မဟုတ် `/stop` နှိပ်ပါ",
            parse_mode='Markdown')
        return False

    # Global concurrency check (prevent Railway OOM under heavy load)
    if scan_semaphore._value == 0:
        await update.effective_message.reply_text(
            f"⚙️ *System busy* — `{scan_semaphore._value}` scans running globally\n"
            f"1-2 မိနစ်ကြာပြီးနောက် ပြန်ကြိုးစားပါ",
            parse_mode='Markdown')
        return False

    return True


async def _acquire_user_slot(uid: int) -> bool:
    """Acquire per-user scan semaphore. Returns True if acquired."""
    global _user_scan_slots
    if uid not in _user_scan_slots:
        _user_scan_slots[uid] = asyncio.Semaphore(1)
    try:
        return (not _user_scan_slots[uid].locked()) and \
               (await asyncio.wait_for(_user_scan_slots[uid].acquire(), timeout=0.1))
    except (asyncio.TimeoutError, asyncio.CancelledError):
        return False


def _release_user_slot(uid: int):
    """Release per-user scan semaphore."""
    if uid in _user_scan_slots:
        try:
            _user_scan_slots[uid].release()
        except Exception:
            pass


async def cmd_vuln(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/vuln <url> — Passive vuln scanner with CF-aware subdomain discovery."""
    if not context.args:
        await update.effective_message.reply_text(
            "🛡️ *Vulnerability Scanner v4*\n\n"
            "Usage: `/vuln <url>`\n\n"
            "Features:\n"
            "• 📡 Subdomain discovery (DNS verified)\n"
            "• ☁️ Cloudflare detection + slow-mode\n"
            "• 🔍 Catch-all false-positive filter\n"
            "• 🔑 Config / credential leaks\n"
            "• 📁 Git / backup / DB dumps\n"
            "• 🔐 Admin panel detection\n"
            "• 🔗 Full clickable URLs\n\n"
            "_Passive only — no exploitation_",
            parse_mode='Markdown'
        )
        return

    url = context.args[0]
    if not url.startswith('http'):
        url = 'https://' + url

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ *`{_active_scans.get(uid)}` running* — ပြီးဆုံးဖို့ စောင့်ပါ\n"
            "သို့မဟုတ် `/stop` နှိပ်ပါ", parse_mode='Markdown')
        return
    _active_scans.set(uid, "Vuln scan")
    asyncio.ensure_future(db_update(lambda db: track_scan(db, uid, "VulnScan", url if context.args else "")))
    allowed, wait_sec = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏱️ `{wait_sec}` seconds စောင့်ပါ",
            parse_mode='Markdown')
        _active_scans.pop(uid, None)
        return

    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(
            f"🚫 `{reason}`", parse_mode='Markdown')
        _active_scans.pop(uid, None)
        return

    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"🛡️ *Vuln Scan v4*\n🌐 `{domain}`\n\n"
        f"• Baseline & catch-all detection\n"
        f"• Subdomain discovery\n"
        f"• Path scanning\n\n_ခဏစောင့်ပါ..._",
        parse_mode='Markdown'
    )

    progress_q: list = []

    async def _prog_loop():
        while True:
            await asyncio.sleep(3)
            if progress_q:
                txt = progress_q[-1]; progress_q.clear()
                try:
                    await msg.edit_text(
                        f"🛡️ *Scanning `{domain}`*\n\n{txt}",
                        parse_mode='Markdown')
                except Exception: pass

    prog = asyncio.create_task(_prog_loop())
    try:
        scan_task = asyncio.ensure_future(asyncio.to_thread(_vuln_scan_sync, url, progress_q))
        _scan_tasks[uid] = scan_task
        results = await scan_task
    except asyncio.CancelledError:
        prog.cancel()
        _active_scans.pop(uid, None)
        _scan_tasks.pop(uid, None)
        try: await msg.edit_text("🛑 *Vuln scan ရပ်သွားပြီ*", parse_mode='Markdown')
        except Exception: pass
        return
    except Exception as e:
        prog.cancel()
        await msg.edit_text(
            f"❌ Scan error: `{type(e).__name__}: {str(e)[:80]}`",
            parse_mode='Markdown'); return
    finally:
        _active_scans.pop(uid, None)
        _scan_tasks.pop(uid, None)
        prog.cancel()

    report = _format_vuln_report(results)
    try:
        if len(report) <= 4000:
            await msg.edit_text(report, parse_mode='Markdown')
        else:
            await msg.edit_text(report[:4000] + "\n_...continued_", parse_mode='Markdown')
            await update.effective_message.reply_text(report[4000:], parse_mode='Markdown')
    except Exception:
        await update.effective_message.reply_text(report[:4000], parse_mode='Markdown')


