async def cmd_resetquota(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: /resetquota <uid|all> [cmd_type] — Reset daily quota"""
    if update.effective_user.id not in ADMIN_IDS:
        await update.effective_message.reply_text("🚫 Admin only"); return
    args = context.args or []
    if not args:
        await update.effective_message.reply_text(
            "Usage: `/resetquota <uid|all> [cmd_type]`\n"
            "Example: `/resetquota 123456 pentest`\n"
            "Example: `/resetquota all`", parse_mode='Markdown'); return
    target = args[0]
    cmd_type = args[1] if len(args) > 1 else None
    if target == 'all':
        with _daily_quota_lock:
            if cmd_type:
                for uid_k in _daily_quotas:
                    _daily_quotas[uid_k].pop(cmd_type, None)
            else:
                _daily_quotas.clear()
        await update.effective_message.reply_text(
            f"✅ Reset `{'all quotas' if not cmd_type else cmd_type}` for all users")
    else:
        try:
            uid_t = int(target)
            quota_reset_user(uid_t, cmd_type)
            await update.effective_message.reply_text(
                f"✅ Reset `{'all' if not cmd_type else cmd_type}` quota for `{uid_t}`",
                parse_mode='Markdown')
        except ValueError:
            await update.effective_message.reply_text("❌ Invalid user ID")


async def cmd_mystats(update: Update, context: ContextTypes.DEFAULT_TYPE):
    # v50: adds daily quota display
    """/mystats — Detailed personal statistics"""
    uid = update.effective_user.id
    async with db_lock:
        db = _load_db_sync()
        u  = get_user(db, uid, update.effective_user.first_name)
        reset_daily(u)
        _save_db_sync(db)

    lim      = get_limit(db, u)
    dls      = u.get("downloads", [])
