# ────────────────────────────────────────────────
# /dl  —  Download (mode = inline keyboard)
# ────────────────────────────────────────────────

async def cmd_dl(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/dl <url> — Download (mode ကို keyboard နဲ့ ရွေး)
    Replaces: /download /fullsite /jsdownload /jsfullsite
    """
    if not await check_force_join(update, context):
        return

    uid = update.effective_user.id
    
    # ✅ CHECK MEMORY STRESS
    if check_memory_usage():
        await update.effective_message.reply_text(
            "⚠️ *System Busy* — Memory usage high. Please try again in a few minutes.",
            parse_mode='Markdown'
        )
        log_event("memory_stressed", uid, "rejected", {"reason": "high_memory"})
        return
    
    # ✅ CHECK DAILY QUOTA
    quota_ok, remaining, quota_msg = check_user_quota(uid, "download")
    if not quota_ok:
        await update.effective_message.reply_text(quota_msg, parse_mode='Markdown')
        log_event("quota_exceeded", uid, "rejected", {"action": "download"})
        return

    args = context.args or []
    url  = args[0].strip() if args else ""

    # URL မပေးရင် usage ပြ
    if not url:
        await update.effective_message.reply_text(
            "📥 *Advanced Download Command*\n\n"
            "```\n/dl <url> [mode] [options]\n```\n\n"
            "*Modes:*\n"
            "  📄 `single` — Single page (default)\n"
            "  🌐 `full`   — Full site crawl\n"
            "  ⚡ `js`     — Single page + JS render\n"
            "  🚀 `jsful`  — Full site + JS render\n\n"
            "*Options:*\n"
            "  `--depth N`   — Crawl depth (1-10)\n"
            "  `--cookie X`  — Session cookie\n"
            "  `--header X`  — Custom header (`Key: Value`)\n"
            "  `--proxy X`   — Use proxy (e.g. `http://user:pass@host:port`)\n"
            "  `--exclude X` — Exclude paths (comma separated)\n\n"
            "*Examples:*\n"
            "  `/dl https://example.com full --depth 3`\n"
            "  `/dl https://app.com --cookie session=xyz123`\n"
            "  `/dl https://site.com full --exclude /logout,/admin`",
            parse_mode='Markdown'
        )
        return

    if not url.startswith('http'):
        url = 'https://' + url

    # ✅ FIX: SSRF check ကို mode routing မတိုင်ခင် စစ်ပါ
    # (mode arg နဲ့ တိုက်ရိုက် enqueue ခေါ်ရင် is_safe_url ကျော်သွားသော bug ကို fix)
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown')
        return

    # ── V30: Parse flags --cookie, --depth, --header ─────────
    import shlex as _shlex
    _cookies_dl = ""
    _headers_dl = ""
    _depth_dl   = 5
    _proxy_dl   = None
    _exclude_dl = []
    _clean_args = []
    _i = 0
    while _i < len(args):
        a = args[_i]
        if a == '--cookie' and _i + 1 < len(args):
            _cookies_dl = args[_i + 1]; _i += 2
        elif a == '--header' and _i + 1 < len(args):
            _headers_dl = args[_i + 1]; _i += 2
        elif a == '--depth' and _i + 1 < len(args):
            try: _depth_dl = max(1, min(10, int(args[_i+1])))
            except: pass
            _i += 2
        elif a == '--proxy' and _i + 1 < len(args):
            _proxy_dl = args[_i + 1]; _i += 2
        elif a == '--exclude' and _i + 1 < len(args):
            _exclude_dl = [x.strip() for x in args[_i+1].split(',')]; _i += 2
        else:
            _clean_args.append(a); _i += 1
    args = _clean_args

    # Mode ကို arg[1] မှ ဖတ် (optional)
    mode = args[1].lower() if len(args) > 1 else ""

    if mode in ("full", "fullsite"):
        await enqueue_download(update, context, url, full_site=True, use_js=False,
                               cookies=_cookies_dl, extra_headers=_headers_dl, max_depth=_depth_dl)
        return
    elif mode in ("js", "jspage"):
        await enqueue_download(update, context, url, full_site=False, use_js=True,
                               cookies=_cookies_dl, extra_headers=_headers_dl, max_depth=_depth_dl)
        return
    elif mode in ("jsful", "jsfull", "jsfullsite"):
        await enqueue_download(update, context, url, full_site=True, use_js=True,
                               cookies=_cookies_dl, extra_headers=_headers_dl, max_depth=_depth_dl)
        return
    elif mode in ("single", "page", ""):
        # Default single page — still show keyboard for confirmation
        pass

    domain = urlparse(url).hostname

    # ── Pre-fetch site info for smarter mode suggestion ──────
    _spa_hint = ""
    _site_meta = ""
    try:
        async with aiohttp.ClientSession(
                headers=_get_headers(),
                timeout=aiohttp.ClientTimeout(total=6)) as _dl_pre:
            async with _dl_pre.get(url, ssl=False, allow_redirects=True) as _r0r:
                _r0_bytes = await _r0r.read()
                _r0_text  = _r0_bytes.decode('utf-8', errors='replace')
                _r0_hdrs  = dict(_r0r.headers)
        _sz = len(_r0_bytes)
        _sv = _r0_hdrs.get('Server', '') or _r0_hdrs.get('X-Powered-By', '')
        _sc = _r0_text.count('<script')
        _is_spa = _sc > 8 or any(k in _r0_text[:4000] for k in (
            '__NEXT_DATA__', 'window.__NUXT__', 'ReactDOM', 'ng-app', '__vue', 'window.__APP__'))
        _spa_hint = "\n⚡ _SPA/React/Vue detected → JS mode recommended_" if _is_spa else ""
        _site_meta = f"📊 `{_sz//1024}KB` | scripts:`{_sc}` | `{_sv[:18] or 'server unknown'}`"
    except Exception:
        _site_meta = "📊 _(site info unavailable)_"

    # Store url in context for callback
    context.user_data['dl_url'] = url

    kb = InlineKeyboardMarkup([
        [
            InlineKeyboardButton("📄 Single Page",     callback_data="dl_single"),
            InlineKeyboardButton("🌐 Full Site",        callback_data="dl_full"),
        ],
        [
            InlineKeyboardButton("⚡ JS Single",        callback_data="dl_js"),
            InlineKeyboardButton("🚀 JS Full Site",     callback_data="dl_jsful"),
        ],
        [InlineKeyboardButton("❌ Cancel",             callback_data="dl_cancel")],
    ])
    await update.effective_message.reply_text(
        f"📥 *Download Mode ရွေးပါ*\n\n"
        f"🔗 `{url[:60]}`\n"
        f"🌐 `{domain}`\n"
        f"{_site_meta}{_spa_hint}\n\n"
        "📄 *Single* — HTML+CSS+JS တစ်ဖန်းတည်း\n"
        "🌐 *Full Site* — linked pages crawl\n"
        "⚡ *JS Single* — JS render ပြီး source ဆွဲ\n"
        "🚀 *JS Full* — JS render + full crawl\n\n"
        "_SPA/React/Vue ဆိုရင် JS mode သုံးပါ_",
        reply_markup=kb,
        parse_mode='Markdown'
    )


async def dl_mode_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Callback for /dl mode selection keyboard"""
    query = update.callback_query
    await query.answer()
    data  = query.data   # dl_single / dl_full / dl_js / dl_jsful / dl_cancel
    url   = context.user_data.get('dl_url', '')

    if data == "dl_cancel" or not url:
        await query.edit_message_text("❌ Download cancelled.")
        return

    mode_map = {
        "dl_single": (False, False),
        "dl_full":   (True,  False),
        "dl_js":     (False, True),
        "dl_jsful":  (True,  True),
    }
    full_site, use_js = mode_map.get(data, (False, False))
    mode_label = {
        "dl_single": "📄 Single Page",
        "dl_full":   "🌐 Full Site",
        "dl_js":     "⚡ JS Single",
        "dl_jsful":  "🚀 JS Full Site",
    }.get(data, "")

    await query.edit_message_text(
        f"⏳ *{mode_label} Download — Queued*\n🔗 `{url[:60]}`",
        parse_mode='Markdown'
    )
    await enqueue_download(update, context, url, full_site=full_site, use_js=use_js)


