        "/logs/error.log", "/logs/access.log",
        "/debug.log", "/error_log",
        "/phpmyadmin/", "/adminer/",
        "/config/database.yml", "/config/secrets.yml",
        "/application/config/database.php",
        "/bitrix/php_interface/dbconn.php",
