# Global request counter per scan (thread-local style via threading.local)
_scan_req_counter: dict = {}   # {thread_id: count}
_scan_req_lock = threading.Lock()

def _make_session(timeout: int = 10, cf_bypass: bool = False,
                   attempt: int = 0) -> requests.Session:
    """Create a hardened requests session.
    cf_bypass=True: rotate CF bypass header strategies to evade WAF.
    """
    s = requests.Session()
    if cf_bypass:
        s.headers.update(_get_cf_bypass_headers(attempt))
    else:
        s.headers.update(_get_headers())
    s.verify = False
    s.max_redirects = 5
    adapter = requests.adapters.HTTPAdapter(
        max_retries=0,
        pool_connections=4,
        pool_maxsize=8,
    )
    s.mount('http://', adapter)
    s.mount('https://', adapter)
    return s

def _throttled_get(sess: requests.Session, url: str, tid: int, **kwargs) -> requests.Response:
    """Rate-throttled GET — enforces SCAN_REQUEST_DELAY between requests."""
    with _scan_req_lock:
        count = _scan_req_counter.get(tid, 0) + 1
        _scan_req_counter[tid] = count
        if count > MAX_SCAN_REQUESTS:
            raise RuntimeError(f'Max scan requests ({MAX_SCAN_REQUESTS}) reached')
    time.sleep(SCAN_REQUEST_DELAY)
    kwargs.setdefault('timeout', 8)
    return sess.get(url, **kwargs)

def _throttled_post(sess: requests.Session, url: str, tid: int, **kwargs) -> requests.Response:
    """Rate-throttled POST."""
    with _scan_req_lock:
        count = _scan_req_counter.get(tid, 0) + 1
        _scan_req_counter[tid] = count
        if count > MAX_SCAN_REQUESTS:
            raise RuntimeError(f'Max scan requests ({MAX_SCAN_REQUESTS}) reached')
    time.sleep(SCAN_REQUEST_DELAY)
    kwargs.setdefault('timeout', 8)
    return sess.post(url, **kwargs)


def _safe_json(obj):
    """Custom JSON serializer for non-serializable objects."""
    import http.cookiejar
    if isinstance(obj, (set, frozenset)):
        return list(obj)
    if hasattr(obj, '__dict__'):
        return {k: v for k, v in obj.__dict__.items() if not k.startswith('_')}
    if isinstance(obj, bytes):
        return obj.decode('utf-8', errors='replace')
    return str(obj)




def _parse_forms(html_text: str, base_url: str) -> list:
    """Extract all <form> elements with their inputs — real targets for injection."""
    soup  = BeautifulSoup(html_text, "html.parser")
    forms = []
    for form in soup.find_all("form"):
        action = form.get("action", "")
        method = form.get("method", "get").lower()
        if not action:
            action = base_url
        elif not action.startswith("http"):
            action = urljoin(base_url, action)
        inputs = {}
        for inp in form.find_all(["input", "textarea", "select"]):
            name = inp.get("name")
            if not name:
                continue
            itype = inp.get("type", "text").lower()
            val   = inp.get("value", "")
            if itype in ("submit", "button", "image", "reset"):
                inputs[name] = val or "Submit"
            elif itype == "checkbox":
                inputs[name] = "on"
            elif itype == "hidden":
                inputs[name] = val or "1"
            else:
                inputs[name] = val or "test"
        forms.append({"action": action, "method": method, "inputs": inputs})
    return forms


def _get_url_params(url: str) -> dict:
    """Extract query parameters as injection targets."""
    parsed = urlparse(url)
    params = {}
    for k, v in _urlparse.parse_qsl(parsed.query):
        params[k] = v
    return params


def _inject_param(url: str, param: str, payload: str) -> str:
    """Replace one parameter value with payload."""
    parsed = urlparse(url)
    qs = dict(_urlparse.parse_qsl(parsed.query))
    qs[param] = payload
    new_query = _urlparse.urlencode(qs)
    return parsed._replace(query=new_query).geturl()


def _check_reflection(response_text: str, payload: str, min_len: int = 3) -> bool:
    """Check if payload appears unescaped in response."""
    chunk = payload[:min_len] if len(payload) > min_len else payload
    return chunk in response_text


def _is_error_response(text: str) -> bool:
    """Check if response contains SQL/server error messages."""
    patterns = [
        "sql syntax", "mysql_fetch", "you have an error in your sql",
        "ora-0", "pg_query", "sqlstate[", "unclosed quotation",
        "sqlite3.operationalerror", "syntax error", "database error",
        "warning: mysql", "pdoexception", "queryexception",
        "microsoft ole db", "odbc sql server", "jdbc exception",
        "javax.persistence", "invalid query", "unterminated string",
        "quoted string not properly terminated",
    ]
    t = text.lower()
    return any(p in t for p in patterns)


