def _xss_engine_sync(url: str, forms: list, params: dict, progress_cb=None) -> dict:
    """
    Real XSS test:
    1. Probe URL params for reflection
    2. Probe form inputs for reflection
    3. Check response headers (CSP blocking?)
    4. Detect DOM sinks in JS (window.location, document.write, innerHTML)
    """
    result = {
        "vulnerable": False,
        "type":       None,   # reflected|stored|dom
        "param":      None,
        "payload":    None,
        "poc":        None,
        "csp_present":False,
        "evidence":   None,
        "dom_sinks":  [],
        "fix":        [],
    }
    tid  = threading.get_ident()
    with _scan_req_lock: _scan_req_counter[tid] = 0
    sess = _make_cf_session(0)   # CF bypass

    # Check CSP first
    try:
        r0 = _throttled_get(sess, url, tid)
        csp = r0.headers.get("Content-Security-Policy", "")
        result["csp_present"] = bool(csp)
        html_base = r0.text
    except Exception:
        html_base = ""

    # ── DOM sink analysis ────────────────────────────────────────────────────
    dom_sinks = []
    dom_patterns = [
        (r'document\.write\s*\(', "document.write()"),
        (r'\.innerHTML\s*=',      "innerHTML assignment"),
        (r'\.outerHTML\s*=',      "outerHTML assignment"),
        (r'eval\s*\(',            "eval()"),
        (r'setTimeout\s*\(',      "setTimeout() with string"),
        (r'location\.href\s*=',   "location.href assignment"),
        (r'location\s*=',         "location assignment"),
        (r'\$\(.+\)\.html\s*\(',  "jQuery .html()"),
    ]
    for pattern, label in dom_patterns:
        if re.search(pattern, html_base, re.I):
            dom_sinks.append(label)
    result["dom_sinks"] = dom_sinks

    # ── Reflection probing ───────────────────────────────────────────────────
    targets = []
    for p in params:
        targets.append(("GET", p, url, None))
    for form in forms:
        for p, v in form["inputs"].items():
            if v in ("Submit", "on"):
                continue
            targets.append((form["method"].upper(), p, form["action"], form))

    if not targets and params == {}:
        # Try appending a dummy param
        sep = "&" if "?" in url else "?"
        targets.append(("GET", "q", url + sep + "q=test", None))

    if progress_cb:
        progress_cb(f"🕷️ XSS: {len(targets)} targets × {len(_XSS_PROBES)} probes")

    for method, param, target_url, form in targets:
        for payload, desc in _XSS_PROBES:
            try:
                if method == "GET":
                    test_url = _inject_param(target_url, param, payload)
                    r = _throttled_get(sess, test_url, tid, allow_redirects=True)
                    body = r.text
                else:
                    data = dict(form["inputs"])
                    data[param] = payload
                    r = sess.post(target_url, data=data, timeout=8, allow_redirects=True)
                    body = r.text
                    test_url = target_url

                # Check if payload reflects unescaped
                if payload in body:
                    # Confirm it's in HTML context (not just in JS string escaped)
                    escaped = _html.escape(payload)
                    if escaped not in body or payload in body.replace(escaped, ""):
                        poc = (f"curl -s '{test_url}' | grep -i 'alert'"
                               if method == "GET"
                               else f"curl -s -X POST '{target_url}' -d '{param}={_urlparse.quote(payload)}'")
                        # Extract surrounding context
                        idx = body.find(payload[:10])
                        ctx = body[max(0, idx-50):idx+len(payload)+50] if idx >= 0 else payload
                        result.update({
                            "vulnerable": True,
                            "type":       "reflected",
                            "param":      param,
                            "payload":    payload,
                            "desc":       desc,
                            "poc":        poc,
                            "evidence":   ctx[:300],
                        })
                        return result

                # Passive marker reflection (for XSSMARK9991)
                if "XSSMARK9991" in payload and "XSSMARK9991" in body:
                    result.update({
                        "vulnerable": True,
                        "type":       "reflected-passive",
                        "param":      param,
                        "payload":    payload,
                        "desc":       "User input reflected unescaped",
                        "poc":        f"Param '{param}' reflects any input — XSS likely",
                        "evidence":   f"Input 'XSSMARK9991' appears in response body",
                    })
                    return result

            except Exception:
                continue

    # ✅ v51 FIX: fix list ကို vulnerable ဖြစ်မှသာ assign
    if result.get("vulnerable"):
        result["fix"] = [
            "Output encode ALL user data: `htmlspecialchars($v, ENT_QUOTES, 'UTF-8')` (PHP)",
            "Jinja2/Django templates auto-escape — never use `| safe` on user input",
            "React: never use `dangerouslySetInnerHTML` with user data",
            "Add Content-Security-Policy header: `default-src 'self'; script-src 'self'`",
            "HttpOnly + Secure cookie flags (prevent cookie theft even if XSS occurs)",
            "Use DOMPurify to sanitize any HTML you must render: `DOMPurify.sanitize(input)`",
        ]
    return result


