def _severity_emoji(has_vuln: bool, kind: str = "") -> str:
    if not has_vuln:
        return "✅"
    critical_kinds = {"sqli", "lfi", "ssrf"}
    return "🔴" if kind in critical_kinds else "🟠"


def _format_pentest_report(domain: str, sqli: dict, xss: dict, ssrf: dict,
                            lfi: dict, auth: dict) -> list:
    """Format combined pentest results as Telegram Markdown lines."""
    lines = [
        f"⚔️ *Pentest Report — `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        "",
    ]
    sev = {"sqli": "🔴 CRITICAL", "lfi": "🔴 CRITICAL", "ssrf": "🔴 CRITICAL",
           "xss": "🟠 HIGH", "auth": "🟠 HIGH"}

    # SQLi
    if sqli.get("vulnerable"):
        lines += [f"  {sev['sqli']} *SQL Injection*",
                  f"    Param: `{sqli.get('param')}` | DB: `{sqli.get('db_type','?')}`",
                  f"    Type: `{sqli.get('type','?')}` | Evidence: `{str(sqli.get('evidence',''))[:80]}`", ""]
    else:
        lines.append("  ✅ SQL Injection — Not found")

    # XSS
    if xss.get("vulnerable"):
        lines += [f"  {sev['xss']} *Cross-Site Scripting (XSS)*",
                  f"    Param: `{xss.get('param')}` | PoC: `{str(xss.get('poc',''))[:80]}`", ""]
    else:
        lines.append("  ✅ XSS — Not found")

    # SSRF
    if ssrf.get("ssrf_found") or ssrf.get("redirect_found"):
        lines += [f"  {sev['ssrf']} *SSRF / Open Redirect*",
                  f"    SSRF param: `{ssrf.get('ssrf_param','?')}` | Redirect: `{ssrf.get('redirect_found',False)}`", ""]
    else:
        lines.append("  ✅ SSRF / Open Redirect — Not found")

    # LFI
    if lfi.get("vulnerable"):
        lines += [f"  {sev['lfi']} *Local File Inclusion (LFI)*",
                  f"    Param: `{lfi.get('param')}` | Target: `{lfi.get('target','?')}`", ""]
    else:
        lines.append("  ✅ LFI — Not found")

    # Auth
    auth_issues = []
    if auth.get("default_creds"):  auth_issues.append(f"Default creds: `{auth.get('poc_cred','?')}`")
    if auth.get("no_rate_limit"):  auth_issues.append("No rate limiting on login")
    if auth.get("csrf_missing"):   auth_issues.append("CSRF token missing")
    if auth.get("weak_session"):   auth_issues.append(f"Weak cookies: `{', '.join(auth['weak_session'][:2])}`")
    if auth_issues:
        lines += [f"  {sev['auth']} *Auth Weaknesses*"] + [f"    • {i}" for i in auth_issues] + [""]
    else:
        lines.append("  ✅ Auth — No critical issues")

    lines += ["", "⚠️ _Passive + limited active probes only — no exploitation._"]
    return lines


async def _prescan(url: str) -> tuple:
    """Returns (html, forms, params) — reused by all engines.
    Tries CF bypass strategies if initial request returns 403/503.
    """
    def _fetch():
        # Try up to 4 CF bypass strategies
        for attempt in range(4):
            try:
                sess = _make_session(12, cf_bypass=(attempt > 0), attempt=attempt)
                r = sess.get(url, timeout=12, allow_redirects=True)
                if r.status_code not in (403, 503, 429) or attempt == 3:
                    return r.text, r.url
                import time as _t; _t.sleep(0.4 * (attempt + 1))
            except Exception:
                if attempt == 3:
                    return "", url
        return "", url

    html, final_url = await asyncio.to_thread(_fetch)
    forms  = _parse_forms(html, final_url)
    params = _get_url_params(final_url)
    return html, forms, params


