async def cmd_pentest(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/pentest <url> — Full offensive pentest: SQLi + XSS + SSRF + LFI + Auth"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return
    # Pentest-specific rate limit (stricter than normal heavy)
    ok, reason = check_pentest_rate(uid)
    if not ok:
        await update.effective_message.reply_text(reason, parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running — `/stop` နှိပ်ပါ",
            parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "⚔️ *Full Pentest*\n\n"
            "📌 *Usage:* `/pentest https://yoursite.com`\n\n"
            "*Tests (real probes, real PoC):*\n"
            "  💉 SQL Injection (error + blind time-based)\n"
            "  🕷️ XSS (reflected, DOM sink analysis)\n"
            "  🔁 SSRF + Open Redirect\n"
            "  📁 LFI / Path Traversal\n"
            "  🔐 Auth weaknesses (default creds, rate limit, cookies)\n\n"
            "📊 Security grade A–F + fix guide per finding\n\n"
            "⚠️ _ကိုယ်ပိုင် site တွင်သာ သုံးပါ_",
            parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith("http"): url = "https://" + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(
            f"❌ *Blocked:* `{reason}`", parse_mode='Markdown'); return

    domain = urlparse(url).netloc
    _active_scans.set(uid, "Pentest")
    asyncio.ensure_future(db_update(lambda db: track_scan(db, uid, "Pentest", url if context.args else "")))

    msg = await update.effective_message.reply_text(
        f"⚔️ *Full Pentest — `{domain}`*\n\n"
        "⏳ Phase 1/6: Fetching page + extracting forms...",
        parse_mode='Markdown')

    cancel_evt = asyncio.Event()

    async def _edit(text: str):
        try:
            if not cancel_evt.is_set():
                await msg.edit_text(text, parse_mode='Markdown')
        except Exception:
            pass

    try:
        # Pre-scan
        html, forms, params = await _prescan(url)
        await _edit(
            f"⚔️ *Full Pentest — `{domain}`*\n\n"
            f"✅ Page fetched | Forms: `{len(forms)}` | Params: `{len(params)}`\n"
            "⏳ Phase 2/6: SQL Injection..."
        )

        progress_log = []
        def _prog(msg_str):
            progress_log.append(msg_str)

        ENGINE_TIMEOUT = 90   # seconds per engine

        # ── Each engine isolated: timeout + individual exception handling ──
        def _empty_sqli(): return {"vulnerable":False,"type":None,"db_type":None,
            "param":None,"payload":None,"poc":None,"columns":None,"evidence":None,"fix":[]}
        def _empty_xss():  return {"vulnerable":False,"type":None,"param":None,
            "payload":None,"poc":None,"csp_present":False,"evidence":None,"dom_sinks":[],"fix":[]}
        def _empty_ssrf(): return {"ssrf_found":False,"redirect_found":False,
            "ssrf_param":None,"ssrf_payload":None,"ssrf_evidence":None,
            "redirect_param":None,"redirect_payload":None,"fix":[]}
        def _empty_lfi():  return {"vulnerable":False,"param":None,"payload":None,
            "target":None,"evidence":None,"fix":[]}
        def _empty_auth(): return {"default_creds":False,"no_rate_limit":False,
            "weak_session":[],"csrf_missing":False,"jwt_in_response":False,
            "login_form":None,"poc_cred":None,"fix":[]}

        async def _run_engine(name, fn, empty_fn, phase, status_line):
            await _edit(f"⚔️ *Full Pentest — `{domain}`*\n\n{status_line}\n⏳ {phase}...")
            try:
                return await asyncio.wait_for(
                    asyncio.to_thread(fn), timeout=ENGINE_TIMEOUT)
            except asyncio.TimeoutError:
                _prog(f"⚠️ {name} timed out after {ENGINE_TIMEOUT}s")
                logger.warning("Pentest engine %s timed out uid=%d", name, uid)
                r = empty_fn()
                r["timeout"] = True
                return r
            except Exception as e:
                _prog(f"❌ {name} error: {e}")
                logger.error("Pentest engine %s error: %s", name, e)
                return empty_fn()

        sqli = await _run_engine("SQLi", 
            lambda: _sqli_engine_sync(url, forms, params, _prog), _empty_sqli,
            "Phase 2/6: SQL Injection", "")
        xss = await _run_engine("XSS",
            lambda: _xss_engine_sync(url, forms, params, _prog), _empty_xss,
            "Phase 3/6: XSS",
            f"{'🔴 SQLi' if sqli.get('vulnerable') else '✅ SQLi'}")
        ssrf = await _run_engine("SSRF",
            lambda: _ssrf_engine_sync(url, params, forms, _prog), _empty_ssrf,
            "Phase 4/6: SSRF + Open Redirect",
            f"{'🔴 SQLi' if sqli.get('vulnerable') else '✅ SQLi'} | "
            f"{'🔴 XSS' if xss.get('vulnerable') else '✅ XSS'}")
        lfi = await _run_engine("LFI",
            lambda: _lfi_engine_sync(url, params, _prog), _empty_lfi,
            "Phase 5/6: LFI / Path Traversal",
            f"{'🔴 SQLi' if sqli.get('vulnerable') else '✅ SQLi'} | "
            f"{'🔴 XSS' if xss.get('vulnerable') else '✅ XSS'} | "
            f"{'🔴 SSRF' if ssrf.get('ssrf_found') else '✅ SSRF'}")
        auth = await _run_engine("Auth",
            lambda: _auth_engine_sync(url, forms, _prog), _empty_auth,
            "Phase 6/6: Auth Weaknesses", "⏳ Almost done...")
        await _edit(f"⚔️ *Full Pentest — `{domain}`*\n\n📊 Generating report...")

        # Format and send
        parts = _format_pentest_report(domain, sqli, xss, ssrf, lfi, auth)
        await safe_edit(msg, parts[0], parse_mode='Markdown')
        for part in parts[1:]:
            if part.strip():
                await update.effective_message.reply_text(part, parse_mode='Markdown')

        # JSON export
        try:
            export = {
                "domain": domain, "url": url,
                "sqli": sqli, "xss": xss, "ssrf": ssrf, "lfi": lfi, "auth": auth,
                "timestamp": datetime.now().isoformat(),
            }
            buf = io.BytesIO(json.dumps(export, indent=2, ensure_ascii=False, default=_safe_json).encode())
            ts  = datetime.now().strftime("%Y%m%d_%H%M%S")
            await context.bot.send_document(
                chat_id=update.effective_chat.id,
                document=buf,
                filename=f"pentest_{domain}_{ts}.json",
                caption=f"⚔️ Pentest: `{domain}`")
        except Exception as _e:
            logger.debug("pentest export: %s", _e)

    except Exception as e:
        logger.error("pentest error: %s", e, exc_info=True)
        await msg.edit_text(f"❌ *Pentest Failed:* `{str(e)[:120]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


# ─────────────────────────────────────────────────────────────────────────────
# Standalone sub-commands  (each engine individually)
# ─────────────────────────────────────────────────────────────────────────────

async def _run_single_engine(update, context, engine_name: str, engine_fn,
                              label: str, emoji: str):
    """Generic wrapper for single-engine standalone commands."""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            f"📌 *Usage:* `/{engine_name} <url>`", parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith("http"): url = "https://" + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(
            f"❌ *Blocked:* `{reason}`", parse_mode='Markdown'); return

    domain = urlparse(url).netloc
    _active_scans.set(uid, engine_name)
    msg = await update.effective_message.reply_text(
        f"{emoji} *{label} — `{domain}`*\n\n⏳ Scanning...", parse_mode='Markdown')

    try:
        html, forms, params = await _prescan(url)
        prog = []
        result = await asyncio.to_thread(engine_fn, url, forms, params, prog.append)
        # Track scan in user history
        try:
            async with db_lock:
                _db = _load_db_sync()
                track_scan(_db, uid, engine_name, url)
                _save_db_sync(_db)
        except Exception:
            pass

        vuln_key = ("vulnerable" if "vulnerable" in result
                    else "ssrf_found" if "ssrf_found" in result else "vulnerable")
        is_vuln  = result.get(vuln_key, False) or result.get("ssrf_found", False) \
                   or result.get("redirect_found", False)

        lines = [f"{emoji} *{label} — `{domain}`*", ""]
        if is_vuln:
            lines.append(f"🔴 *VULNERABLE*\n")
            for k, v in result.items():
                if k in ("fix", "dom_sinks") or v is None or v is False or v == []:
                    continue
                if isinstance(v, bool):
                    lines.append(f"  {k}: `{v}`")
                elif isinstance(v, str) and len(v) < 200:
                    lines.append(f"  {k}: `{v}`")
                elif isinstance(v, list):
                    lines.append(f"  {k}: `{', '.join(str(i) for i in v[:3])}`")
        else:
            lines.append("✅ *No vulnerability found*")

        # ✅ FIX v51: HOW TO FIX section ကိ vulnerability ကေ့က်မှသာပှာပှသည်
        if is_vuln:
            fix = result.get("fix", [])
            if fix:
                lines += ["", "*🔧 HOW TO FIX:*"]
                for f in fix:
                    lines.append(f"  • {f}")

        text = "\n".join(lines)
        if len(text) > 4000:
            text = text[:4000] + "\n_...truncated_"
        await msg.edit_text(text, parse_mode='Markdown')

    except Exception as e:
        logger.error("%s error: %s", engine_name, e, exc_info=True)
        await msg.edit_text(f"❌ *{label} Failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


