# ─────────────────────────────────────────────────────────────────────────────
# 🗺️  /fixall <url> — Priority fix roadmap
# ─────────────────────────────────────────────────────────────────────────────

async def cmd_fixall(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/fixall <url> — Run all checks, output prioritized fix roadmap for developers"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/fixall https://yoursite.com`\n\n"
            "🗺️ Runs all attack tests then outputs a *prioritized fix roadmap*\n"
            "for your development team.",
            parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith("http"): url = "https://" + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(
            f"❌ *Blocked:* `{reason}`", parse_mode='Markdown'); return

    domain = urlparse(url).netloc
    _active_scans.set(uid, "FixAll")
    msg = await update.effective_message.reply_text(
        f"🗺️ *Fix Roadmap — `{domain}`*\n\n⏳ Running all checks...",
        parse_mode='Markdown')

    try:
        html, forms, params = await _prescan(url)
        prog = []

        await msg.edit_text(
            f"🗺️ *Fix Roadmap — `{domain}`*\n\n⏳ Running SQLi + XSS + SSRF + LFI + Auth...",
            parse_mode='Markdown')

        sqli = await asyncio.to_thread(_sqli_engine_sync, url, forms, params, prog.append)
        xss  = await asyncio.to_thread(_xss_engine_sync,  url, forms, params, prog.append)
        ssrf = await asyncio.to_thread(_ssrf_engine_sync, url, params, forms, prog.append)
        lfi  = await asyncio.to_thread(_lfi_engine_sync,  url, params, prog.append)
        auth = await asyncio.to_thread(_auth_engine_sync, url, forms, prog.append)

        # Build prioritized fix list
        issues = []
        if sqli.get("vulnerable"):
            issues.append(("🔴 CRITICAL", "SQL Injection", sqli.get("fix", []),
                           f"Param: `{sqli.get('param')}` | DB: `{sqli.get('db_type')}`"))
        if lfi.get("vulnerable"):
            issues.append(("🔴 CRITICAL", "Local File Inclusion", lfi.get("fix", []),
                           f"Param: `{lfi.get('param')}` | Target: `{lfi.get('target')}`"))
        if ssrf.get("ssrf_found"):
            # SSRF fix = first 3 items, Open Redirect fix = last 3
            ssrf_fix = ssrf.get("fix", [])[:3]
            issues.append(("🔴 CRITICAL", "SSRF", ssrf_fix,
                           f"Param: `{ssrf.get('ssrf_param')}`"))
        if auth.get("default_creds"):
            issues.append(("🔴 CRITICAL", "Default Credentials",
                           [auth.get("fix", [""])[0], auth.get("fix", ["",""])[1]],
                           f"Creds: `{auth.get('poc_cred')}`"))
        if xss.get("vulnerable"):
            issues.append(("🟠 HIGH", "Cross-Site Scripting (XSS)", xss.get("fix", []),
                           f"Param: `{xss.get('param')}`"))
        if ssrf.get("redirect_found"):
            redir_fix = ssrf.get("fix", [])[3:]  # deduplicated: use different slice
            if not redir_fix: redir_fix = ["Use allowlist for redirect destinations",
                                            "Reject absolute URLs in redirect params"]
            issues.append(("🟠 HIGH", "Open Redirect", redir_fix,
                           f"Param: `{ssrf.get('redirect_param')}`"))
        if auth.get("no_rate_limit"):
            issues.append(("🟠 HIGH", "No Rate Limiting on Login", auth.get("fix", []), ""))
        if auth.get("csrf_missing"):
            issues.append(("🟠 HIGH", "CSRF Token Missing", auth.get("fix", []), ""))
        if auth.get("weak_session"):
            issues.append(("🟡 MEDIUM", "Weak Cookie Security", auth.get("fix", []),
                           f"{len(auth['weak_session'])} cookies affected"))

        lines = [
            "🗺️ *Developer Fix Roadmap*",
            f"🌐 `{domain}`",
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            "",
            f"Total issues: `{len(issues)}`",
            "",
        ]

        timeline = {
            "🔴 CRITICAL": "🚨 Fix within 24 hours",
            "🟠 HIGH":     "⚡ Fix within 1 week",
            "🟡 MEDIUM":   "📅 Fix within 1 month",
        }

        if not issues:
            lines += [
                "✅ *No vulnerabilities found!*",
                "",
                "_Website passed all pentest probes._",
                "Continue monitoring with `/devaudit` and `/secretscan`",
            ]
        else:
            for i, (sev, name, fixes, detail) in enumerate(issues, 1):
                tl = timeline.get(sev, "")
                lines += [
                    f"*{i}. {sev} — {name}*",
                    f"   {tl}",
                ]
                if detail:
                    lines.append(f"   {detail}")
                lines.append("")
                lines.append("   *Fix steps:*")
                for fix in fixes[:3]:
                    lines.append(f"   ✅ {fix}")
                lines.append("")

        lines += [
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            "*📋 After fixing:*",
            "  1. Run `/pentest` again to verify",
            "  2. Run `/devaudit` for headers/SSL",
            "  3. Run `/hardening` for server config",
            "",
            "⚠️ _Authorized testing only_",
        ]

        text = "\n".join(lines)
        if len(text) <= 4000:
            await msg.edit_text(text, parse_mode='Markdown')
        else:
            await msg.edit_text(text[:4000] + "\n_...continued below_", parse_mode='Markdown')
            await update.effective_message.reply_text(text[4000:8000], parse_mode='Markdown')

    except Exception as e:
        logger.error("fixall error: %s", e, exc_info=True)
        await msg.edit_text(f"❌ *Failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


