async def cmd_api(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /api <url> — v46 Ultra Admin & API Finder
    - Scans for admin panels, login pages, hidden dashboards, and API endpoints
    - Multi-threaded deep scanning (32 parallel workers)
    """
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return
        
    # v46: Performance Boost for API Scanner
    # Force high-concurrency for this specific scan
    _SCAN_WORKERS = 32

    if not context.args:
        await update.effective_message.reply_text(
            "🚀 *Admin Panel Finder*\n\n"
            "📌 *Usage:* `/api https://example.com`\n\n"
            "ရှာဖွေမည့်နေရာများ:\n"
            "  • Admin panels & Login pages\n"
            "  • Dashboards & Control panels\n"
            "  • DB management (phpMyAdmin, etc)\n"
            "  • Config files & API endpoints\n\n"
            "⚠️ _Authorized testing only_",
            parse_mode='Markdown'
        )
        return

    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown')
        return

    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ *`{_active_scans.get(uid)}` running* — `/stop` နှိပ်ပါ", parse_mode='Markdown')
        return
    _active_scans.set(uid, "Admin Finder")
    asyncio.ensure_future(db_update(lambda db: track_scan(db, uid, "AdminFinder", url if context.args else "")))

    domain = urlparse(url).hostname
    base_url = f"{urlparse(url).scheme}://{domain}"
    msg = await update.effective_message.reply_text(
        f"🚀 *Admin Finder — `{domain}`*\n\n⏳ Scanning `{len(_ADMIN_PATHS)}` paths...",
        parse_mode='Markdown')

    results = []
    progress_idx = [0]
    total = len(_ADMIN_PATHS)

    # v42: False Positive detection by comparing with a non-existent path
    fake_content_hash = None
    try:
        async with aiohttp.ClientSession(headers=_get_headers()) as sess:
            async with sess.get(f"{base_url}/non_existent_path_{random.randint(1000,9999)}", timeout=10) as r:
                fake_content = await r.text()
                fake_content_hash = hashlib.md5(fake_content.encode()).hexdigest()
    except: pass

    async def _scan_path(session, path):
        full_url = base_url.rstrip('/') + path
        # v42: Try with normal headers first, then with bypass headers if 403
        try:
            async with session.get(full_url, timeout=10, allow_redirects=False) as r:
                status = r.status
                if status == 403:
                    # Try bypass
                    async with session.get(full_url, timeout=10, headers=_get_headers(bypass_403=True), allow_redirects=False) as r2:
                        if r2.status != 403:
                            status = r2.status
                
                progress_idx[0] += 1
                if status in [200, 301, 302, 401]:
                    if status == 200 and fake_content_hash:
                        # Check for false positive
                        curr_content = await r.text()
                        if hashlib.md5(curr_content.encode()).hexdigest() == fake_content_hash:
                            return None
                    return {'url': full_url, 'status': status}
        except:
            progress_idx[0] += 1
        return None

    async def _prog_updater():
        while progress_idx[0] < total:
            await asyncio.sleep(3)
            perc = (progress_idx[0] / total) * 100
            try:
                await msg.edit_text(
                    f"🚀 *Admin Finder — `{domain}`*\n\n"
                    f"⏳ Progress: `{perc:.1f}%` ({progress_idx[0]}/{total})\n"
                    f"✅ Found: `{len(results)}`",
                    parse_mode='Markdown'
                )
            except: pass

    updater = asyncio.create_task(_prog_updater())

    try:
        # v41: optimized connector for heavy parallel scanning
        conn = aiohttp.TCPConnector(ssl=False, limit=50, ttl_dns_cache=300)
        async with aiohttp.ClientSession(headers=_get_headers(), connector=conn) as session:
            # Batch processing to avoid overwhelming
            batch_size = 25  # increased batch size for v41 performance
            for i in range(0, total, batch_size):
                batch = _ADMIN_PATHS[i:i+batch_size]
                tasks = [_scan_path(session, p) for p in batch]
                batch_results = await asyncio.gather(*tasks)
                results.extend([r for r in batch_results if r])
                if uid in _cancel_flags and _cancel_flags.get(uid).is_set():
                    break
    finally:
        updater.cancel()
        _active_scans.pop(uid, None)

    if not results:
        await msg.edit_text(f"🚀 *Admin Finder — `{domain}`*\n\n❌ Admin panel တစ်ခုမှ မတွေ့ပါ", parse_mode='Markdown')
        return

    lines = [
        f"🚀 *Admin Finder — `{domain}`*\n",
        "━━━━━━━━━━━━━━━━━━━━",
        "| Status | URL |",
        "| :--- | :--- |"
    ]
    # Sort results by status
    results.sort(key=lambda x: x['status'])
    
    for r in results:
        status = r['status']
        icon = "✅" if status == 200 else "🔗" if status in [301, 302] else "🔒"
        # Truncate long URLs for table
        u = r['url']
        if len(u) > 40: u = u[:37] + "..."
        lines.append(f"| {icon} `{status}` | [{u}]({r['url']}) |")

    final_text = "\n".join(lines)
    if len(final_text) > 4000: final_text = final_text[:4000] + "\n..."
    await msg.edit_text(final_text, parse_mode='Markdown', disable_web_page_preview=True)


