async def cmd_report_export(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/report_export <url> — Generate professional pentest report (Markdown + JSON)"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running — `/stop` နှိပ်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/report_export https://example.com`\n\n"
            "📄 *Professional Pentest Report Generator*\n\n"
            "Runs all scan modules then exports:\n"
            "  • `report.md` — Markdown (OWASP Top 10 format)\n"
            "  • `report.json` — Machine-readable findings\n"
            "  • `executive_summary.txt` — Non-technical summary\n\n"
            "⏱️ Estimated time: 3–5 minutes\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown'); return
    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown'); return
    _active_scans.set(uid, "Report Export")
    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"📄 *Report Export — `{domain}`*\n\n⏳ Running all scans...\n_This takes 3–5 minutes_",
        parse_mode='Markdown')
    try:
        # Run key scans in parallel
        await msg.edit_text(f"📄 *Report — `{domain}`*\n\n🔄 Running 5 scan modules...", parse_mode='Markdown')
        html, forms, params = await _prescan(url)
        prog = []
        sqli, xss, ssrf, lfi, auth = await asyncio.gather(
            asyncio.to_thread(_sqli_engine_sync, url, forms, params, prog.append),
            asyncio.to_thread(_xss_engine_sync,  url, forms, params, prog.append),
            asyncio.to_thread(_ssrf_engine_sync, url, params, forms, prog.append),
            asyncio.to_thread(_lfi_engine_sync,  url, params, prog.append),
            asyncio.to_thread(_auth_engine_sync, url, forms,  prog.append),
            return_exceptions=True
        )
        # Normalize exceptions to empty dicts
        sqli = sqli if isinstance(sqli, dict) else {}
        xss  = xss  if isinstance(xss,  dict) else {}
        ssrf = ssrf if isinstance(ssrf, dict) else {}
        lfi  = lfi  if isinstance(lfi,  dict) else {}
        auth = auth if isinstance(auth, dict) else {}

        ts      = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        ts_file = datetime.now().strftime('%Y%m%d_%H%M%S')

        # Build findings list
        findings = []
        OWASP = {
            'sqli': 'A03:2021 – Injection',
            'xss':  'A03:2021 – Injection',
            'ssrf': 'A10:2021 – SSRF',
            'lfi':  'A01:2021 – Broken Access Control',
            'auth': 'A07:2021 – Identification and Authentication Failures',
        }
        for key, res, label, sev in [
            ('sqli', sqli, 'SQL Injection',     'CRITICAL'),
            ('xss',  xss,  'Cross-Site Scripting (XSS)', 'HIGH'),
            ('ssrf', ssrf, 'SSRF / Open Redirect',       'CRITICAL'),
            ('lfi',  lfi,  'Local File Inclusion (LFI)', 'CRITICAL'),
            ('auth', auth, 'Authentication Weakness',    'HIGH'),
        ]:
            vuln = res.get('vulnerable') or res.get('ssrf_found') or res.get('redirect_found') or res.get('default_creds') or res.get('no_rate_limit')
            findings.append({
                'id':       key.upper(),
                'name':     label,
                'severity': sev if vuln else 'PASS',
                'owasp':    OWASP[key],
                'vulnerable': bool(vuln),
                'param':    res.get('param') or res.get('ssrf_param', ''),
                'evidence': str(res.get('evidence', res.get('poc', '')))[:200],
                'fix':      res.get('fix', [])[:3],
            })

        vuln_count  = sum(1 for f in findings if f['vulnerable'])
        pass_count  = len(findings) - vuln_count
        risk_level  = 'CRITICAL' if any(f['severity']=='CRITICAL' and f['vulnerable'] for f in findings) else ('HIGH' if any(f['severity']=='HIGH' and f['vulnerable'] for f in findings) else 'LOW')

        # ── Markdown Report ───────────────────────────────────────────
        md = f"""# Penetration Test Report
## Target: {url}
**Generated:** {ts}
**Risk Level:** {risk_level}
**Findings:** {vuln_count} vulnerabilities | {pass_count} passed

---

## Executive Summary
This automated penetration test scanned `{domain}` for common web vulnerabilities.
{'⚠️ **Critical vulnerabilities were found** requiring immediate remediation.' if vuln_count > 0 else '✅ No critical vulnerabilities were detected in this scan.'}

| Vulnerability | OWASP | Status | Severity |
|---|---|---|---|
"""
        for f in findings:
            status = '🔴 VULNERABLE' if f['vulnerable'] else '✅ PASS'
            md += f"| {f['name']} | {f['owasp']} | {status} | {f['severity']} |\n"

        md += "\n---\n\n## Detailed Findings\n\n"
        for f in findings:
            if not f['vulnerable']: continue
            md += f"""### {f['name']} ({f['severity']})
**OWASP:** {f['owasp']}
**Parameter:** `{f['param'] or 'N/A'}`
**Evidence:** `{f['evidence'] or 'N/A'}`

**Remediation:**
"""
            for fix in f['fix']:
                md += f"- {fix}\n"
            md += "\n"

        md += f"---\n*Generated by PhantomScopeBot v52 — {ts}*\n"

        # ── JSON Report ───────────────────────────────────────────────
        report_json = {
            'meta': {'target': url, 'domain': domain, 'timestamp': ts,
                     'risk_level': risk_level, 'tool': 'PhantomScopeBot v52'},
            'summary': {'total': len(findings), 'vulnerable': vuln_count, 'passed': pass_count},
            'findings': findings,
        }

        # ── Executive Summary TXT ─────────────────────────────────────
        exec_txt = f"""EXECUTIVE SUMMARY — Penetration Test
Target: {url}
Date:   {ts}
Risk:   {risk_level}

RESULTS:
  Vulnerabilities found: {vuln_count}
  Checks passed:        {pass_count}

{'IMMEDIATE ACTION REQUIRED:' if vuln_count > 0 else 'No critical issues found.'}
"""
        for f in findings:
            if f['vulnerable']:
                exec_txt += f"  • Fix {f['name']} ({f['owasp']})\n"

        exec_txt += f"\nGenerated by PhantomScopeBot v52"

        # Send files
        import io as _io
        for fname, content, ctype in [
            (f"report_{domain}_{ts_file}.md",   md,                         '📄 Markdown Report'),
            (f"report_{domain}_{ts_file}.json", json.dumps(report_json, indent=2, ensure_ascii=False), '📊 JSON Report'),
            (f"executive_{domain}_{ts_file}.txt", exec_txt,                 '📋 Executive Summary'),
        ]:
            buf = _io.BytesIO(content.encode('utf-8'))
            await context.bot.send_document(
                chat_id=update.effective_chat.id,
                document=buf, filename=fname,
                caption=f"{ctype} — `{domain}`",
                parse_mode='Markdown',
            )

        vuln_icon = '🔴' if vuln_count > 0 else '✅'
        await msg.edit_text(
            f"📄 *Report Export Complete — `{domain}`*\n\n"
            f"{vuln_icon} Risk: `{risk_level}` | Vulns: `{vuln_count}` | Passed: `{pass_count}`\n\n"
            "3 files sent: Markdown + JSON + Executive Summary",
            parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *Report export failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


