# 3️⃣  /password_leak_check — Real Breach Detection
#     Uses Have I Been Pwned k-Anonymity API (free, no key needed)
# ══════════════════════════════════════════════════

async def _check_hibp_password(password: str) -> tuple:
    """Check password against HIBP Pwned Passwords using k-Anonymity model."""
    sha1 = hashlib.sha1(password.encode('utf-8')).hexdigest().upper()
    prefix = sha1[:5]
    suffix = sha1[5:]

    try:
        async with aiohttp.ClientSession(
                timeout=aiohttp.ClientTimeout(total=10),
                headers={"User-Agent": "TelegramBot-LeakCheck"}) as _hs:
            async with _hs.get(
                    f"https://api.pwnedpasswords.com/range/{prefix}",
                    ssl=False) as _hr:
                if _hr.status == 200:
                    text = await _hr.text()
                    for line in text.splitlines():
                        parts = line.strip().split(":")
                        if len(parts) == 2 and parts[0] == suffix:
                            return True, int(parts[1])
    except Exception:
        pass
    return False, 0


async def _check_email_breaches(email: str) -> list:
    """Check email against multiple breach-check APIs — pure aiohttp."""
    breaches = []
    _timeout = aiohttp.ClientTimeout(total=12)
    _ua = {"User-Agent": "TelegramBot-LeakCheck"}

    async with aiohttp.ClientSession(timeout=_timeout, headers=_ua) as _ses:

        # Method 1: Have I Been Pwned (requires API key for v3; falls back gracefully)
        try:
            _hdrs = {**_ua, "hibp-api-key": os.getenv("HIBP_API_KEY", "")}
            async with _ses.get(
                    f"https://haveibeenpwned.com/api/v3/breachedaccount/{email}",
                    headers=_hdrs, params={"truncateResponse": "true"},
                    ssl=False) as r1:
                if r1.status == 200:
                    for b in await r1.json(content_type=None):
                        breaches.append(b.get("Name", "Unknown"))
        except Exception:
            pass

        # Method 2: BreachDirectory public API
        try:
            async with _ses.get(
                    f"https://breachdirectory.org/api/v1/check/{email}",
                    ssl=False) as r2:
                if r2.status == 200:
                    d2 = await r2.json(content_type=None)
                    if d2.get("found"):
                        for src in d2.get("sources", []):
                            if src not in breaches:
                                breaches.append(src)
        except Exception:
            pass

        # Method 3: Leak-Lookup public search
        try:
            async with _ses.post(
                    "https://leak-lookup.com/api/search",
                    data={"key": os.getenv("LEAK_LOOKUP_KEY", "public"),
                          "type": "email_address", "query": email},
                    ssl=False) as r3:
                if r3.status == 200:
                    d3 = await r3.json(content_type=None)
                    if d3.get("error") == "false":
                        for src in d3.get("message", []):
                            if src not in breaches:
                                breaches.append(src)
        except Exception:
            pass

        # Method 4: Intelligence X public search
        try:
            _ix_key = os.getenv("INTELX_API_KEY", "")
            if _ix_key:
                async with _ses.get(
                        f"https://2.intelx.io/explore/search?s={email}",
                        headers={"x-key": _ix_key}, ssl=False) as r4:
                    if r4.status == 200:
                        d4 = await r4.json(content_type=None)
                        if d4.get("results"):
                            breaches.append("Intelligence X (Potential Leaks Found)")
        except Exception:
            pass

    return breaches


async def _check_domain_breaches(domain: str) -> dict:
    """Check domain for known breaches and exposed services."""
    results = {'breaches': [], 'exposed_services': [], 'dns_info': {}}

    # Check common subdomains for exposed services — parallel async DNS
    subdomains = ["mail","webmail","ftp","admin","cpanel","phpmyadmin",
                  "dev","staging","api","vpn","remote","git","jenkins"]

    async def _resolve(sub):
        target = f"{sub}.{domain}"
        try:
            ip = await asyncio.get_event_loop().run_in_executor(
                None, socket.gethostbyname, target)
            if _is_safe_ip(ip):  # skip private IPs (SSRF guard)
                return {"subdomain": target, "ip": ip}
        except Exception:
            pass
        return None

    _resolved = await asyncio.gather(*[_resolve(s) for s in subdomains])
    results["exposed_services"] = [r for r in _resolved if r]

    # Check DNS records
    try:
        import subprocess
        dig_result = await asyncio.to_thread(
            lambda: subprocess.run(['dig', '+short', domain, 'ANY'],
                                   capture_output=True, text=True, timeout=10)
        )
        if dig_result.returncode == 0:
            results['dns_info']['records'] = dig_result.stdout.strip()[:500]
    except Exception:
        pass

    return results


