# 4️⃣  /site_map — Sitemap Discovery & Crawler
# ══════════════════════════════════════════════════

async def cmd_site_map(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/site_map <url> — Discover and parse sitemap.xml"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/site_map https://example.com`", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    parsed = urlparse(url)
    root = f"{parsed.scheme}://{parsed.netloc}"
    domain = parsed.netloc

    msg = await update.effective_message.reply_text(
        f"🗺️ *Sitemap Discovery — `{domain}`*\n\n⏳ Scanning...", parse_mode='Markdown')

    sitemap_urls = [
        f'{root}/sitemap.xml', f'{root}/sitemap_index.xml',
        f'{root}/sitemap-index.xml', f'{root}/wp-sitemap.xml',
        f'{root}/sitemap.xml.gz', f'{root}/sitemap1.xml',
        f'{root}/post-sitemap.xml', f'{root}/page-sitemap.xml',
        f'{root}/news-sitemap.xml', f'{root}/video-sitemap.xml',
    ]

    found_sitemaps = []
    all_urls = set()

    for sm_url in sitemap_urls:
        try:
            async with aiohttp.ClientSession(
                    headers=_get_headers(),
                    timeout=aiohttp.ClientTimeout(total=10)) as _sm_sess:
                async with _sm_sess.get(sm_url, ssl=False) as _sm_r:
                    _sm_text = await _sm_r.text(errors='replace')
                    _sm_status = _sm_r.status
            if _sm_status == 200 and ('<?xml' in _sm_text[:100] or '<urlset' in _sm_text[:200] or '<sitemapindex' in _sm_text[:200]):
                found_sitemaps.append(sm_url)
                # Extract URLs
                for m in re.findall(r'<loc>\s*(https?://[^<]+)\s*</loc>', _sm_text):
                    all_urls.add(m.strip())
        except Exception:
            pass

    # Also check robots.txt for sitemap references
    try:
        async with aiohttp.ClientSession(
                headers=_get_headers(),
                timeout=aiohttp.ClientTimeout(total=8)) as _rb_sess:
            async with _rb_sess.get(f'{root}/robots.txt', ssl=False) as _rb_r:
                _rb_text   = await _rb_r.text(errors='replace')
                _rb_status = _rb_r.status
        if _rb_status == 200:
            for m in re.findall(r'(?i)sitemap:\s*(https?://\S+)', _rb_text):
                if m not in found_sitemaps:
                    found_sitemaps.append(m)
    except Exception:
        pass

    lines = [
        f"🗺️ *Sitemap Report: `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        "",
    ]

    if found_sitemaps:
        lines.append(f"📄 *Found `{len(found_sitemaps)}` sitemaps:*")
        for sm in found_sitemaps[:10]:
            lines.append(f"  ├ `{sm}`")
        lines.append("")
        lines.append(f"🔗 *Total URLs extracted:* `{len(all_urls)}`")
        if all_urls:
            lines.append("")
            lines.append("📋 *Sample URLs (first 15):*")
            for u in list(all_urls)[:15]:
                path = urlparse(u).path
                lines.append(f"  `{path}`")
    else:
        lines.append("❌ *No sitemaps found.*")

    await msg.edit_text("\n".join(lines), parse_mode='Markdown')


