async def cmd_info_unified(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /info <domain> [mode]
    Unified domain info:
      /info <domain>       — WHOIS + DNS combined
      /info <domain> sub   — subdomain enumeration
      /info <domain> whois — WHOIS only
      /info <domain> dns   — DNS records only
    """
    if not await check_force_join(update, context): return
    args = context.args or []
    if not args:
        await update.effective_message.reply_text(
            "📌 *Usage:*\n"
            "  `/info <domain>`       — WHOIS + DNS + RDAP\n"
            "  `/info <domain> sub`   — Subdomain enumeration\n"
            "  `/info <domain> whois` — WHOIS only\n"
            "  `/info <domain> dns`   — DNS records only\n",
            parse_mode='Markdown')
        return
    mode = args[-1].lower() if len(args) > 1 else "full"
    if mode in ("sub", "whois", "dns"):
        context.args = args[:-1] if len(args) > 1 else args
    else:
        mode = "full"
    if mode == "sub":
        await cmd_subdomains(update, context)
    elif mode == "whois":
        await cmd_whois(update, context)
    elif mode == "dns":
        await cmd_dns_enum(update, context)
    else:
        await cmd_info(update, context)


async def cmd_info(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /info <domain>  — Combined WHOIS + DNS records in one command

    Replaces: /whois + /dns_enum  (both still work as aliases)
    """
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/info example.com`\n\n"
            "🌐 WHOIS + RDAP + DNS records combined", parse_mode='Markdown'); return

    domain = context.args[0].strip().replace('https://','').replace('http://','').split('/')[0]
    msg = await update.effective_message.reply_text(
        f"🌐 *Domain Info — `{domain}`*\n\n⏳ Fetching WHOIS + DNS...", parse_mode='Markdown')

    async def _do():
        info = {}
        # IP
        try: info['ip'] = socket.gethostbyname(domain)
        except: info['ip'] = 'N/A'
        try: info['all_ips'] = list({r[4][0] for r in socket.getaddrinfo(domain,None)})[:5]
        except: info['all_ips'] = []

        # RDAP
        try:
            async with aiohttp.ClientSession(
                    timeout=aiohttp.ClientTimeout(total=8)) as _rdap_s:
                async with _rdap_s.get(
                        f"https://rdap.org/domain/{domain}",
                        headers={"Accept":"application/json"}, ssl=False) as _rdap_r:
                    _rdap_status = _rdap_r.status
                    _rdap_data   = await _rdap_r.json(content_type=None) if _rdap_r.status == 200 else {}
            if _rdap_status == 200:
                d = _rdap_data
                info['rdap'] = {
                    'name': d.get('ldhName', domain),
                    'status': d.get('status', []),
                    'registered': next((e['eventDate'] for e in d.get('events',[])
                                        if e.get('eventAction')=='registration'), 'N/A'),
                    'expires':    next((e['eventDate'] for e in d.get('events',[])
                                        if e.get('eventAction')=='expiration'), 'N/A'),
                    'nameservers': [ns.get('ldhName','') for ns in d.get('nameservers',[])][:4],
                }
        except: info['rdap'] = None

        # whois binary
        info['whois_fields'] = {}
        try:
            proc = subprocess.run(['whois', domain], capture_output=True, text=True, timeout=12)
            raw = proc.stdout or ''
            if raw and len(raw) > 30:
                for line in raw.splitlines():
                    if ':' in line:
                        k, _, v = line.partition(':')
                        k = k.strip().lower(); v = v.strip()
                        if v and k not in info['whois_fields']:
                            if any(x in k for x in ['registrar','creation','expir','updated',
                                                      'name server','registrant','country','dnssec']):
                                info['whois_fields'][k] = v
        except: pass

        # DNS records
        info['dns'] = {}
        for rtype in ['A','AAAA','MX','NS','TXT','CNAME']:
            try:
                r2 = subprocess.run(['dig','+short', domain, rtype],
                                    capture_output=True, text=True, timeout=8)
                if r2.returncode == 0 and r2.stdout.strip():
                    info['dns'][rtype] = r2.stdout.strip().split('\n')[:4]
            except: pass

        return info

    data = await _do()
    lines = [f"🌐 *Domain Info — `{domain}`*", "━━━━━━━━━━━━━━━━━━━━━━", ""]

    # IPs
    lines.append(f"📍 *IP:* `{data.get('ip','N/A')}`")
    if len(data.get('all_ips',[])) > 1:
        lines.append(f"   All: `{', '.join(data['all_ips'][:4])}`")

    # RDAP
    rdap = data.get('rdap')
    if rdap:
        lines += ["", "*📋 Registration:*",
                  f"  Registrar: `{', '.join(rdap.get('status',[]))[:40] or 'N/A'}`",
                  f"  Registered: `{rdap.get('registered','N/A')[:19]}`",
                  f"  Expires:    `{rdap.get('expires','N/A')[:19]}`"]
        if rdap.get('nameservers'):
            lines.append(f"  NS: `{', '.join(rdap['nameservers'])[:60]}`")

    wf = data.get('whois_fields', {})
    key_map = [('registrar','🏢 Registrar'), ('registrant country','🌍 Country'),
               ('dnssec','🔒 DNSSEC')]
    for wk, lbl in key_map:
        for fk, fv in wf.items():
            if wk in fk:
                lines.append(f"  {lbl}: `{fv[:50]}`"); break

    # DNS
    dns = data.get('dns', {})
    if dns:
        lines += ["", "*📡 DNS Records:*"]
        icons = {'A':'🌐','AAAA':'🌐','MX':'📧','NS':'📡','TXT':'📝','CNAME':'🔗'}
        for rtype, vals in dns.items():
            icon = icons.get(rtype, '•')
            lines.append(f"  {icon} {rtype}: `{', '.join(str(v)[:30] for v in vals[:2])}`")

    text = "\n".join(lines)
    if len(text) > 4000: text = text[:4000] + "\n_..._"
    await msg.edit_text(text, parse_mode='Markdown')


async def cmd_dns_enum(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/dns_enum <domain> — DNS record enumeration (A, AAAA, MX, NS, TXT, CNAME, SOA)"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/dns_enum example.com`", parse_mode='Markdown')
        return

    domain = context.args[0].strip().replace('https://', '').replace('http://', '').split('/')[0]
    msg = await update.effective_message.reply_text(
        f"📡 *DNS Enumeration — `{domain}`*\n\n⏳ Querying records...", parse_mode='Markdown')

    record_types = ['A', 'AAAA', 'MX', 'NS', 'TXT', 'CNAME', 'SOA']
    results = {}

    for rtype in record_types:
        try:
            r = await asyncio.to_thread(
                lambda rt=rtype: subprocess.run(
                    ['dig', '+short', domain, rt],
                    capture_output=True, text=True, timeout=10
                )
            )
            if r.returncode == 0 and r.stdout.strip():
                results[rtype] = r.stdout.strip().split('\n')
        except Exception:
            pass

    lines = [
        f"📡 *DNS Records: `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        "",
    ]

    type_icons = {'A': '🌐', 'AAAA': '🌐', 'MX': '📧', 'NS': '📡',
                  'TXT': '📝', 'CNAME': '🔗', 'SOA': '🏛️'}

    for rtype, records in results.items():
        icon = type_icons.get(rtype, '🔹')
        lines.append(f"{icon} *{rtype} Records:*")
        for rec in records[:5]:
            lines.append(f"  `{rec.strip()}`")
        if len(records) > 5:
            lines.append(f"  _... +{len(records)-5} more_")
        lines.append("")

    if not results:
        lines.append("❌ *No DNS records found.*")

    await msg.edit_text("\n".join(lines), parse_mode='Markdown')


