# ══════════════════════════════════════════════════

async def cmd_ssl_check(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ssl_check <domain> — SSL/TLS certificate analysis"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/ssl_check example.com`", parse_mode='Markdown')
        return

    domain = context.args[0].strip().replace('https://', '').replace('http://', '').split('/')[0]
    msg = await update.effective_message.reply_text(
        f"🔒 *SSL Check — `{domain}`*\n\n⏳ Analyzing certificate...", parse_mode='Markdown')

    try:
        import ssl as ssl_mod
        result = await asyncio.to_thread(
            lambda: subprocess.run(
                ['openssl', 's_client', '-connect', f'{domain}:443', '-servername', domain],
                input='', capture_output=True, text=True, timeout=15
            )
        )

        cert_text = result.stdout + result.stderr

        # Parse certificate info
        cert_info = {}
        for line in cert_text.splitlines():
            line = line.strip()
            if 'subject=' in line.lower():
                cert_info['subject'] = line.split('=', 1)[1].strip() if '=' in line else line
            elif 'issuer=' in line.lower():
                cert_info['issuer'] = line.split('=', 1)[1].strip() if '=' in line else line
            elif 'not before' in line.lower():
                cert_info['valid_from'] = line.split(':', 1)[1].strip() if ':' in line else line
            elif 'not after' in line.lower():
                cert_info['valid_until'] = line.split(':', 1)[1].strip() if ':' in line else line
            elif 'protocol' in line.lower() and 'tls' in line.lower():
                cert_info['protocol'] = line.strip()
            elif 'cipher' in line.lower() and 'is' in line.lower():
                cert_info['cipher'] = line.strip()

        lines = [
            f"🔒 *SSL/TLS Report: `{domain}`*",
            "━━━━━━━━━━━━━━━━━━━━",
            "",
        ]

        if cert_info:
            if 'subject' in cert_info:
                lines.append(f"📜 *Subject:* `{cert_info['subject'][:80]}`")
            if 'issuer' in cert_info:
                lines.append(f"🏢 *Issuer:* `{cert_info['issuer'][:80]}`")
            if 'valid_from' in cert_info:
                lines.append(f"📅 *Valid From:* `{cert_info['valid_from']}`")
            if 'valid_until' in cert_info:
                lines.append(f"⏰ *Valid Until:* `{cert_info['valid_until']}`")
            if 'protocol' in cert_info:
                lines.append(f"🔐 *Protocol:* `{cert_info['protocol']}`")
            if 'cipher' in cert_info:
                lines.append(f"🔑 *Cipher:* `{cert_info['cipher'][:60]}`")
            lines.append("")
            lines.append("✅ *SSL certificate is valid.*")
        else:
            lines.append("❌ *Could not retrieve SSL certificate.*")
            lines.append("_Port 443 ပိတ်ထားတာ (သို့) SSL မရှိတာ ဖြစ်နိုင်ပါသည်။_")

        await msg.edit_text("\n".join(lines), parse_mode='Markdown')

    except Exception as e:
        await msg.edit_text(f"❌ *SSL Check Failed:* `{str(e)[:100]}`", parse_mode='Markdown')


