async def cmd_waf_detect(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/waf_detect <url> — Detect WAF/Firewall type"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/waf_detect https://example.com`", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    domain = urlparse(url).netloc

    msg = await update.effective_message.reply_text(
        f"🛡️ *WAF Detection — `{domain}`*\n\n⏳ Fingerprinting firewall...", parse_mode='Markdown')

    try:
        # ✅ v51: Native aiohttp — no thread overhead
        malicious_url = url.rstrip('/') + "/?id=1%27%20OR%201%3D1--"
        _waf_timeout = aiohttp.ClientTimeout(total=12)
        async with aiohttp.ClientSession(
                headers=_get_headers(), timeout=_waf_timeout) as _waf_sess:
            # Normal request
            async with _waf_sess.get(url, ssl=False, allow_redirects=True) as _r:
                body_bytes = await _r.read()
                body = body_bytes.decode("utf-8", errors="replace").lower()[:5000]
                hdrs_lower = {k.lower(): v.lower() for k, v in _r.headers.items()}
                server = hdrs_lower.get("server", "")
                resp_status = _r.status
                # Save for later reference
                class _RespMock:
                    status_code = _r.status
                resp = _RespMock()

            # Malicious request to trigger WAF
            try:
                async with _waf_sess.get(
                        malicious_url, ssl=False, allow_redirects=True) as _rm:
                    mal_bytes = await _rm.read()
                    mal_status = _rm.status
                    mal_body   = mal_bytes.decode("utf-8", errors="replace").lower()[:5000]
                    mal_hdrs   = {k.lower(): v.lower() for k, v in _rm.headers.items()}
            except Exception:
                mal_status = 0
                mal_body   = ""
                mal_hdrs   = {}

        detected_wafs = []

        for waf_name, sigs in _WAF_SIGNATURES.items():
            score = 0
            # Check headers
            for h in sigs['headers']:
                if h in hdrs_lower or h in mal_hdrs:
                    score += 2
            # Check server
            if sigs['server'] and sigs['server'] in server:
                score += 3
            # Check body
            for pattern in sigs['body']:
                if pattern in body or pattern in mal_body:
                    score += 2
            if score >= 2:
                detected_wafs.append((waf_name, score))

        detected_wafs.sort(key=lambda x: x[1], reverse=True)

        lines = [
            f"🛡️ *WAF Detection: `{domain}`*",
            "━━━━━━━━━━━━━━━━━━━━",
            f"🌐 Normal Status: `{resp.status_code}` | Malicious Status: `{mal_status}`",
            f"📡 Server: `{server or 'Hidden'}`",
            "",
        ]

        if detected_wafs:
            lines.append(f"🔥 *Detected WAF/Firewall ({len(detected_wafs)}):*")
            for waf, score in detected_wafs:
                confidence = "High" if score >= 4 else "Medium" if score >= 2 else "Low"
                lines.append(f"  🛡️ `{waf}` — Confidence: `{confidence}`")
            lines.append("")
            if mal_status in (403, 406, 429, 503):
                lines.append(f"⚠️ *WAF actively blocking:* Malicious request returned `{mal_status}`")
        else:
            lines.append("✅ *No WAF detected.*")
            if mal_status == resp.status_code:
                lines.append("_Malicious request was not blocked — no WAF protection._")

        await msg.edit_text("\n".join(lines), parse_mode='Markdown')

    except Exception as e:
        await msg.edit_text(f"❌ *WAF Detection Failed:* `{str(e)[:100]}`", parse_mode='Markdown')


