# 1️⃣1️⃣  /cors_check — CORS Misconfiguration Scanner
# ══════════════════════════════════════════════════

async def cmd_cors_check(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/cors_check <url> — Check for CORS misconfigurations"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/cors_check https://example.com`", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    domain = urlparse(url).netloc

    msg = await update.effective_message.reply_text(
        f"🔓 *CORS Check — `{domain}`*\n\n⏳ Testing CORS policy...", parse_mode='Markdown')

    test_origins = [
        'https://evil.com',
        'https://attacker.com',
        f'https://{domain}.evil.com',
        'null',
        f'https://sub.{domain}',
    ]

    findings = []

    # ✅ v51: Native aiohttp CORS check — no threads
    _cors_timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=_cors_timeout) as _cors_session:
        for origin in test_origins:
            try:
                hdrs = {**_get_headers(), "Origin": origin}
                async with _cors_session.get(url, headers=hdrs, ssl=False) as resp:
                    acao = resp.headers.get('Access-Control-Allow-Origin', '')
                    acac = resp.headers.get('Access-Control-Allow-Credentials', '')

                    if acao:
                        vuln = False
                        desc = ''
                        if acao == '*':
                            vuln = True
                            desc = 'Wildcard (*) — allows any origin'
                        elif acao == origin:
                            vuln = True
                            desc = f'Reflects origin: {origin}'
                        elif 'null' in acao:
                            vuln = True
                            desc = 'Allows null origin'

                        if vuln:
                            severity = '🔴 HIGH' if acac.lower() == 'true' else '🟡 MEDIUM'
                            findings.append({
                                'origin': origin,
                                'acao': acao,
                                'credentials': acac,
                                'severity': severity,
                                'desc': desc,
                            })
            except Exception:
                pass

    lines = [
        f"🔓 *CORS Analysis: `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        "",
    ]

    if findings:
        lines.append(f"⚠️ *CORS Misconfigurations Found ({len(findings)}):*")
        lines.append("")
        for f in findings:
            lines.append(f"  {f['severity']}")
            lines.append(f"  Origin: `{f['origin']}`")
            lines.append(f"  ACAO: `{f['acao']}`")
            lines.append(f"  Credentials: `{f['credentials'] or 'No'}`")
            lines.append(f"  Issue: _{f['desc']}_")
            lines.append("")
    else:
        lines.append("✅ *No CORS misconfigurations detected.*")
        lines.append("_CORS policy appears to be properly configured._")

    await msg.edit_text("\n".join(lines), parse_mode='Markdown')


