async def cmd_dir_brute(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/dir_brute <url> — Directory brute-force scanner"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/dir_brute https://example.com`\n\n"
            f"📁 `{len(_DIR_WORDLIST)}` directories/files ကို scan လုပ်ပေးပါမည်။",
            parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    root = url.rstrip('/')
    domain = urlparse(url).netloc

    msg = await update.effective_message.reply_text(
        f"📁 *Dir Brute — `{domain}`*\n\n⏳ Scanning `{len(_DIR_WORDLIST)}` paths...",
        parse_mode='Markdown')

    found = []
    done = [0]

    async def _check_dir(session, word):
        target = f"{root}/{word}"
        try:
            async with session.get(target, headers=_get_headers(bypass_403=True),
                                   timeout=aiohttp.ClientTimeout(total=8),
                                   ssl=False, allow_redirects=False) as r:
                if r.status in (200, 301, 302, 401, 403):
                    size = r.content_length or 0
                    found.append({'path': word, 'status': r.status, 'size': size})
        except Exception:
            pass
        finally:
            done[0] += 1

    connector = aiohttp.TCPConnector(limit=20, ssl=False)
    async with aiohttp.ClientSession(connector=connector) as session:
        batch_size = 25
        for i in range(0, len(_DIR_WORDLIST), batch_size):
            batch = _DIR_WORDLIST[i:i+batch_size]
            tasks = [_check_dir(session, w) for w in batch]
            await asyncio.gather(*tasks, return_exceptions=True)
            try:
                await msg.edit_text(
                    f"📁 *Dir Brute — `{domain}`*\n\n"
                    f"🔄 Progress: `{done[0]}/{len(_DIR_WORDLIST)}`\n"
                    f"✅ Found: `{len(found)}`",
                    parse_mode='Markdown')
            except Exception:
                pass

    found.sort(key=lambda x: x['status'])

    lines = [
        f"📁 *Directory Scan: `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        f"📊 Scanned: `{len(_DIR_WORDLIST)}` | Found: `{len(found)}`",
        "",
    ]

    status_icons = {200: '🟢', 301: '🔵', 302: '🔵', 401: '🟡', 403: '🔴'}

    for f in found[:30]:
        icon = status_icons.get(f['status'], '⚪')
        lines.append(f"  {icon} `/{f['path']}` — `{f['status']}` ({f['size']} bytes)")

    if not found:
        lines.append("❌ *No accessible directories found.*")

    await msg.edit_text("\n".join(lines), parse_mode='Markdown')


