async def cmd_cms_detect(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/cms_detect <url> — Detect CMS type and version"""
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/cms_detect https://example.com`", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    parsed = urlparse(url)
    root = f"{parsed.scheme}://{parsed.netloc}"
    domain = parsed.netloc

    msg = await update.effective_message.reply_text(
        f"📝 *CMS Detection — `{domain}`*\n\n⏳ Fingerprinting...", parse_mode='Markdown')

    cms_results = []

    # WordPress detection
    wp_checks = [
        (f'{root}/wp-login.php', 'wp-login'),
        (f'{root}/wp-admin/', 'wp-admin'),
        (f'{root}/wp-json/', '"name"'),
        (f'{root}/wp-includes/js/wp-embed.min.js', 'wp-embed'),
        (f'{root}/xmlrpc.php', 'XML-RPC'),
    ]

    wp_version = None
    wp_score = 0
    # ✅ v51: Native aiohttp — asyncio.to_thread(requests) ပယ်ဖျက်
    _cms_timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(
            headers=_get_headers(),
            timeout=_cms_timeout) as _cms_session:

        for check_url, pattern in wp_checks:
            try:
                async with _cms_session.get(
                        check_url, ssl=False, allow_redirects=True) as r:
                    if r.status == 200:
                        text = await r.text(errors="replace")
                        if pattern.lower() in text.lower():
                            wp_score += 1
                            ver_match = re.search(r'ver=(\d+\.\d+[\.\d]*)', text)
                            if ver_match and not wp_version:
                                wp_version = ver_match.group(1)
            except Exception:
                pass

        if wp_score >= 2:
            ver_str = f" v{wp_version}" if wp_version else ""
            cms_results.append(f"📝 *WordPress{ver_str}* (Confidence: `{min(wp_score*25, 100)}%`)")

        # Shopify / Drupal / Joomla / Ghost / Wix / Squarespace / Webflow
        try:
            async with _cms_session.get(url, ssl=False, allow_redirects=True) as r:
                body_bytes = await r.read()
                r_text = body_bytes.decode("utf-8", errors="replace")
                body = r_text.lower()
                hdrs = {k.lower(): v.lower() for k, v in r.headers.items()}

                if 'cdn.shopify.com' in body or 'x-shopify-stage' in hdrs:
                    cms_results.append("🛍️ *Shopify* (Confidence: `95%`)")
                if 'drupal' in body or 'x-drupal-cache' in hdrs:
                    ver = re.search(r'Drupal (\d+[\.\d]*)', r_text)
                    ver_str = f" v{ver.group(1)}" if ver else ""
                    cms_results.append(f"💧 *Drupal{ver_str}* (Confidence: `85%`)")
                if '/media/jui/' in body or 'joomla' in body:
                    cms_results.append("🔶 *Joomla* (Confidence: `80%`)")
                if 'ghost' in body and ('ghost/api' in body or 'ghost-url' in body):
                    cms_results.append("👻 *Ghost CMS* (Confidence: `85%`)")
                if 'wix.com' in body or 'wixstatic.com' in body:
                    cms_results.append("🟦 *Wix* (Confidence: `90%`)")
                if 'squarespace' in body:
                    cms_results.append("⬛ *Squarespace* (Confidence: `90%`)")
                if 'webflow' in body or 'data-wf-' in body:
                    cms_results.append("🟪 *Webflow* (Confidence: `85%`)")
        except Exception:
            pass

    lines = [
        f"📝 *CMS Detection: `{domain}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        "",
    ]

    if cms_results:
        lines.append("🔍 *Detected CMS:*")
        for cms in cms_results:
            lines.append(f"  {cms}")
    else:
        lines.append("❓ *No known CMS detected.*")
        lines.append("_Custom-built website ဖြစ်နိုင်ပါသည်။_")

    await msg.edit_text("\n".join(lines), parse_mode='Markdown')


