async def cmd_speed_audit(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/speed_audit <url> — Website loading speed and performance audit"""
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/speed_audit https://example.com`", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url
    domain = urlparse(url).netloc

    msg = await update.effective_message.reply_text(
        f"⚡ *Speed Audit — `{domain}`*\n\n⏳ Measuring performance...", parse_mode='Markdown')

    try:
        # ✅ v51: Pure aiohttp timing measurement
        start = time.monotonic()
        _speed_timeout = aiohttp.ClientTimeout(total=30)
        async with aiohttp.ClientSession(
                headers=_get_headers(),
                timeout=_speed_timeout) as _spd_session:
            req_start = time.monotonic()
            async with _spd_session.get(url, ssl=False, allow_redirects=True) as resp:
                # TTFB = time until first byte received (headers done)
                ttfb = time.monotonic() - req_start
                body_bytes = await resp.read()
                total_time = time.monotonic() - start

        body = body_bytes.decode("utf-8", errors="replace")
        content_length = len(body_bytes)
        encoding = resp.headers.get("Content-Encoding", "")
        cache_control = resp.headers.get("Cache-Control", "")
        soup = BeautifulSoup(body, _BS_PARSER)

        # Count resources
        scripts = soup.find_all('script', src=True)
        stylesheets = soup.find_all('link', rel='stylesheet')
        images = soup.find_all('img')
        iframes = soup.find_all('iframe')

        # Check for performance issues
        issues = []
        if ttfb > 2.0:
            issues.append(f"🔴 TTFB too slow: `{ttfb:.2f}s` (should be < 0.8s)")
        elif ttfb > 0.8:
            issues.append(f"🟡 TTFB moderate: `{ttfb:.2f}s` (should be < 0.8s)")

        if content_length > 500_000:
            issues.append(f"🔴 Page too large: `{content_length/1024:.0f} KB` (should be < 500KB)")
        elif content_length > 200_000:
            issues.append(f"🟡 Page size moderate: `{content_length/1024:.0f} KB`")

        if len(scripts) > 20:
            issues.append(f"🔴 Too many scripts: `{len(scripts)}` (should be < 15)")
        elif len(scripts) > 10:
            issues.append(f"🟡 Many scripts: `{len(scripts)}`")

        if len(stylesheets) > 10:
            issues.append(f"🟡 Many stylesheets: `{len(stylesheets)}`")

        # Check for lazy loading
        lazy_imgs = sum(1 for img in images if img.get('loading') == 'lazy')
        if images and lazy_imgs == 0:
            issues.append(f"🟡 No lazy loading on `{len(images)}` images")

        # Check compression (already extracted above)
        if not encoding:
            issues.append("🟡 No compression (gzip/br) detected")

        # Check caching (already extracted above)
        if not cache_control:
            issues.append("🟡 No Cache-Control header")

        # Score
        score = 100
        for issue in issues:
            if '🔴' in issue:
                score -= 15
            elif '🟡' in issue:
                score -= 5
        score = max(0, score)
        grade = 'A+' if score >= 95 else 'A' if score >= 85 else 'B' if score >= 70 else 'C' if score >= 50 else 'D' if score >= 30 else 'F'

        lines = [
            f"⚡ *Speed Audit: `{domain}`*",
            "━━━━━━━━━━━━━━━━━━━━",
            f"📊 *Score:* `{score}/100` (Grade: `{grade}`)",
            "",
            "⏱️ *Timing:*",
            f"  TTFB: `{ttfb:.3f}s`",
            f"  Total Load: `{total_time:.3f}s`",
            "",
            "📦 *Page Size:*",
            f"  HTML: `{content_length/1024:.1f} KB`",
            f"  Compression: `{encoding or 'None'}`",
            f"  Caching: `{cache_control[:40] or 'None'}`",
            "",
            "📋 *Resources:*",
            f"  Scripts: `{len(scripts)}` | CSS: `{len(stylesheets)}`",
            f"  Images: `{len(images)}` (lazy: `{lazy_imgs}`) | iFrames: `{len(iframes)}`",
            "",
        ]

        if issues:
            lines.append(f"⚠️ *Issues ({len(issues)}):*")
            for issue in issues:
                lines.append(f"  {issue}")
        else:
            lines.append("✅ *No major performance issues detected!*")

        await msg.edit_text("\n".join(lines), parse_mode='Markdown')

    except Exception as e:
        await msg.edit_text(f"❌ *Speed Audit Failed:* `{str(e)[:100]}`", parse_mode='Markdown')


