async def cmd_smuggle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /smuggle <url> [h2c]

    HTTP Request Smuggling Detection:
      /smuggle <url>       — CL.TE + TE.CL + TE.TE-obfuscated (HTTP/1.1)
      /smuggle <url> h2c   — HTTP/2 Cleartext (h2c) tunneling test
    """
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(
            f"⏳ `{_active_scans.get(uid)}` running — `/stop` နှိပ်ပါ",
            parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:*\n"
            "  `/smuggle <url>`       — CL.TE / TE.CL detection\n"
            "  `/smuggle <url> h2c`   — H2C upgrade test\n\n"
            "⚠️ _Authorized testing only._",
            parse_mode='Markdown'); return

    url  = context.args[0].strip()
    mode = (context.args[1].lower() if len(context.args) > 1 else "http1")
    if not url.startswith("http"): url = "https://" + url
    safe, reason = is_safe_url(url)
    if not safe:
        await update.effective_message.reply_text(
            f"❌ *Blocked:* {reason}", parse_mode='Markdown'); return

    domain = urlparse(url).netloc
    _active_scans.set(uid, "Smuggling Test")

    try:
        # ══ H2C MODE ═════════════════════════════════════════════════════
        if mode == "h2c":
            msg = await update.effective_message.reply_text(
                f"🚀 *h2c Smuggling — `{domain}`*\n\n⏳ Testing Protocol Upgrade...",
                parse_mode='Markdown')
            h2c_headers = {
                "Upgrade":        "h2c",
                "Connection":     "Upgrade, HTTP2-Settings",
                "HTTP2-Settings": "AAMAAABkAAQAAP__",
            }
            result_set = False
            for attempt in range(1, 4):
                proxy_entry = await _PROXY_MANAGER.get_proxy(strategy='round-robin')
                proxy_url   = proxy_entry.url if proxy_entry else None
                try:
                    async with aiohttp.ClientSession(
                            headers=_get_headers(),
                            timeout=aiohttp.ClientTimeout(total=10)) as session:
                        async with session.get(
                                url, headers=h2c_headers, proxy=proxy_url,
                                ssl=False, allow_redirects=False) as r:
                            if proxy_entry: await _PROXY_MANAGER.mark_success(proxy_entry)
                            if r.status == 101:
                                await msg.edit_text(
                                    "🔴 *CRITICAL:* Server accepted `Upgrade: h2c` (101).\n\n"
                                    "💡 WAF/proxy bypass via HTTP/2 binary frames is possible.\n"
                                    "Exploit: upgrade then send smuggled HTTP/1.1 inside h2c stream.",
                                    parse_mode='Markdown')
                            elif "h2c" in r.headers.get("Upgrade", "").lower():
                                await msg.edit_text(
                                    f"🟠 *POTENTIAL:* h2c in Upgrade header (status `{r.status}`).\n"
                                    "_Manual verification recommended._",
                                    parse_mode='Markdown')
                            else:
                                await msg.edit_text(
                                    f"✅ *Not Vulnerable:* `{r.status}` — h2c upgrade rejected.",
                                    parse_mode='Markdown')
                            result_set = True
                            _active_scans.pop(uid, None)
                            return
                except (asyncio.TimeoutError, aiohttp.ClientError):
                    if proxy_entry: await _PROXY_MANAGER.mark_fail(proxy_entry)
                except Exception as e:
                    logger.debug("h2c test error: %s", e)
                    break
            if not result_set:
                await msg.edit_text(
                    "❌ *Test Failed:* All proxy attempts timed out.",
                    parse_mode='Markdown')

        # ══ HTTP/1.1 MODE (CL.TE / TE.CL / TE.TE) ═══════════════════════
        else:
            msg = await update.effective_message.reply_text(
                f"🚀 *Smuggling Test — `{domain}`*\n\n"
                "⏳ Testing CL.TE / TE.CL / TE.TE variants...\n"
                "_3 probes × 3 variants_",
                parse_mode='Markdown')
            findings = []
            tests = [
                {
                    "name":    "CL.TE",
                    "headers": {"Content-Length": "4", "Transfer-Encoding": "chunked"},
                    "body":    "1\r\nZ\r\n0\r\n\r\n",
                    "desc":    "Frontend uses Content-Length; backend uses Transfer-Encoding.",
                },
                {
                    "name":    "TE.CL",
                    "headers": {"Transfer-Encoding": "chunked", "Content-Length": "6"},
                    "body":    "0\r\n\r\nX",
                    "desc":    "Frontend uses Transfer-Encoding; backend uses Content-Length.",
                },
                {
                    "name":    "TE.TE (obfuscated)",
                    "headers": {
                        "Transfer-Encoding":    "chunked",
                        "Transfer-Encoding\t":  "xchunked",
                    },
                    "body":    "0\r\n\r\n",
                    "desc":    "Tab-obfuscated duplicate TE header to bypass WAF normalization.",
                },
            ]
            for t in tests:
                found = False
                for attempt in range(1, 4):
                    proxy_entry = await _PROXY_MANAGER.get_proxy(strategy='round-robin')
                    proxy_url   = proxy_entry.url if proxy_entry else None
                    try:
                        t0 = time.monotonic()
                        async with aiohttp.ClientSession(
                                headers=_get_headers(),
                                timeout=aiohttp.ClientTimeout(total=16)) as session:
                            async with session.post(
                                    url, headers=t["headers"], data=t["body"],
                                    proxy=proxy_url, ssl=False) as r:
                                elapsed = time.monotonic() - t0
                                if proxy_entry: await _PROXY_MANAGER.mark_success(proxy_entry)
                                if elapsed > 6:
                                    findings.append(
                                        f"⚠️ *{t['name']} DETECTED* — delay `{elapsed:.1f}s`\n"
                                        f"  _{t['desc']}_")
                                elif r.status == 400:
                                    findings.append(f"ℹ️ *{t['name']} Rejected* — 400 (WAF protected)")
                                elif r.status in (200, 204):
                                    findings.append(
                                        f"🟡 *{t['name']} Ambiguous* — `{r.status}` (manual verify)")
                                found = True
                                break
                    except asyncio.TimeoutError:
                        if proxy_entry: await _PROXY_MANAGER.mark_fail(proxy_entry)
                        if attempt == 3:
                            findings.append(
                                f"🔥 *{t['name']} HIGH RISK* — timed out on all 3 probes\n"
                                f"  _{t['desc']}_")
                            found = True
                    except Exception as e:
                        logger.debug("Smuggle %s error: %s", t["name"], e)
                        break
                if not found:
                    findings.append(f"❓ *{t['name']}* — test inconclusive")

            if any("DETECTED" in f or "HIGH RISK" in f for f in findings):
                header = "🔥 *Vulnerability Indicators Found:*\n"
            else:
                header = "✅ *No Smuggling Detected:*\n"

            report = header + "\n".join(f"\n{f}" for f in findings)
            report += "\n\n⚠️ _Authorized testing only. Results may vary by network path._"
            if len(report) > 4000:
                report = report[:4000] + "\n_...(truncated)_"
            await msg.edit_text(report, parse_mode='Markdown')

    finally:
        _active_scans.pop(uid, None)


