# ─────────────────────────────────────────────────────────────────────────────
# 🔒  /ssltls_deep <domain> — Deep SSL/TLS audit
#     TLS version, cipher suite weakness, cert chain, HSTS, HPKP
# ─────────────────────────────────────────────────────────────────────────────

async def cmd_ssltls_deep(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ssltls_deep <domain> — Deep SSL/TLS cipher + cert chain audit"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/ssltls_deep example.com`\n\n"
            "🔒 *Checks:*\n"
            "  • TLS 1.0 / 1.1 (deprecated) detection\n"
            "  • Weak cipher suites (RC4, DES, 3DES, NULL)\n"
            "  • Certificate expiry + chain validation\n"
            "  • HSTS header presence + max-age\n"
            "  • Self-signed / mismatched cert detection\n"
            "  • Certificate Transparency (CT) log check\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown'); return

    domain = context.args[0].strip().replace("https://","").replace("http://","").split("/")[0]
    try:
        ip = await asyncio.to_thread(lambda: __import__('socket').gethostbyname(domain))
        if not _is_safe_ip(ip):
            await update.effective_message.reply_text("🚫 Private IP blocked", parse_mode='Markdown'); return
    except Exception:
        await update.effective_message.reply_text(f"❌ Cannot resolve `{domain}`", parse_mode='Markdown'); return

    _active_scans.set(uid, "SSL/TLS Deep")
    msg = await update.effective_message.reply_text(
        f"🔒 *SSL/TLS Deep Audit — `{domain}`*\n\n⏳ Probing TLS stack...", parse_mode='Markdown')

    try:
        result = await asyncio.to_thread(_ssltls_deep_sync, domain)
        lines = [f"🔒 *SSL/TLS Deep Audit — `{domain}`*", "━"*20, ""]

        # TLS Versions
        lines.append("*📋 TLS Version Support:*")
        for ver, supported in result.get("tls_versions", {}).items():
            if ver in ("TLSv1", "TLSv1.1"):
                icon = "🔴 VULNERABLE" if supported else "✅ Disabled"
            else:
                icon = "✅ Supported" if supported else "⚪ Not supported"
            lines.append(f"  {ver}: `{icon}`")
        lines.append("")

        # Certificate
        cert = result.get("cert", {})
        if cert:
            lines.append("*📜 Certificate:*")
            lines.append(f"  Subject: `{cert.get('subject','?')[:60]}`")
            lines.append(f"  Issuer:  `{cert.get('issuer','?')[:60]}`")
            lines.append(f"  Expiry:  `{cert.get('not_after','?')}`")
            days = cert.get('days_remaining', 999)
            expiry_icon = "🔴" if days < 14 else "🟡" if days < 30 else "✅"
            lines.append(f"  {expiry_icon} Days remaining: `{days}`")
            if cert.get("self_signed"):
                lines.append("  🔴 *Self-signed certificate!*")
            if cert.get("mismatch"):
                lines.append("  🔴 *Hostname mismatch!*")
            lines.append("")

        # Cipher issues
        weak = result.get("weak_ciphers", [])
        if weak:
            lines.append(f"*🔴 Weak Ciphers ({len(weak)}):*")
            for c in weak[:6]:
                lines.append(f"  ⚠️ `{c}`")
            lines.append("")

        # HSTS
        hsts = result.get("hsts")
        if hsts:
            lines.append(f"✅ *HSTS:* `{hsts[:80]}`")
        else:
            lines.append("🟡 *HSTS:* Not present — SSL stripping possible")
        lines.append("")

        # Overall grade
        issues = result.get("issues", [])
        if any("critical" in i.lower() for i in issues):
            grade = "🔴 F — Critical Issues"
        elif weak or not hsts:
            grade = "🟠 C — Hardening Needed"
        elif days < 30:
            grade = "🟡 B — Cert Expiring Soon"
        else:
            grade = "✅ A — Good Configuration"
        lines += ["", f"*📊 Overall Grade:* {grade}", "", "⚠️ _Authorized testing only_"]

        await msg.edit_text("\n".join(lines), parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *Failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


def _ssltls_deep_sync(domain: str) -> dict:
    """Sync SSL/TLS deep auditor."""
    import ssl, socket
    from datetime import datetime as _dt
    result = {
        "tls_versions": {}, "cert": {}, "weak_ciphers": [],
        "hsts": None, "issues": [],
    }
    _WEAK_CIPHER_KEYWORDS = ["RC4","DES","3DES","NULL","EXPORT","anon","MD5","SHA1"]
    _TLS_VERSIONS = [
        ("TLSv1",   ssl.PROTOCOL_TLS_CLIENT, ssl.TLSVersion.TLSv1  if hasattr(ssl.TLSVersion, "TLSv1")  else None),
        ("TLSv1.1", ssl.PROTOCOL_TLS_CLIENT, ssl.TLSVersion.TLSv1_1 if hasattr(ssl.TLSVersion, "TLSv1_1") else None),
        ("TLSv1.2", ssl.PROTOCOL_TLS_CLIENT, ssl.TLSVersion.TLSv1_2),
        ("TLSv1.3", ssl.PROTOCOL_TLS_CLIENT, ssl.TLSVersion.TLSv1_3 if hasattr(ssl.TLSVersion, "TLSv1_3") else None),
    ]

    # Test each TLS version
    for ver_name, proto, tls_ver in _TLS_VERSIONS:
        if tls_ver is None:
            result["tls_versions"][ver_name] = False
            continue
        try:
            ctx = ssl.SSLContext(proto)
            ctx.check_hostname = False
            ctx.verify_mode = ssl.CERT_NONE
            try:
                ctx.minimum_version = tls_ver
                ctx.maximum_version = tls_ver
            except AttributeError:
                pass
            with socket.create_connection((domain, 443), timeout=5) as sock:
                with ctx.wrap_socket(sock, server_hostname=domain) as ssock:
                    result["tls_versions"][ver_name] = True
                    # Get cipher + cert on TLS 1.2+
                    if ver_name in ("TLSv1.2", "TLSv1.3") and not result["cert"]:
                        cipher = ssock.cipher()
                        if cipher:
                            cn = cipher[0]
                            if any(w in cn for w in _WEAK_CIPHER_KEYWORDS):
                                result["weak_ciphers"].append(cn)
                        raw = ssock.getpeercert()
                        if raw:
                            subj_dict = dict(x[0] for x in raw.get("subject", []))
                            issuer_dict = dict(x[0] for x in raw.get("issuer", []))
                            not_after_str = raw.get("notAfter", "")
                            try:
                                not_after = _dt.strptime(not_after_str, "%b %d %H:%M:%S %Y %Z")
                                days_left = (not_after - _dt.utcnow()).days
                            except Exception:
                                not_after = None
                                days_left = 999
                            subj_cn = subj_dict.get("commonName", "")
                            issuer_o = issuer_dict.get("organizationName", "")
                            self_signed = (subj_dict == issuer_dict)
                            mismatch = domain not in subj_cn and f"*.{'.'.join(domain.split('.')[1:])}" not in subj_cn
                            result["cert"] = {
                                "subject": subj_cn, "issuer": issuer_o,
                                "not_after": not_after_str[:20] if not_after_str else "?",
                                "days_remaining": days_left,
                                "self_signed": self_signed, "mismatch": mismatch,
                            }
                            if self_signed: result["issues"].append("critical: self-signed cert")
                            if days_left < 14: result["issues"].append("critical: cert expiring <14d")
                            elif days_left < 30: result["issues"].append("warning: cert expiring <30d")
        except (ssl.SSLError, ConnectionRefusedError, OSError, TimeoutError):
            result["tls_versions"][ver_name] = False
        except Exception:
            result["tls_versions"][ver_name] = False

    if result["tls_versions"].get("TLSv1") or result["tls_versions"].get("TLSv1.1"):
        result["issues"].append("critical: deprecated TLS version enabled")

    # HSTS check
    try:
        import requests as _req
        r = _req.get(f"https://{domain}", timeout=8, verify=False, headers=_get_headers())
        result["hsts"] = r.headers.get("Strict-Transport-Security", None)
    except Exception:
        pass

    return result


