async def cmd_cors_deep(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/cors_deep <url> — Deep CORS policy audit (preflight + credentialed)"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
