    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(f"⏳ `{_active_scans.get(uid)}` running — `/stop`", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/cors_deep https://api.example.com`\n\n"
            "🔓 *CORS Deep Tests:*\n"
            "  ① Simple origin reflection check\n"
            "  ② Null origin bypass\n"
            "  ③ Subdomain wildcard (`*.domain.com`)\n"
            "  ④ Preflight OPTIONS method\n"
            "  ⑤ Credentialed request (`withCredentials`)\n"
            "  ⑥ HTTP→HTTPS origin downgrade\n"
            "  ⑦ Unicode domain bypass\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown'); return

    _active_scans.set(uid, "CORS Deep")
    domain = urlparse(url).netloc
    apex = '.'.join(domain.split('.')[-2:]) if domain.count('.') >= 1 else domain

    msg = await update.effective_message.reply_text(
        f"🔓 *CORS Deep Audit — `{domain}`*\n\n⏳ Testing 8 CORS bypass vectors...", parse_mode='Markdown')

    test_origins = [
        (f"https://evil.com", "Arbitrary origin"),
        (f"https://attacker.com", "Attacker origin"),
        ("null", "Null origin (sandbox bypass)"),
        (f"https://{domain}.evil.com", "Domain prefix abuse"),
        (f"https://evil.com.{apex}", "Domain suffix abuse"),
        (f"http://{domain}", "HTTP downgrade"),
        (f"https://sub.{apex}", "Subdomain wildcard"),
        (f"https://ẹvil.com", "Unicode homoglyph"),
    ]

    findings = []
    try:
        timeout = aiohttp.ClientTimeout(total=10)
        async with aiohttp.ClientSession(timeout=timeout) as sess:
            for origin, test_name in test_origins:
                await asyncio.sleep(0)
                # Simple GET with Origin
                try:
                    async with sess.get(url, headers={**_get_headers(), "Origin": origin},
                                        ssl=False) as r:
                        acao = r.headers.get("Access-Control-Allow-Origin", "")
                        acac = r.headers.get("Access-Control-Allow-Credentials", "")
                        acam = r.headers.get("Access-Control-Allow-Methods", "")
                        vary = r.headers.get("Vary", "")
                        if acao and (acao == "*" or acao == origin or acao == "null"):
                            sev = "🔴 CRITICAL" if (acac.lower() == "true" and acao != "*") else "🟠 HIGH" if acao == origin else "🟡 MEDIUM"
                            findings.append({
                                "test": test_name, "origin": origin, "acao": acao,
                                "credentials": acac, "methods": acam,
                                "vary": vary, "severity": sev,
                            })
                except Exception:
                    pass

                # Preflight OPTIONS
                try:
                    async with sess.options(
                            url,
                            headers={
                                **_get_headers(),
                                "Origin": origin,
                                "Access-Control-Request-Method": "DELETE",
                                "Access-Control-Request-Headers": "Authorization,X-Custom-Header",
                            }, ssl=False) as r:
                        acao_p = r.headers.get("Access-Control-Allow-Origin", "")
                        acam_p = r.headers.get("Access-Control-Allow-Methods", "")
                        acah_p = r.headers.get("Access-Control-Allow-Headers", "")
                        if acao_p and "DELETE" in acam_p and acao_p == origin:
                            findings.append({
                                "test": f"Preflight: {test_name}", "origin": origin,
                                "acao": acao_p, "credentials": "",
                                "methods": acam_p, "vary": "",
                                "severity": "🔴 CRITICAL",
                            })
                except Exception:
                    pass

        out = [f"🔓 *CORS Deep Audit — `{domain}`*", "━"*20,
               f"📊 Tested: `{len(test_origins)}` origins × GET + OPTIONS", ""]
        if findings:
            out.append(f"⚠️ *CORS Misconfigurations ({len(findings)} found):*\n")
            for fi in findings[:8]:
                out += [
                    f"  {fi['severity']}",
                    f"  Test: _{fi['test']}_",
                    f"  Origin: `{fi['origin'][:60]}`",
                    f"  ACAO: `{fi['acao']}`",
                    f"  Credentials: `{fi['credentials'] or 'false'}`",
                    f"  Methods: `{fi['methods'][:40] or 'not specified'}`",
                    "",
                ]
            out += [
                "*🔧 Fix:*",
                "  • Use explicit allowlist: `Access-Control-Allow-Origin: https://trusted.com`",
                "  • Never reflect Origin header blindly",
                "  • Set `Vary: Origin` header",
                "  • Never combine `*` with `Allow-Credentials: true`",
                "  • Validate origin against server-side allowlist",
            ]
        else:
            out.append("✅ *No CORS misconfiguration detected.*")
            out.append(f"_All `{len(test_origins)}` test origins properly rejected._")
        out.append("\n⚠️ _Authorized testing only_")
        await msg.edit_text("\n".join(out), parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *CORS deep audit failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


