# ─────────────────────────────────────────────────────────────────────────────

async def cmd_ratelimit_test(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ratelimit_test <url> — Test rate limiting / brute-force protection"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(f"⏳ `{_active_scans.get(uid)}` running — `/stop`", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/ratelimit_test https://site.com/login`\n\n"
            "🔢 *Rate Limit Tests:*\n"
            "  ① Rapid request burst (20 reqs/s)\n"
            "  ② 429 / 503 status detection\n"
            "  ③ Lockout detection (body analysis)\n"
            "  ④ CAPTCHA trigger detection\n"
            "  ⑤ Retry-After header check\n"
            "  ⑥ X-RateLimit header presence\n"
            "  ⑦ Account lockout threshold\n\n"
            "⚠️ _Authorized testing only — sends 30 requests_", parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown'); return

    _active_scans.set(uid, "Rate Limit Test")
    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"🔢 *Rate Limit Test — `{domain}`*\n\n⏳ Sending 30 rapid requests...", parse_mode='Markdown')

    results = {
        "total": 0, "blocked_429": 0, "blocked_503": 0,
        "lockout_detected": False, "captcha_detected": False,
        "retry_after": None, "ratelimit_headers": [],
        "response_times": [], "status_codes": [],
    }

    LOCKOUT_PHRASES = ["locked","too many","blocked","throttle","banned","limit exceeded","slow down"]
    CAPTCHA_PHRASES = ["captcha","recaptcha","hcaptcha","challenge","are you human","verify"]
    RATELIMIT_HDRS  = ["x-ratelimit-limit","x-ratelimit-remaining","x-ratelimit-reset",
                       "x-rate-limit","retry-after","ratelimit-limit"]

    try:
        timeout = aiohttp.ClientTimeout(total=8)
        # Phase 1: Burst test — 30 parallel requests
        async with aiohttp.ClientSession(timeout=timeout) as sess:
            start_t = time.monotonic()

            async def _single_probe(i):
                t0 = time.monotonic()
                try:
                    async with sess.post(
                            url,
                            data={"username": f"ratelimitcheck{i}", "password": "testpass"},
                            headers=_get_headers(), ssl=False) as r:
                        body = (await r.text(errors="replace"))[:500].lower()
                        elapsed = time.monotonic() - t0
                        return {
                            "status": r.status, "elapsed": elapsed,
                            "body": body, "headers": dict(r.headers),
                        }
                except Exception as e:
                    return {"status": 0, "elapsed": time.monotonic()-t0, "body": "", "headers": {}}

            # Send 30 requests in batches of 10
            all_responses = []
            for batch_start in range(0, 30, 10):
                batch = await asyncio.gather(*[_single_probe(i) for i in range(batch_start, batch_start+10)])
                all_responses.extend(batch)
                await asyncio.sleep(0.1)

        elapsed_total = time.monotonic() - start_t
        results["total"] = len(all_responses)

        for resp in all_responses:
            s = resp["status"]
            results["status_codes"].append(s)
            results["response_times"].append(resp["elapsed"])
            if s == 429: results["blocked_429"] += 1
            if s == 503: results["blocked_503"] += 1
            body = resp["body"]
            if any(p in body for p in LOCKOUT_PHRASES):
                results["lockout_detected"] = True
            if any(p in body for p in CAPTCHA_PHRASES):
                results["captcha_detected"] = True
            for hdr in RATELIMIT_HDRS:
                if hdr in {k.lower() for k in resp["headers"]}:
                    val = next((v for k,v in resp["headers"].items() if k.lower() == hdr), "")
                    entry = f"`{hdr}: {val[:40]}`"
                    if entry not in results["ratelimit_headers"]:
                        results["ratelimit_headers"].append(entry)
            retry = resp["headers"].get("Retry-After") or resp["headers"].get("retry-after")
            if retry and not results["retry_after"]:
                results["retry_after"] = retry

        avg_rt = sum(results["response_times"]) / max(len(results["response_times"]), 1)
        blocked_total = results["blocked_429"] + results["blocked_503"]
        is_protected = blocked_total > 0 or results["lockout_detected"] or results["captcha_detected"]

        out = [f"🔢 *Rate Limit Test — `{domain}`*", "━"*20, ""]
        out.append("*📊 Results:*")
        out.append(f"  Requests sent : `{results['total']}` in `{elapsed_total:.1f}s`")
        out.append(f"  Avg response  : `{avg_rt*1000:.0f}ms`")
        out.append(f"  Status 429    : `{results['blocked_429']}`")
        out.append(f"  Status 503    : `{results['blocked_503']}`")
        out.append(f"  Lockout msg   : `{'Yes' if results['lockout_detected'] else 'No'}`")
        out.append(f"  CAPTCHA       : `{'Yes' if results['captcha_detected'] else 'No'}`")
        if results["retry_after"]:
            out.append(f"  Retry-After   : `{results['retry_after']}`")
        out.append("")

        if results["ratelimit_headers"]:
            out.append("*📋 Rate Limit Headers:*")
            for h in results["ratelimit_headers"][:6]:
                out.append(f"  ✅ {h}")
            out.append("")

        if is_protected:
            out.append(f"✅ *Rate limiting IS enforced* (`{blocked_total}/{results['total']}` blocked)")
        else:
            out += [
                "🔴 *No rate limiting detected!*",
                "_All 30 rapid requests returned normal responses._",
                "",
                "*🔧 Fix:*",
                "  • Nginx: `limit_req_zone $binary_remote_addr zone=login:10m rate=5r/m;`",
                "  • Express.js: `express-rate-limit` middleware",
                "  • Django: `django-ratelimit` decorator",
                "  • Return `429 Too Many Requests` with `Retry-After` header",
                "  • Implement account lockout after 5 failed attempts",
                "  • Add CAPTCHA (hCaptcha/reCAPTCHA) on login forms",
            ]
        out.append("\n⚠️ _Authorized testing only_")
        await msg.edit_text("\n".join(out), parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *Rate limit test failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


