# 🔍  /nuclei_lite <url> — CVE Template Lite Scanner
#     Runs built-in critical CVE checks (no external nuclei binary needed)
# ─────────────────────────────────────────────────────────────────────────────

_NUCLEI_TEMPLATES = [
    # (name, method, path, headers, body, detect_fn, severity)
    ("CVE-2021-44228 Log4Shell", "GET", "/${jndi:ldap://127.0.0.1/a}", {}, None,
     lambda s,b,h: s in (200,500) and "jndi" not in b.lower(), "CRITICAL"),
    ("CVE-2022-22965 Spring4Shell", "POST", "/", {"Content-Type": "application/x-www-form-urlencoded"},
     "class.module.classLoader.urls[0]=0",
     lambda s,b,h: s == 400 and ("binding" in b.lower() or "method not allowed" not in b.lower()), "CRITICAL"),
    ("CVE-2021-41773 Apache path traversal", "GET", "/cgi-bin/.%2e/%2e%2e/%2e%2e/etc/passwd", {}, None,
     lambda s,b,h: s == 200 and "root:x" in b, "CRITICAL"),
    ("CVE-2021-42013 Apache path traversal v2", "GET", "/cgi-bin/.%%32%65/etc/passwd", {}, None,
     lambda s,b,h: s == 200 and "root:x" in b, "CRITICAL"),
    ("CVE-2023-44487 HTTP/2 Rapid Reset", "GET", "/", {"X-Rapid-Reset-Check": "true"}, None,
     lambda s,b,h: s in (200,400) and "x-rapid-reset-check" not in str(h).lower(), "HIGH"),
    ("PHP-CGI RCE CVE-2024-4577", "GET", "/?%ADd+allow_url_include%3d1+-d+auto_prepend_file%3dphp://input", {}, None,
     lambda s,b,h: s == 200 and "allow_url_include" in b, "CRITICAL"),
    ("Git config exposed", "GET", "/.git/config", {}, None,
     lambda s,b,h: s == 200 and "[core]" in b, "HIGH"),
    (".env exposed", "GET", "/.env", {}, None,
     lambda s,b,h: s == 200 and any(k in b for k in ["APP_KEY","DB_PASSWORD","SECRET_KEY","AWS_"]), "CRITICAL"),
    ("phpinfo() exposed", "GET", "/phpinfo.php", {}, None,
     lambda s,b,h: s == 200 and "phpinfo()" in b.lower(), "MEDIUM"),
    ("Admin panel open", "GET", "/admin", {}, None,
     lambda s,b,h: s == 200 and any(k in b.lower() for k in ["dashboard","admin panel","login","welcome"]), "HIGH"),
    ("Exposed .DS_Store", "GET", "/.DS_Store", {}, None,
     lambda s,b,h: s == 200 and b.startswith("\x00\x00\x00\x01"), "MEDIUM"),
    ("Backup file exposed", "GET", "/backup.zip", {}, None,
     lambda s,b,h: s == 200 and len(b) > 100, "HIGH"),
    ("CORS wildcard", "GET", "/", {"Origin": "https://evil.com"}, None,
     lambda s,b,h: h.get("access-control-allow-origin","") == "*", "MEDIUM"),
    ("Server header disclosure", "GET", "/", {}, None,
     lambda s,b,h: bool(h.get("server","")) and any(c.isdigit() for c in h.get("server","")), "LOW"),
]

async def cmd_nuclei_lite(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/nuclei_lite <url> — Lightweight CVE template scanner (no external binary)"""
    if not await check_force_join(update, context): return
    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid, heavy=True)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown'); return
    if uid in _active_scans:
        await update.effective_message.reply_text(f"⏳ `{_active_scans.get(uid)}` running — `/stop`", parse_mode='Markdown'); return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/nuclei_lite https://example.com`\n\n"
            f"🔍 *Nuclei-lite — {len(_NUCLEI_TEMPLATES)} CVE templates:*\n"
            "  • Log4Shell (CVE-2021-44228)\n"
            "  • Spring4Shell (CVE-2022-22965)\n"
            "  • Apache path traversal (CVE-2021-41773/42013)\n"
            "  • PHP-CGI RCE (CVE-2024-4577)\n"
            "  • Git/env/backup file exposure\n"
            "  • phpinfo, admin panel, CORS wildcard\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown'); return

    url = context.args[0].strip()
    if not url.startswith('http'): url = 'https://' + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{reason}`", parse_mode='Markdown'); return

    _active_scans.set(uid, "Nuclei Lite")
    domain = urlparse(url).netloc
    base = f"{urlparse(url).scheme}://{domain}"

    msg = await update.effective_message.reply_text(
        f"🔍 *Nuclei Lite — `{domain}`*\n\n"
        f"⏳ Running `{len(_NUCLEI_TEMPLATES)}` CVE templates...", parse_mode='Markdown')

    findings = []
    try:
        timeout = aiohttp.ClientTimeout(total=10)
        async with aiohttp.ClientSession(timeout=timeout) as sess:
            for name, method, path, extra_hdrs, body, detect_fn, severity in _NUCLEI_TEMPLATES:
                await asyncio.sleep(0)
                target = base + path
                try:
                    safe_t, _ = is_safe_url(target)
                    if not safe_t: continue
                    hdrs = {**_get_headers(), **extra_hdrs}
                    if method == "GET":
                        cm = sess.get(target, headers=hdrs, ssl=False, allow_redirects=False)
                    else:
                        cm = sess.post(target, headers=hdrs, data=body, ssl=False, allow_redirects=False)
                    async with cm as r:
                        resp_body = (await r.text(errors="replace"))[:2000]
                        resp_hdrs = {k.lower(): v for k, v in r.headers.items()}
                        try:
                            triggered = detect_fn(r.status, resp_body, resp_hdrs)
                        except Exception:
                            triggered = False
                        if triggered:
                            findings.append({"name": name, "severity": severity,
                                             "url": target, "status": r.status})
                except Exception:
                    pass

        sev_order = {"CRITICAL": 0, "HIGH": 1, "MEDIUM": 2, "LOW": 3}
        findings.sort(key=lambda x: sev_order.get(x["severity"], 9))

        out = [f"🔍 *Nuclei Lite — `{domain}`*", "━"*20,
               f"📊 Templates: `{len(_NUCLEI_TEMPLATES)}` | Findings: `{len(findings)}`", ""]

        if findings:
            sev_icons = {"CRITICAL": "🔴", "HIGH": "🟠", "MEDIUM": "🟡", "LOW": "🔵"}
            for fi in findings:
                icon = sev_icons.get(fi["severity"], "⚪")
                out.append(f"{icon} *{fi['severity']}* — {fi['name']}")
                out.append(f"  URL: `{fi['url'][:80]}`")
                out.append(f"  Status: `{fi['status']}`")
                out.append("")
            out += ["*🔧 Priority Fixes:*",
                    "  1. Patch all CRITICAL CVEs immediately",
                    "  2. Remove exposed config/backup files from webroot",
                    "  3. Apply WAF rules for known CVE patterns",
                    "  4. Update frameworks to latest patched versions"]
        else:
            out.append("✅ *No CVE templates triggered.*")
            out.append(f"_All {len(_NUCLEI_TEMPLATES)} checks returned negative._")
            out.append("_Note: This is a lightweight scanner — false negatives are possible._")
        out.append("\n⚠️ _Authorized testing only_")
        await msg.edit_text("\n".join(out), parse_mode='Markdown')
    except Exception as e:
        await msg.edit_text(f"❌ *Nuclei Lite failed:* `{str(e)[:100]}`", parse_mode='Markdown')
    finally:
        _active_scans.pop(uid, None)


